export interface Location {
  latitude: number;
  longitude: number;
}

export interface MenuItem {
  id: string;
  name: string;
  description: string;
  price: number;
  image: string;
  category: 'entrée' | 'plat' | 'boisson' | 'dessert';
  isAvailable: boolean;
}

export interface Restaurant {
  id: string;
  name: string;
  description: string;
  latitude: number;
  longitude: number;
  isOpen: boolean;
  rating: number; // 1-5
  reviewCount: number;
  preparationTime: number; // in minutes
  deliveryAvailable: boolean;
  coverImage: string;
  menu: MenuItem[];
  // Calculated fields
