import React from 'react';
import { Restaurant, Location } from '../types';
import { Navigation } from 'lucide-react';

interface Props {
  restaurants: Restaurant[];
  userLocation: Location | null;
  onSelect: (r: Restaurant) => void;
}

// A purely visual component to simulate a map without an API key
export const MapView: React.FC<Props> = ({ restaurants, userLocation, onSelect }) => {
  return (
    <div className="relative w-full h-[calc(100vh-180px)] bg-gray-200 rounded-xl overflow-hidden border border-gray-300">
      {/* Fake Map Background Pattern */}
      <div 
        className="absolute inset-0 opacity-10"
        style={{
            backgroundImage: 'radial-gradient(#9ca3af 1px, transparent 1px)',
            backgroundSize: '20px 20px'
        }}
      />

      {/* Instructions Overlay */}
      <div className="absolute top-4 left-4 z-10 bg-white/90 backdrop-blur-md p-3 rounded-lg shadow-md max-w-[200px]">
        <p className="text-xs text-gray-600 font-medium">
          Carte simplifiée (Démo). Les points représentent la distance relative.
        </p>
      </div>

      {/* Central User Point */}
      <div className="absolute top-1/2 left-1/2 transform -translate-x-1/2 -translate-y-1/2 flex flex-col items-center z-20">
        <div className="w-4 h-4 bg-blue-500 rounded-full border-2 border-white shadow-lg animate-pulse"></div>
        <div className="w-16 h-16 bg-blue-500/10 rounded-full absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2"></div>
        <span className="mt-2 bg-blue-600 text-white text-[10px] px-2 py-0.5 rounded-full font-bold">Vous</span>
      </div>

      {/* Restaurants Plotting (Simulated Logic) */}
      {restaurants.map((r, index) => {
        // Scatter them randomly for demo purposes, but in a circle around center if we had real canvas logic
        // We will just use a pseudo-random position based on index to ensure they stay in same place
        const angle = (index / restaurants.length) * 2 * Math.PI;
        const radius = 80 + (index * 20); // pixels from center
        const top = `calc(50% + ${Math.sin(angle) * radius}px)`;
        const left = `calc(50% + ${Math.cos(angle) * radius}px)`;

        return (
          <button
            key={r.id}
            onClick={() => onSelect(r)}
            className="absolute transform -translate-x-1/2 -translate-y-1/2 flex flex-col items-center group z-10 hover:z-30 transition-all"
            style={{ top, left }}
          >
            <div className={`w-8 h-8 rounded-full flex items-center justify-center shadow-lg border-2 border-white transition-transform group-hover:scale-110 ${r.isOpen ? 'bg-brand-500' : 'bg-gray-400'}`}>
               <span className="text-white text-xs font-bold">{index + 1}</span>
            </div>
            <div className="bg-white px-2 py-1 rounded shadow text-[10px] font-bold mt-1 opacity-0 group-hover:opacity-100 transition-opacity whitespace-nowrap text-gray-800">
              {r.name}
            </div>
          </button>
        );
      })}

      <div className="absolute bottom-4 right-4 bg-white p-2 rounded-full shadow-lg">
        <Navigation size={20} className="text-blue-600" />
      </div>
    </div>
  );
};

import React from 'react';
import { X, Trash2, ShoppingBag, CreditCard, Banknote } from 'lucide-react';
