                <div key={item.id} className="p-4 flex items-center justify-between hover:bg-gray-50">
                    <div className="flex items-center space-x-3">
                    <img src={item.image} alt={item.name} className="w-12 h-12 rounded-lg object-cover bg-gray-200" />
                    <div>
                        <p className="font-bold text-gray-800 text-sm">{item.name}</p>
                        <p className="text-xs text-gray-500">{item.price.toFixed(2)} $ • {item.category}</p>
                    </div>
                    </div>
                    <button onClick={() => deleteItem(item.id)} className="text-red-400 hover:text-red-600 p-2">
                    <Trash2 size={16} />
                    </button>
                </div>
                ))
            )}
          </div>
        </div>
      </main>
    </div>
  );
};

import React, { useState, useEffect, useMemo } from 'react';
import { MapPin, ShoppingBag, List, Map, Zap, ArrowLeft, Plus, Bike, Footprints, LogOut } from 'lucide-react';
import { KINSHASA_CENTER_LAT, KINSHASA_CENTER_LNG } from '../constants';
import { Restaurant, UserState, ViewMode, MenuItem, CartItem, User } from '../types';
import { calculateTime, getDistanceFromLatLonInKm, formatDistance, formatTime } from '../utils/geo';
import { RestaurantCard } from './RestaurantCard';
import { MapView } from './MapView';
import { CartDrawer } from './CartDrawer';

// Speed constants
const SPEED_WALKING = 5;
const SPEED_MOTO = 30;

interface Props {
  user: User;
  allRestaurants: Restaurant[];
  onLogout: () => void;
}

export const CustomerView: React.FC<Props> = ({ user, allRestaurants, onLogout }) => {
  // State
  const [userState, setUserState] = useState<UserState>({
    location: null,
    locationError: null,
    loadingLocation: true,
  });

  const [restaurants, setRestaurants] = useState<Restaurant[]>([]);
  const [viewMode, setViewMode] = useState<ViewMode>('list');
  const [selectedRestaurant, setSelectedRestaurant] = useState<Restaurant | null>(null);
  const [cart, setCart] = useState<CartItem[]>([]);
  const [isCartOpen, setIsCartOpen] = useState(false);
  const [urgentMode, setUrgentMode] = useState(false);
  const [showSuccess, setShowSuccess] = useState(false);

  // Initial Geolocation
  useEffect(() => {
    if (!navigator.geolocation) {
      setUserState({
        location: null,
        locationError: "La géolocalisation n'est pas supportée par votre navigateur",
        loadingLocation: false
      });
      return;
    }

    navigator.geolocation.getCurrentPosition(
      (position) => {
        setUserState({
          location: {
            latitude: position.coords.latitude,
            longitude: position.coords.longitude,
          },
          locationError: null,
          loadingLocation: false
        });
      },
      (error) => {
        console.warn("Geo error:", error);
        setUserState({
            location: {
                latitude: KINSHASA_CENTER_LAT,
                longitude: KINSHASA_CENTER_LNG
            },
            locationError: "Position introuvable. Utilisation de la position par défaut (Kinshasa).",
            loadingLocation: false
        });
      },
      { enableHighAccuracy: true, timeout: 5000, maximumAge: 0 }
    );
  }, []);

  // Update Restaurants when location or database changes
  useEffect(() => {
    if (userState.location) {
      const updatedRestaurants = allRestaurants.map(r => {
        const dist = getDistanceFromLatLonInKm(
          userState.location!.latitude,
          userState.location!.longitude,
          r.latitude,
          r.longitude
        );
        return {
          ...r,
          distance: dist,
          timeWalking: calculateTime(dist, SPEED_WALKING),
          timeMoto: calculateTime(dist, SPEED_MOTO),
        };
      }).sort((a, b) => (a.distance || 0) - (b.distance || 0));

      setRestaurants(updatedRestaurants);
    } else {
      setRestaurants(allRestaurants);
    }
  }, [userState.location, allRestaurants]);

  // Filter Logic
  const filteredRestaurants = useMemo(() => {
    let list = restaurants;
    if (urgentMode) {
      list = list.filter(r => r.isOpen && r.preparationTime <= 20);
    }
    return list;
  }, [restaurants, urgentMode]);

  // Cart Logic
  const addToCart = (item: MenuItem, restaurant: Restaurant) => {
    setCart(prev => {
        return [...prev, { ...item, quantity: 1, restaurantId: restaurant.id, restaurantName: restaurant.name }];
    });
  };

  const removeFromCart = (itemId: string) => {
    setCart(prev => {
        const index = prev.findIndex(i => i.id === itemId);
        if (index > -1) {
            const newArr = [...prev];
            newArr.splice(index, 1);
            return newArr;
        }
        return prev;
    });
  };

  const cartTotal = cart.reduce((sum, item) => sum + item.price, 0);

  const handleCheckout = () => {
    setIsCartOpen(false);
    setShowSuccess(true);
    setCart([]);
    setTimeout(() => {
        setShowSuccess(false);
        setViewMode('list');
    }, 4000);
  };

  // Views
  if (userState.loadingLocation) {
    return (
      <div className="min-h-screen flex flex-col items-center justify-center bg-brand-50">
        <div className="w-16 h-16 border-4 border-brand-500 border-t-transparent rounded-full animate-spin"></div>
        <p className="mt-4 text-brand-800 font-medium">Localisation en cours...</p>
      </div>
    );
  }

  return (
    <div className="min-h-screen pb-20 max-w-md mx-auto bg-gray-50 shadow-2xl overflow-hidden relative">

      {/* SUCCESS OVERLAY */}
      {showSuccess && (
        <div className="absolute inset-0 z-[60] bg-brand-500 flex flex-col items-center justify-center text-white p-6 text-center animate-fade-in">
           <div className="w-20 h-20 bg-white rounded-full flex items-center justify-center mb-6 shadow-xl">
              <ShoppingBag className="text-brand-500" size={40} />
           </div>
           <h2 className="text-3xl font-bold mb-2">Commande Reçue !</h2>
           <p className="text-brand-100">Votre repas est en préparation.</p>
           <div className="mt-8 bg-white/20 p-4 rounded-xl backdrop-blur-sm">
             <p className="font-mono text-sm">Temps estimé: 35 min</p>
           </div>
        </div>
      )}

      {/* HEADER */}
      <header className="bg-white sticky top-0 z-30 px-4 py-3 shadow-sm border-b border-gray-100">
        <div className="flex justify-between items-center mb-2">
            <div className="flex items-center">
                <h1 className="text-xl font-black text-brand-600 tracking-tight mr-2">DashMeals</h1>
                <span className="text-xs bg-brand-100 text-brand-800 px-2 py-0.5 rounded-full font-bold">Client</span>
            </div>
          <div className="flex items-center space-x-2">
            <button onClick={() => setIsCartOpen(true)} className="relative p-2 bg-gray-100 rounded-full hover:bg-gray-200 transition-colors">
                <ShoppingBag size={20} className="text-gray-700" />
                {cart.length > 0 && (
                <span className="absolute top-0 right-0 bg-red-500 text-white text-[10px] font-bold h-4 w-4 flex items-center justify-center rounded-full border-2 border-white">
                    {cart.length}
                </span>
                )}
            </button>
            <button onClick={onLogout} className="p-2 text-gray-400 hover:text-red-500">
                <LogOut size={20} />
            </button>
          </div>
        </div>

        <div className="flex items-center text-sm text-gray-500 bg-gray-50 p-2 rounded-lg">
           <MapPin size={14} className="mr-1.5 text-brand-500" />
           <span className="truncate flex-1">
             {userState.locationError ? "Mode Démo (Gombe)" : "Ma Position actuelle"}
           </span>
        </div>
      </header>

      {/* MAIN CONTENT AREA */}
      <main className="p-4">

        {viewMode === 'list' || viewMode === 'map' ? (
            <>
                {/* FILTERS */}
                <div className="flex space-x-3 mb-6 overflow-x-auto no-scrollbar pb-1">
                    <button 
                        onClick={() => setUrgentMode(!urgentMode)}
                        className={`flex items-center px-4 py-2 rounded-full font-bold text-sm shadow-sm transition-all border whitespace-nowrap ${urgentMode ? 'bg-red-500 text-white border-red-500 animate-pulse-fast' : 'bg-white text-gray-700 border-gray-200'}`}
                    >
                        <Zap size={16} className={`mr-1 ${urgentMode ? 'fill-white' : 'fill-none'}`} />
                        Urgent - J'ai faim !
                    </button>
                    <button className="px-4 py-2 rounded-full bg-white border border-gray-200 text-gray-600 font-medium text-sm whitespace-nowrap shadow-sm">
                        🍖 Grillades
                    </button>
                    <button className="px-4 py-2 rounded-full bg-white border border-gray-200 text-gray-600 font-medium text-sm whitespace-nowrap shadow-sm">
                        🍗 Poulet
                    </button>
                </div>

                {/* CONTENT */}
                {viewMode === 'list' ? (
                    <div className="space-y-4">
                        {filteredRestaurants.map(restaurant => (
                            <RestaurantCard 
                                key={restaurant.id} 
                                restaurant={restaurant} 
                                onClick={() => {
                                    setSelectedRestaurant(restaurant);
                                    setViewMode('restaurant_detail');
                                }} 
                            />
                        ))}
                        {filteredRestaurants.length === 0 && (
                            <div className="text-center py-10 text-gray-500">
                                <p>Aucun restaurant trouvé :(</p>
                                {urgentMode && <button onClick={() => setUrgentMode(false)} className="text-brand-500 underline mt-2">Désactiver le mode urgent</button>}
                            </div>
                        )}
                    </div>
                ) : (
                    <MapView 
                        restaurants={filteredRestaurants} 
                        userLocation={userState.location} 
                        onSelect={(r) => {
                            setSelectedRestaurant(r);
                            setViewMode('restaurant_detail');
                        }}
                    />
                )}
            </>
        ) : viewMode === 'restaurant_detail' && selectedRestaurant ? (
            <div className="animate-in slide-in-from-right duration-300">
                <button 
                    onClick={() => setViewMode('list')} 
                    className="mb-4 flex items-center text-gray-600 font-medium hover:text-brand-600"
                >
                    <ArrowLeft size={18} className="mr-1" /> Retour
                </button>

                <div className="bg-white rounded-2xl shadow-sm border border-gray-100 overflow-hidden mb-6">
                    <img src={selectedRestaurant.coverImage} className="w-full h-48 object-cover" alt="Cover" />
                    <div className="p-4">
                        <h1 className="text-2xl font-bold text-gray-900">{selectedRestaurant.name}</h1>
                        <p className="text-gray-500 mb-4">{selectedRestaurant.description}</p>

                        {/* Primary Stats */}
                        <div className="flex items-center space-x-4 text-sm text-gray-600 mb-4">
                            <span className="flex items-center bg-gray-100 px-2 py-1 rounded"><Navigation size={14} className="mr-1"/> {formatDistance(selectedRestaurant.distance || 0)}</span>
                            <span className="flex items-center bg-gray-100 px-2 py-1 rounded"><Zap size={14} className="mr-1 text-yellow-500"/> {selectedRestaurant.preparationTime} min</span>
                        </div>

                        {/* Travel Times with Icons */}
                        <div className="grid grid-cols-2 gap-3 mb-2">
                             <div className="flex items-center p-3 bg-orange-50 rounded-lg text-orange-700 border border-orange-100">
                                <Bike size={20} className="mr-3" />
                                <div>
                                    <p className="text-[10px] font-bold uppercase tracking-wider opacity-70">En Moto</p>
                                    <p className="font-bold text-lg leading-none">{selectedRestaurant.timeMoto ? formatTime(selectedRestaurant.timeMoto) : '--'}</p>
                                </div>
                            </div>
                            <div className="flex items-center p-3 bg-blue-50 rounded-lg text-blue-700 border border-blue-100">
                                <Footprints size={20} className="mr-3" />
                                <div>
                                     <p className="text-[10px] font-bold uppercase tracking-wider opacity-70">À pied</p>
                                     <p className="font-bold text-lg leading-none">{selectedRestaurant.timeWalking ? formatTime(selectedRestaurant.timeWalking) : '--'}</p>
                                </div>
                            </div>
                        </div>

                    </div>
                </div>

                <h3 className="text-lg font-bold mb-3">Menu</h3>
                <div className="space-y-3">
                    {selectedRestaurant.menu.map(item => (
                        <div key={item.id} className="bg-white p-3 rounded-xl border border-gray-100 shadow-sm flex space-x-3">
                            <img src={item.image} className="w-20 h-20 rounded-lg object-cover bg-gray-100" alt={item.name} />
                            <div className="flex-1 flex flex-col justify-between">
                                <div>
                                    <h4 className="font-bold text-gray-800">{item.name}</h4>
                                    <p className="text-xs text-gray-500 line-clamp-1">{item.description}</p>
                                </div>
                                <div className="flex justify-between items-end mt-2">
                                    <span className="font-bold text-brand-600">${item.price.toFixed(2)}</span>
                                    <button 
                                        onClick={() => addToCart(item, selectedRestaurant)}
                                        className="bg-brand-50 text-brand-600 p-2 rounded-full hover:bg-brand-100 transition-colors"
                                    >
                                        <Plus size={16} />
                                    </button>
                                </div>
                            </div>
                        </div>
                    ))}
                </div>
            </div>
        ) : null}
      </main>

      {/* BOTTOM NAV */}
      <nav className="fixed bottom-0 left-0 right-0 bg-white border-t border-gray-200 px-6 py-3 flex justify-around items-center z-40 max-w-md mx-auto">
        <button 
            onClick={() => setViewMode('list')} 
            className={`flex flex-col items-center space-y-1 ${viewMode === 'list' ? 'text-brand-600' : 'text-gray-400'}`}
        >
            <List size={22} />
            <span className="text-[10px] font-medium">Liste</span>
        </button>

        {/* Urgent Button Floating */}
        <div className="relative -top-6">
            <button 
                onClick={() => setUrgentMode(!urgentMode)}
                className={`w-14 h-14 rounded-full flex items-center justify-center shadow-lg border-4 border-gray-50 transition-all ${urgentMode ? 'bg-red-500 text-white scale-110' : 'bg-brand-500 text-white'}`}
            >
                <Zap size={24} className={urgentMode ? 'animate-pulse' : ''} />
            </button>
        </div>

        <button 
            onClick={() => setViewMode('map')} 
            className={`flex flex-col items-center space-y-1 ${viewMode === 'map' ? 'text-brand-600' : 'text-gray-400'}`}
        >
            <Map size={22} />
            <span className="text-[10px] font-medium">Carte</span>
        </button>
      </nav>

      {/* CART DRAWER */}
      <CartDrawer 
        isOpen={isCartOpen} 
        onClose={() => setIsCartOpen(false)} 
        items={cart} 
        onRemove={removeFromCart} 
        onCheckout={handleCheckout}
        total={cartTotal}
      />

    </div>
  );
};

import React, { useState } from 'react';
import { MOCK_RESTAURANTS } from './constants';
import { Restaurant, User } from './types';
import { AuthScreen } from './components/AuthScreen';
import { CustomerView } from './components/CustomerView';
import { BusinessDashboard } from './components/BusinessDashboard';

function App() {
  // Global Application State (Simulates Database)
  const [restaurants, setRestaurants] = useState<Restaurant[]>(MOCK_RESTAURANTS);
  const [currentUser, setCurrentUser] = useState<User | null>(null);

  // Authentication Handler
  const handleLogin = (user: User, businessData?: any) => {
    setCurrentUser(user);

    // If a new business registers, create their restaurant entry immediately in state
    if (user.role === 'business' && businessData) {
      const newRestaurant: Restaurant = {
        id: `resto-${Date.now()}`,
        ownerId: user.id,
        name: businessData.name,
        type: businessData.type,
        description: 'Nouvel établissement sur DashMeals.',
        latitude: businessData.latitude,
        longitude: businessData.longitude,
        isOpen: true,
        rating: 5.0,
        reviewCount: 0,
        preparationTime: 30,
        deliveryAvailable: true,
        coverImage: 'https://picsum.photos/800/600?grayscale',
        menu: []
      };

      // Update user with business link
      const updatedUser = { ...user, businessId: newRestaurant.id };
      setCurrentUser(updatedUser);
      setRestaurants([...restaurants, newRestaurant]);
    } else if (user.role === 'business') {
        // Try to find existing business
        const existingBusiness = restaurants.find(r => r.ownerId === user.id);
        if (existingBusiness) {
             const updatedUser = { ...user, businessId: existingBusiness.id };
             setCurrentUser(updatedUser);
        } else {
            // Demo fallback: Assign random business if not strictly found in mock 
            // (In real app, we would fetch from DB)
            // For now, if no ID matches, just assign the first one for demo purposes if it was a generic login
             const updatedUser = { ...user, businessId: restaurants[0].id };
             setCurrentUser(updatedUser);
        }
    }
  };

  const handleLogout = () => {
    setCurrentUser(null);
  };

  const handleUpdateRestaurant = (updatedResto: Restaurant) => {
    setRestaurants(prev => prev.map(r => r.id === updatedResto.id ? updatedResto : r));
  };

  // 1. Not Logged In -> Show Auth
  if (!currentUser) {
    return <AuthScreen onLogin={handleLogin} />;
  }

  // 2. Logged in as Business -> Show Dashboard
  if (currentUser.role === 'business' && currentUser.businessId) {
    const myRestaurant = restaurants.find(r => r.id === currentUser.businessId);
    if (!myRestaurant) return <div>Erreur: Business introuvable</div>;

    return (
      <BusinessDashboard 
        user={currentUser} 
        restaurant={myRestaurant} 
        onUpdateRestaurant={handleUpdateRestaurant}
        onLogout={handleLogout}
      />
    );
  }

  // 3. Logged in as Client -> Show Main App (Customer View)
  return (
    <CustomerView 
      user={currentUser}
      allRestaurants={restaurants}
      onLogout={handleLogout}
    />
  );
}

export default App;

import React, { useState, useEffect, useMemo } from 'react';
import { MapPin, ShoppingBag, List, Map, Zap, ArrowLeft, Plus, Bike, Footprints, LogOut, Navigation } from 'lucide-react';
import { KINSHASA_CENTER_LAT, KINSHASA_CENTER_LNG } from '../constants';
import { Restaurant, UserState, ViewMode, MenuItem, CartItem, User } from '../types';
import { calculateTime, getDistanceFromLatLonInKm, formatDistance, formatTime } from '../utils/geo';
import { RestaurantCard } from './RestaurantCard';
import { MapView } from './MapView';
import { CartDrawer } from './CartDrawer';

// Speed constants
const SPEED_WALKING = 5;
const SPEED_MOTO = 30;

interface Props {
  user: User;
  allRestaurants: Restaurant[];
  onLogout: () => void;
}

export const CustomerView: React.FC<Props> = ({ user, allRestaurants, onLogout }) => {
  // State
  const [userState, setUserState] = useState<UserState>({
    location: null,
    locationError: null,
    loadingLocation: true,
  });

  const [restaurants, setRestaurants] = useState<Restaurant[]>([]);
  const [viewMode, setViewMode] = useState<ViewMode>('list');
  const [selectedRestaurant, setSelectedRestaurant] = useState<Restaurant | null>(null);
  const [cart, setCart] = useState<CartItem[]>([]);
  const [isCartOpen, setIsCartOpen] = useState(false);
  const [urgentMode, setUrgentMode] = useState(false);
  const [showSuccess, setShowSuccess] = useState(false);

  // Initial Geolocation
  useEffect(() => {
    if (!navigator.geolocation) {
      setUserState({
        location: null,
        locationError: "La géolocalisation n'est pas supportée par votre navigateur",
        loadingLocation: false
      });
      return;
    }

    navigator.geolocation.getCurrentPosition(
      (position) => {
        setUserState({
          location: {
            latitude: position.coords.latitude,
            longitude: position.coords.longitude,
          },
          locationError: null,
          loadingLocation: false
        });
      },
      (error) => {
        console.warn("Geo error:", error);
        setUserState({
            location: {
                latitude: KINSHASA_CENTER_LAT,
                longitude: KINSHASA_CENTER_LNG
            },
            locationError: "Position introuvable. Utilisation de la position par défaut (Kinshasa).",
            loadingLocation: false
        });
      },
      { enableHighAccuracy: true, timeout: 5000, maximumAge: 0 }
    );
  }, []);

  // Update Restaurants when location or database changes
  useEffect(() => {
    if (userState.location) {
      const updatedRestaurants = allRestaurants.map(r => {
        const dist = getDistanceFromLatLonInKm(
          userState.location!.latitude,
          userState.location!.longitude,
          r.latitude,
          r.longitude
        );
        return {
          ...r,
          distance: dist,
          timeWalking: calculateTime(dist, SPEED_WALKING),
          timeMoto: calculateTime(dist, SPEED_MOTO),
        };
      }).sort((a, b) => (a.distance || 0) - (b.distance || 0));

      setRestaurants(updatedRestaurants);
    } else {
      setRestaurants(allRestaurants);
    }
  }, [userState.location, allRestaurants]);

  // Filter Logic
  const filteredRestaurants = useMemo(() => {
    let list = restaurants;
    if (urgentMode) {
      list = list.filter(r => r.isOpen && r.preparationTime <= 20);
    }
    return list;
  }, [restaurants, urgentMode]);

  // Cart Logic
  const addToCart = (item: MenuItem, restaurant: Restaurant) => {
    setCart(prev => {
        return [...prev, { ...item, quantity: 1, restaurantId: restaurant.id, restaurantName: restaurant.name }];
    });
  };

  const removeFromCart = (itemId: string) => {
    setCart(prev => {
        const index = prev.findIndex(i => i.id === itemId);
        if (index > -1) {
            const newArr = [...prev];
            newArr.splice(index, 1);
            return newArr;
        }
        return prev;
    });
  };

  const cartTotal = cart.reduce((sum, item) => sum + item.price, 0);

  const handleCheckout = () => {
    setIsCartOpen(false);
    setShowSuccess(true);
    setCart([]);
    setTimeout(() => {
        setShowSuccess(false);
        setViewMode('list');
    }, 4000);
  };

  // Views
  if (userState.loadingLocation) {
    return (
      <div className="min-h-screen flex flex-col items-center justify-center bg-brand-50">
        <div className="w-16 h-16 border-4 border-brand-500 border-t-transparent rounded-full animate-spin"></div>
        <p className="mt-4 text-brand-800 font-medium">Localisation en cours...</p>
      </div>
    );
  }

  return (
    <div className="min-h-screen pb-20 max-w-md mx-auto bg-gray-50 shadow-2xl overflow-hidden relative">

      {/* SUCCESS OVERLAY */}
      {showSuccess && (
        <div className="absolute inset-0 z-[60] bg-brand-500 flex flex-col items-center justify-center text-white p-6 text-center animate-fade-in">
           <div className="w-20 h-20 bg-white rounded-full flex items-center justify-center mb-6 shadow-xl">
              <ShoppingBag className="text-brand-500" size={40} />
           </div>
           <h2 className="text-3xl font-bold mb-2">Commande Reçue !</h2>
           <p className="text-brand-100">Votre repas est en préparation.</p>
           <div className="mt-8 bg-white/20 p-4 rounded-xl backdrop-blur-sm">
             <p className="font-mono text-sm">Temps estimé: 35 min</p>
           </div>
        </div>
      )}

      {/* HEADER */}
      <header className="bg-white sticky top-0 z-30 px-4 py-3 shadow-sm border-b border-gray-100">
        <div className="flex justify-between items-center mb-2">
            <div className="flex items-center">
                <h1 className="text-xl font-black text-brand-600 tracking-tight mr-2">DashMeals</h1>
                <span className="text-xs bg-brand-100 text-brand-800 px-2 py-0.5 rounded-full font-bold">Client</span>
            </div>
          <div className="flex items-center space-x-2">
            <button onClick={() => setIsCartOpen(true)} className="relative p-2 bg-gray-100 rounded-full hover:bg-gray-200 transition-colors">
                <ShoppingBag size={20} className="text-gray-700" />
                {cart.length > 0 && (
                <span className="absolute top-0 right-0 bg-red-500 text-white text-[10px] font-bold h-4 w-4 flex items-center justify-center rounded-full border-2 border-white">
                    {cart.length}
                </span>
                )}
            </button>
            <button onClick={onLogout} className="p-2 text-gray-400 hover:text-red-500">
                <LogOut size={20} />
            </button>
          </div>
        </div>

        <div className="flex items-center text-sm text-gray-500 bg-gray-50 p-2 rounded-lg">
           <MapPin size={14} className="mr-1.5 text-brand-500" />
           <span className="truncate flex-1">
             {userState.locationError ? "Mode Démo (Gombe)" : "Ma Position actuelle"}
           </span>
        </div>
      </header>

      {/* MAIN CONTENT AREA */}
      <main className="p-4">

        {viewMode === 'list' || viewMode === 'map' ? (
            <>
                {/* FILTERS */}
                <div className="flex space-x-3 mb-6 overflow-x-auto no-scrollbar pb-1">
                    <button 
                        onClick={() => setUrgentMode(!urgentMode)}
                        className={`flex items-center px-4 py-2 rounded-full font-bold text-sm shadow-sm transition-all border whitespace-nowrap ${urgentMode ? 'bg-red-500 text-white border-red-500 animate-pulse-fast' : 'bg-white text-gray-700 border-gray-200'}`}
                    >
                        <Zap size={16} className={`mr-1 ${urgentMode ? 'fill-white' : 'fill-none'}`} />
                        Urgent - J'ai faim !
                    </button>
                    <button className="px-4 py-2 rounded-full bg-white border border-gray-200 text-gray-600 font-medium text-sm whitespace-nowrap shadow-sm">
                        🍖 Grillades
                    </button>
                    <button className="px-4 py-2 rounded-full bg-white border border-gray-200 text-gray-600 font-medium text-sm whitespace-nowrap shadow-sm">
                        🍗 Poulet
                    </button>
                </div>

                {/* CONTENT */}
                {viewMode === 'list' ? (
                    <div className="space-y-4">
                        {filteredRestaurants.map(restaurant => (
                            <RestaurantCard 
                                key={restaurant.id} 
                                restaurant={restaurant} 
                                onClick={() => {
                                    setSelectedRestaurant(restaurant);
                                    setViewMode('restaurant_detail');
                                }} 
                            />
                        ))}
                        {filteredRestaurants.length === 0 && (
                            <div className="text-center py-10 text-gray-500">
                                <p>Aucun restaurant trouvé :(</p>
                                {urgentMode && <button onClick={() => setUrgentMode(false)} className="text-brand-500 underline mt-2">Désactiver le mode urgent</button>}
                            </div>
                        )}
                    </div>
                ) : (
                    <MapView 
                        restaurants={filteredRestaurants} 
                        userLocation={userState.location} 
                        onSelect={(r) => {
                            setSelectedRestaurant(r);
                            setViewMode('restaurant_detail');
                        }}
                    />
                )}
            </>
        ) : viewMode === 'restaurant_detail' && selectedRestaurant ? (
            <div className="animate-in slide-in-from-right duration-300">
                <button 
                    onClick={() => setViewMode('list')} 
                    className="mb-4 flex items-center text-gray-600 font-medium hover:text-brand-600"
                >
                    <ArrowLeft size={18} className="mr-1" /> Retour
                </button>

                <div className="bg-white rounded-2xl shadow-sm border border-gray-100 overflow-hidden mb-6">
                    <img src={selectedRestaurant.coverImage} className="w-full h-48 object-cover" alt="Cover" />
                    <div className="p-4">
                        <h1 className="text-2xl font-bold text-gray-900">{selectedRestaurant.name}</h1>
                        <p className="text-gray-500 mb-4">{selectedRestaurant.description}</p>

                        {/* Primary Stats */}
                        <div className="flex items-center space-x-4 text-sm text-gray-600 mb-4">
                            <span className="flex items-center bg-gray-100 px-2 py-1 rounded"><Navigation size={14} className="mr-1"/> {formatDistance(selectedRestaurant.distance || 0)}</span>
                            <span className="flex items-center bg-gray-100 px-2 py-1 rounded"><Zap size={14} className="mr-1 text-yellow-500"/> {selectedRestaurant.preparationTime} min</span>
                        </div>

                        {/* Travel Times with Icons */}
                        <div className="grid grid-cols-2 gap-3 mb-2">
                             <div className="flex items-center p-3 bg-orange-50 rounded-lg text-orange-700 border border-orange-100">
                                <Bike size={20} className="mr-3" />
                                <div>
                                    <p className="text-[10px] font-bold uppercase tracking-wider opacity-70">En Moto</p>
                                    <p className="font-bold text-lg leading-none">{selectedRestaurant.timeMoto ? formatTime(selectedRestaurant.timeMoto) : '--'}</p>
                                </div>
                            </div>
                            <div className="flex items-center p-3 bg-blue-50 rounded-lg text-blue-700 border border-blue-100">
                                <Footprints size={20} className="mr-3" />
                                <div>
                                     <p className="text-[10px] font-bold uppercase tracking-wider opacity-70">À pied</p>
                                     <p className="font-bold text-lg leading-none">{selectedRestaurant.timeWalking ? formatTime(selectedRestaurant.timeWalking) : '--'}</p>
                                </div>
                            </div>
                        </div>

                    </div>
                </div>

                <h3 className="text-lg font-bold mb-3">Menu</h3>
                <div className="space-y-3">
                    {selectedRestaurant.menu.map(item => (
                        <div key={item.id} className="bg-white p-3 rounded-xl border border-gray-100 shadow-sm flex space-x-3">
                            <img src={item.image} className="w-20 h-20 rounded-lg object-cover bg-gray-100" alt={item.name} />
                            <div className="flex-1 flex flex-col justify-between">
                                <div>
                                    <h4 className="font-bold text-gray-800">{item.name}</h4>
                                    <p className="text-xs text-gray-500 line-clamp-1">{item.description}</p>
                                </div>
                                <div className="flex justify-between items-end mt-2">
                                    <span className="font-bold text-brand-600">${item.price.toFixed(2)}</span>
                                    <button 
                                        onClick={() => addToCart(item, selectedRestaurant)}
                                        className="bg-brand-50 text-brand-600 p-2 rounded-full hover:bg-brand-100 transition-colors"
                                    >
                                        <Plus size={16} />
                                    </button>
                                </div>
                            </div>
                        </div>
                    ))}
                </div>
            </div>
        ) : null}
      </main>

      {/* BOTTOM NAV */}
      <nav className="fixed bottom-0 left-0 right-0 bg-white border-t border-gray-200 px-6 py-3 flex justify-around items-center z-40 max-w-md mx-auto">
        <button 
            onClick={() => setViewMode('list')} 
            className={`flex flex-col items-center space-y-1 ${viewMode === 'list' ? 'text-brand-600' : 'text-gray-400'}`}
        >
            <List size={22} />
            <span className="text-[10px] font-medium">Liste</span>
        </button>

        {/* Urgent Button Floating */}
        <div className="relative -top-6">
            <button 
                onClick={() => setUrgentMode(!urgentMode)}
                className={`w-14 h-14 rounded-full flex items-center justify-center shadow-lg border-4 border-gray-50 transition-all ${urgentMode ? 'bg-red-500 text-white scale-110' : 'bg-brand-500 text-white'}`}
            >
                <Zap size={24} className={urgentMode ? 'animate-pulse' : ''} />
            </button>
        </div>

        <button 
            onClick={() => setViewMode('map')} 
            className={`flex flex-col items-center space-y-1 ${viewMode === 'map' ? 'text-brand-600' : 'text-gray-400'}`}
        >
            <Map size={22} />
            <span className="text-[10px] font-medium">Carte</span>
        </button>
      </nav>

      {/* CART DRAWER */}
      <CartDrawer 
        isOpen={isCartOpen} 
        onClose={() => setIsCartOpen(false)} 
        items={cart} 
        onRemove={removeFromCart} 
        onCheckout={handleCheckout}
        total={cartTotal}
      />

    </div>
  );
};

