Voici les changements pour connecter votre application DashMeals à Supabase.

### ⚠️ Important : Configuration Base de Données requise
Pour que le code ci-dessous fonctionne, vous devez exécuter le script SQL suivant dans l'éditeur SQL de votre projet Supabase pour créer les tables nécessaires :

```sql
-- Création de la table des profils utilisateurs
create table profiles (
  id uuid references auth.users not null primary key,
  role text not null check (role in ('client', 'business')),
  full_name text
);

-- Création de la table des restaurants
create table restaurants (
  id uuid default gen_random_uuid() primary key,
  owner_id uuid references auth.users not null,
  name text not null,
  type text not null,
  description text,
  latitude float not null,
  longitude float not null,
  is_open boolean default true,
  rating float default 5.0,
  review_count int default 0,
  preparation_time int default 30,
  delivery_available boolean default true,
  cover_image text
);

-- Création de la table des menus
create table menu_items (
  id uuid default gen_random_uuid() primary key,
  restaurant_id uuid references restaurants(id) not null,
  name text not null,
  description text,
  price float not null,
  category text not null,
  image text,
  is_available boolean default true
);

-- Activation RLS (Sécurité simplifiée pour le démarrage)
alter table profiles enable row level security;
alter table restaurants enable row level security;
alter table menu_items enable row level security;

-- Politiques d'accès (Lecture publique, Ecriture authentifiée)
create policy "Public profiles" on profiles for select using (true);
create policy "Users can insert their own profile" on profiles for insert with check (auth.uid() = id);

create policy "Public restaurants" on restaurants for select using (true);
create policy "Owners can update restaurants" on restaurants for update using (auth.uid() = owner_id);
create policy "Owners can insert restaurants" on restaurants for insert with check (auth.uid() = owner_id);

create policy "Public menu" on menu_items for select using (true);
create policy "Owners can manage menu" on menu_items for all using (
  exists (select 1 from restaurants where id = menu_items.restaurant_id and owner_id = auth.uid())
);
```

Voici les mises à jour du code :

