                  onChange={(e) => setBusinessType(e.target.value as BusinessType)}
                >
                  <option value="restaurant">Restaurant</option>
                  <option value="bar">Bar / Lounge</option>
                  <option value="terrasse">Terrasse</option>
                  <option value="snack">Snack / Fast-food</option>
                </select>
              </div>
            </div>
          )}

          <div>
            <label className="block text-xs font-bold text-gray-600 mb-1">Email</label>
            <input 
              type="email" 
              required 
              className="w-full p-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-brand-500 outline-none"
              placeholder="Ex: nom@mail.com"
              value={email}
              onChange={(e) => setEmail(e.target.value)}
            />
          </div>

          <div>
            <label className="block text-xs font-bold text-gray-600 mb-1">Mot de passe</label>
            <input 
              type="password" 
              required 
              className="w-full p-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-brand-500 outline-none"
              placeholder="••••••••"
              value={password}
              onChange={(e) => setPassword(e.target.value)}
            />
          </div>

          <button 
            type="submit"
            disabled={loading}
            className={`w-full bg-brand-600 hover:bg-brand-700 text-white font-bold py-3 rounded-xl shadow-lg transition-transform active:scale-95 mt-4 flex justify-center items-center ${loading ? 'opacity-70 cursor-not-allowed' : ''}`}
          >
            {loading ? <div className="w-5 h-5 border-2 border-white border-t-transparent rounded-full animate-spin"></div> : (isLogin ? 'Se connecter' : "S'inscrire")}
          </button>
        </form>

        <div className="bg-gray-50 p-4 text-center border-t">
          <button 
            type="button"
            onClick={() => setIsLogin(!isLogin)}
            className="text-sm text-brand-600 font-bold hover:underline"
          >
            {isLogin ? "Pas de compte ? S'inscrire" : "Déjà inscrit ? Se connecter"}
          </button>
        </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect, useMemo } from 'react';
import { MapPin, ShoppingBag, List, Map, Zap, ArrowLeft, Plus, Bike, Footprints, LogOut, Navigation, Filter } from 'lucide-react';
import { KINSHASA_CENTER_LAT, KINSHASA_CENTER_LNG, CITIES_RDC } from '../constants';
import { Restaurant, UserState, ViewMode, MenuItem, CartItem, User } from '../types';
import { calculateTime, getDistanceFromLatLonInKm, formatDistance, formatTime } from '../utils/geo';
import { RestaurantCard } from './RestaurantCard';
import { MapView } from './MapView';
import { CartDrawer } from './CartDrawer';

// Speed constants
const SPEED_WALKING = 5;
const SPEED_MOTO = 30;

interface Props {
  user: User;
  allRestaurants: Restaurant[];
  onLogout: () => void;
}

export const CustomerView: React.FC<Props> = ({ user, allRestaurants, onLogout }) => {
  // State
  const [userState, setUserState] = useState<UserState>({
    location: null,
    locationError: null,
    loadingLocation: true,
  });

  const [restaurants, setRestaurants] = useState<Restaurant[]>([]);
  const [viewMode, setViewMode] = useState<ViewMode>('list');
  const [selectedRestaurant, setSelectedRestaurant] = useState<Restaurant | null>(null);
  const [cart, setCart] = useState<CartItem[]>([]);
  const [isCartOpen, setIsCartOpen] = useState(false);
  const [urgentMode, setUrgentMode] = useState(false);
  const [showSuccess, setShowSuccess] = useState(false);
  const [selectedCity, setSelectedCity] = useState<string>(user.city || 'Kinshasa');

  // Initial Geolocation
  useEffect(() => {
    if (!navigator.geolocation) {
      setUserState({
        location: null,
        locationError: "La géolocalisation n'est pas supportée par votre navigateur",
        loadingLocation: false
      });
      return;
    }

    navigator.geolocation.getCurrentPosition(
      (position) => {
        setUserState({
          location: {
            latitude: position.coords.latitude,
            longitude: position.coords.longitude,
          },
          locationError: null,
          loadingLocation: false
        });
      },
      (error) => {
        console.warn("Geo error:", error);
        setUserState({
            location: {
                latitude: KINSHASA_CENTER_LAT,
                longitude: KINSHASA_CENTER_LNG
            },
            locationError: "Position introuvable. Utilisation de la position par défaut (Kinshasa).",
            loadingLocation: false
        });
      },
      { enableHighAccuracy: true, timeout: 5000, maximumAge: 0 }
    );
  }, []);

  // Update Restaurants when location or database changes
  useEffect(() => {
    if (userState.location) {
      const updatedRestaurants = allRestaurants.map(r => {
        const dist = getDistanceFromLatLonInKm(
          userState.location!.latitude,
          userState.location!.longitude,
          r.latitude,
          r.longitude
        );
        return {
          ...r,
          distance: dist,
          timeWalking: calculateTime(dist, SPEED_WALKING),
          timeMoto: calculateTime(dist, SPEED_MOTO),
        };
      }).sort((a, b) => (a.distance || 0) - (b.distance || 0));

      setRestaurants(updatedRestaurants);
    } else {
      setRestaurants(allRestaurants);
    }
  }, [userState.location, allRestaurants]);

  // Filter Logic (City + Urgent)
  const filteredRestaurants = useMemo(() => {
    let list = restaurants;

    // Filter by City
    if (selectedCity && selectedCity !== 'Toutes') {
      list = list.filter(r => r.city === selectedCity);
    }

    // Filter by Urgent Mode
    if (urgentMode) {
      list = list.filter(r => r.isOpen && r.preparationTime <= 20);
    }

    return list;
  }, [restaurants, urgentMode, selectedCity]);

  // Cart Logic
  const addToCart = (item: MenuItem, restaurant: Restaurant) => {
    setCart(prev => {
        return [...prev, { ...item, quantity: 1, restaurantId: restaurant.id, restaurantName: restaurant.name }];
    });
  };

  const removeFromCart = (itemId: string) => {
    setCart(prev => {
        const index = prev.findIndex(i => i.id === itemId);
        if (index > -1) {
            const newArr = [...prev];
            newArr.splice(index, 1);
            return newArr;
        }
        return prev;
    });
  };

  const cartTotal = cart.reduce((sum, item) => sum + item.price, 0);

  const handleCheckout = () => {
    setIsCartOpen(false);
    setShowSuccess(true);
    setCart([]);
    setTimeout(() => {
        setShowSuccess(false);
        setViewMode('list');
    }, 4000);
  };

  // Views
  if (userState.loadingLocation) {
    return (
      <div className="min-h-screen flex flex-col items-center justify-center bg-brand-50">
        <div className="w-16 h-16 border-4 border-brand-500 border-t-transparent rounded-full animate-spin"></div>
        <p className="mt-4 text-brand-800 font-medium">Localisation en cours...</p>
      </div>
    );
  }

  return (
    <div className="min-h-screen pb-20 max-w-md mx-auto bg-gray-50 shadow-2xl overflow-hidden relative">

      {/* SUCCESS OVERLAY */}
      {showSuccess && (
        <div className="absolute inset-0 z-[60] bg-brand-500 flex flex-col items-center justify-center text-white p-6 text-center animate-fade-in">
           <div className="w-20 h-20 bg-white rounded-full flex items-center justify-center mb-6 shadow-xl">
              <ShoppingBag className="text-brand-500" size={40} />
           </div>
           <h2 className="text-3xl font-bold mb-2">Commande Reçue !</h2>
           <p className="text-brand-100">Votre repas est en préparation.</p>
           <div className="mt-8 bg-white/20 p-4 rounded-xl backdrop-blur-sm">
             <p className="font-mono text-sm">Temps estimé: 35 min</p>
           </div>
        </div>
      )}

      {/* HEADER */}
      <header className="bg-white sticky top-0 z-30 px-4 py-3 shadow-sm border-b border-gray-100">
        <div className="flex justify-between items-center mb-2">
            <div className="flex items-center">
                <h1 className="text-xl font-black text-brand-600 tracking-tight mr-2">DashMeals</h1>
                <span className="text-xs bg-brand-100 text-brand-800 px-2 py-0.5 rounded-full font-bold">Client</span>
            </div>
          <div className="flex items-center space-x-2">
            <button onClick={() => setIsCartOpen(true)} className="relative p-2 bg-gray-100 rounded-full hover:bg-gray-200 transition-colors">
                <ShoppingBag size={20} className="text-gray-700" />
                {cart.length > 0 && (
                <span className="absolute top-0 right-0 bg-red-500 text-white text-[10px] font-bold h-4 w-4 flex items-center justify-center rounded-full border-2 border-white">
                    {cart.length}
                </span>
                )}
            </button>
            <button onClick={onLogout} className="p-2 text-gray-400 hover:text-red-500">
                <LogOut size={20} />
            </button>
          </div>
        </div>

        {/* Location & City Filter */}
        <div className="flex items-center space-x-2">
            <div className="flex-1 flex items-center text-sm text-gray-500 bg-gray-50 p-2 rounded-lg truncate">
              <MapPin size={14} className="mr-1.5 text-brand-500 flex-shrink-0" />
              <span className="truncate">
                {userState.locationError ? "Mode Démo" : "Ma Position"}
              </span>
            </div>

            <select 
              className="bg-brand-50 text-brand-700 text-xs font-bold py-2 pl-2 pr-6 rounded-lg border border-brand-200 outline-none appearance-none bg-[url('data:image/svg+xml;charset=US-ASCII,%3Csvg%20xmlns%3D%22http%3A%2F%2Fwww.w3.org%2F2000%2Fsvg%22%20width%3D%22292.4%22%20height%3D%22292.4%22%3E%3Cpath%20fill%3D%22%23ea580c%22%20d%3D%22M287%2069.4a17.6%2017.6%200%200%200-13-5.4H18.4c-5%200-9.3%201.8-12.9%205.4A17.6%2017.6%200%200%200%200%2082.2c0%205%201.8%209.3%205.4%2012.9l128%20127.9c3.6%203.6%207.8%205.4%2012.8%205.4s9.2-1.8%2012.8-5.4L287%2095c3.5-3.5%205.4-7.8%205.4-12.8%200-5-1.9-9.2-5.5-12.8z%22%2F%3E%3C%2Fsvg%3E')] bg-[length:10px] bg-[right_8px_center] bg-no-repeat"
              value={selectedCity}
              onChange={(e) => setSelectedCity(e.target.value)}
            >
              <option value="Toutes">Toutes les villes</option>
              {CITIES_RDC.map(city => (
                <option key={city} value={city}>{city}</option>
              ))}
            </select>
        </div>
      </header>

      {/* MAIN CONTENT AREA */}
      <main className="p-4">

        {viewMode === 'list' || viewMode === 'map' ? (
            <>
                {/* FILTERS */}
                <div className="flex space-x-3 mb-6 overflow-x-auto no-scrollbar pb-1">
                    <button 
                        onClick={() => setUrgentMode(!urgentMode)}
                        className={`flex items-center px-4 py-2 rounded-full font-bold text-sm shadow-sm transition-all border whitespace-nowrap ${urgentMode ? 'bg-red-500 text-white border-red-500 animate-pulse-fast' : 'bg-white text-gray-700 border-gray-200'}`}
                    >
                        <Zap size={16} className={`mr-1 ${urgentMode ? 'fill-white' : 'fill-none'}`} />
                        Urgent - J'ai faim !
                    </button>
                    <button className="px-4 py-2 rounded-full bg-white border border-gray-200 text-gray-600 font-medium text-sm whitespace-nowrap shadow-sm">
                        🍖 Grillades
                    </button>
                    <button className="px-4 py-2 rounded-full bg-white border border-gray-200 text-gray-600 font-medium text-sm whitespace-nowrap shadow-sm">
                        🍗 Poulet
                    </button>
                </div>

                {/* CONTENT */}
                {viewMode === 'list' ? (
                    <div className="space-y-4">
                        {filteredRestaurants.map(restaurant => (
                            <RestaurantCard 
                                key={restaurant.id} 
                                restaurant={restaurant} 
                                onClick={() => {
                                    setSelectedRestaurant(restaurant);
                                    setViewMode('restaurant_detail');
                                }} 
                            />
                        ))}
                        {filteredRestaurants.length === 0 && (
                            <div className="text-center py-10 text-gray-500">
                                <p>Aucun restaurant trouvé à <strong>{selectedCity}</strong> :(</p>
                                {urgentMode && <button onClick={() => setUrgentMode(false)} className="text-brand-500 underline mt-2">Désactiver le mode urgent</button>}
                            </div>
                        )}
                    </div>
                ) : (
                    <MapView 
                        restaurants={filteredRestaurants} 
                        userLocation={userState.location} 
                        onSelect={(r) => {
                            setSelectedRestaurant(r);
                            setViewMode('restaurant_detail');
                        }}
                    />
                )}
            </>
        ) : viewMode === 'restaurant_detail' && selectedRestaurant ? (
            <div className="animate-in slide-in-from-right duration-300">
                <button 
                    onClick={() => setViewMode('list')} 
                    className="mb-4 flex items-center text-gray-600 font-medium hover:text-brand-600"
                >
                    <ArrowLeft size={18} className="mr-1" /> Retour
                </button>

                <div className="bg-white rounded-2xl shadow-sm border border-gray-100 overflow-hidden mb-6">
                    <img src={selectedRestaurant.coverImage} className="w-full h-48 object-cover" alt="Cover" />
                    <div className="p-4">
                        <div className="flex justify-between items-start">
                           <h1 className="text-2xl font-bold text-gray-900">{selectedRestaurant.name}</h1>
                           <span className="text-xs bg-gray-100 text-gray-600 px-2 py-1 rounded-lg">{selectedRestaurant.city}</span>
                        </div>
                        <p className="text-gray-500 mb-4">{selectedRestaurant.description}</p>

                        {/* Primary Stats */}
                        <div className="flex items-center space-x-4 text-sm text-gray-600 mb-4">
                            <span className="flex items-center bg-gray-100 px-2 py-1 rounded"><Navigation size={14} className="mr-1"/> {formatDistance(selectedRestaurant.distance || 0)}</span>
                            <span className="flex items-center bg-gray-100 px-2 py-1 rounded"><Zap size={14} className="mr-1 text-yellow-500"/> {selectedRestaurant.preparationTime} min</span>
                        </div>

                        {/* Travel Times with Icons */}
                        <div className="grid grid-cols-2 gap-3 mb-2">
                             <div className="flex items-center p-3 bg-orange-50 rounded-lg text-orange-700 border border-orange-100">
