                                     <p className="text-[10px] font-bold uppercase tracking-wider opacity-70">À pied</p>
                                     <p className="font-bold text-lg leading-none">{selectedRestaurant.timeWalking ? formatTime(selectedRestaurant.timeWalking) : '--'}</p>
                                </div>
                            </div>
                        </div>

                    </div>
                </div>

                <h3 className="text-lg font-bold mb-3">Menu</h3>
                <div className="space-y-3">
                    {selectedRestaurant.menu.map(item => (
                        <div key={item.id} className="bg-white p-3 rounded-xl border border-gray-100 shadow-sm flex space-x-3">
