import React, { useState } from 'react';
import { supabase } from '../lib/supabase';
import { Restaurant, MenuItem, User } from '../types';
import { Plus, Trash2, Power, LogOut, Coffee, DollarSign, Clock, Truck } from 'lucide-react';

interface Props {
  user: User;
  restaurant: Restaurant;
  onUpdateRestaurant: (updated: Restaurant) => void;
  onLogout: () => void;
}

export const BusinessDashboard: React.FC<Props> = ({ user, restaurant, onUpdateRestaurant, onLogout }) => {
  const [isAddingItem, setIsAddingItem] = useState(false);
  const [loading, setLoading] = useState(false);
  const [updatingTimes, setUpdatingTimes] = useState(false);

  // Time editing state
  const [prepTime, setPrepTime] = useState(restaurant.preparationTime.toString());
  const [deliveryTime, setDeliveryTime] = useState(restaurant.estimatedDeliveryTime.toString());

  // New Item State
  const [newItemName, setNewItemName] = useState('');
  const [newItemDesc, setNewItemDesc] = useState('');
  const [newItemPrice, setNewItemPrice] = useState('');
  const [newItemCategory, setNewItemCategory] = useState<MenuItem['category']>('plat');

  const updateTimes = async () => {
    setUpdatingTimes(true);
    try {
      const newPrep = parseInt(prepTime) || 0;
      const newDeliv = parseInt(deliveryTime) || 0;

      const { error } = await supabase
        .from('restaurants')
        .update({ 
            preparation_time: newPrep,
            estimated_delivery_time: newDeliv
        })
        .eq('id', restaurant.id);

      if (error) throw error;

      onUpdateRestaurant({
          ...restaurant,
          preparationTime: newPrep,
          estimatedDeliveryTime: newDeliv
      });
      alert("Temps mis à jour !");
    } catch (err) {
        console.error("Error updating times", err);
        alert("Erreur lors de la mise à jour");
    } finally {
        setUpdatingTimes(false);
    }
  };

  const toggleOpen = async () => {
    try {
      const newState = !restaurant.isOpen;

      // Update DB
      const { error } = await supabase
        .from('restaurants')
        .update({ is_open: newState })
        .eq('id', restaurant.id);

      if (error) throw error;

      // Update Local
      onUpdateRestaurant({
        ...restaurant,
        isOpen: newState
      });
    } catch (err) {
      console.error("Error updating status:", err);
      alert("Erreur lors de la mise à jour du statut");
    }
  };

  const deleteItem = async (itemId: string) => {
    if (!window.confirm("Supprimer cet élément ?")) return;

    try {
      const { error } = await supabase
        .from('menu_items')
        .delete()
        .eq('id', itemId);

      if (error) throw error;

      onUpdateRestaurant({
        ...restaurant,
        menu: restaurant.menu.filter(m => m.id !== itemId)
      });
    } catch (err) {
      console.error("Error deleting item:", err);
    }
  };

  const addItem = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);

    const price = parseFloat(newItemPrice);
    const newItemPayload = {
      restaurant_id: restaurant.id,
      name: newItemName,
      description: newItemDesc,
      price: price,
      category: newItemCategory,
      is_available: true,
      image: `https://picsum.photos/200/200?random=${Date.now()}`
    };

    try {
      // Insert into DB
      const { data, error } = await supabase
        .from('menu_items')
        .insert(newItemPayload)
        .select()
        .single();

      if (error) throw error;

      if (data) {
        // Update Local
        const newItem: MenuItem = {
          id: data.id,
          name: data.name,
          description: data.description,
          price: data.price,
          category: data.category as any,
          isAvailable: data.is_available,
          image: data.image
        };

        onUpdateRestaurant({
          ...restaurant,
          menu: [...restaurant.menu, newItem]
        });

        // Reset Form
        setNewItemName('');
        setNewItemDesc('');
        setNewItemPrice('');
        setIsAddingItem(false);
      }
    } catch (err) {
      console.error("Error adding item:", err);
      alert("Erreur lors de l'ajout du plat");
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="min-h-screen bg-gray-100 pb-20">
      {/* Header */}
      <header className="bg-white shadow-sm px-6 py-4 flex justify-between items-center sticky top-0 z-10">
        <div>
           <h1 className="text-xl font-black text-brand-600">DashBoard<span className="text-gray-400 text-xs font-normal ml-1">Pro</span></h1>
           <p className="text-xs text-gray-500">Bienvenue, {user.name} ({restaurant.city})</p>
        </div>
        <button onClick={onLogout} className="p-2 bg-gray-100 rounded-full text-gray-600 hover:text-red-500">
          <LogOut size={20} />
        </button>
      </header>

      <main className="p-4 max-w-2xl mx-auto space-y-6">

        {/* Status Card */}
        <div className="bg-white rounded-2xl p-6 shadow-sm border border-gray-100 flex items-center justify-between">
          <div>
            <h2 className="text-lg font-bold text-gray-800">{restaurant.name}</h2>
            <p className="text-sm text-gray-500 capitalize">{restaurant.type} • {restaurant.city}</p>
            <div className={`mt-2 inline-flex items-center px-3 py-1 rounded-full text-xs font-bold ${restaurant.isOpen ? 'bg-green-100 text-green-700' : 'bg-red-100 text-red-700'}`}>
              {restaurant.isOpen ? 'Établissement Ouvert' : 'Établissement Fermé'}
            </div>
          </div>
          <button 
            onClick={toggleOpen}
            className={`w-16 h-16 rounded-full flex flex-col items-center justify-center transition-colors shadow-inner ${restaurant.isOpen ? 'bg-green-500 text-white' : 'bg-red-500 text-white'}`}
          >
            <Power size={24} />
            <span className="text-[10px] font-bold mt-1">{restaurant.isOpen ? 'ON' : 'OFF'}</span>
          </button>
        </div>

        {/* Time Management Card */}
        <div className="bg-white rounded-2xl p-6 shadow-sm border border-gray-100">
           <h3 className="text-sm font-bold text-gray-700 mb-4 flex items-center">
             <Clock size={16} className="mr-2"/> Temps d'attente (minutes)
           </h3>
           <div className="flex space-x-4 mb-3">
             <div className="flex-1">
               <label className="text-xs text-gray-500 font-bold block mb-1">Préparation Cuisine</label>
               <input 
                 type="number" 
                 value={prepTime}
                 onChange={e => setPrepTime(e.target.value)}
                 className="w-full p-2 border border-gray-300 rounded text-sm font-bold text-center"
               />
             </div>
             <div className="flex-1">
               <label className="text-xs text-gray-500 font-bold block mb-1 flex items-center"><Truck size={10} className="mr-1"/> Livraison Moyenne</label>
               <input 
                 type="number" 
                 value={deliveryTime}
                 onChange={e => setDeliveryTime(e.target.value)}
                 className="w-full p-2 border border-gray-300 rounded text-sm font-bold text-center text-brand-600"
               />
             </div>
           </div>
           <button 
             onClick={updateTimes}
             disabled={updatingTimes}
             className="w-full bg-gray-100 text-gray-700 font-bold py-2 rounded-lg text-xs hover:bg-gray-200"
           >
             {updatingTimes ? 'Mise à jour...' : 'Mettre à jour les temps'}
           </button>
        </div>

        {/* Menu Management */}
        <div className="bg-white rounded-2xl shadow-sm border border-gray-100 overflow-hidden">
          <div className="p-4 border-b border-gray-100 flex justify-between items-center bg-gray-50">
            <h3 className="font-bold text-gray-700 flex items-center">
              <Coffee size={18} className="mr-2 text-brand-500"/>
              Menu & Carte ({restaurant.menu.length})
            </h3>
            <button 
              onClick={() => setIsAddingItem(!isAddingItem)}
              className="flex items-center text-xs font-bold bg-brand-600 text-white px-3 py-2 rounded-lg hover:bg-brand-700"
            >
              <Plus size={14} className="mr-1"/> Ajouter
            </button>
          </div>

          {/* Add Item Form */}
          {isAddingItem && (
            <form onSubmit={addItem} className="p-4 bg-brand-50 border-b border-brand-100 animate-in slide-in-from-top">
              <h4 className="font-bold text-brand-800 mb-3 text-sm">Nouveau Plat / Boisson</h4>
              <div className="space-y-3">
                <input 
                  className="w-full p-2 rounded border border-gray-300 text-sm" 
                  placeholder="Nom du produit (ex: Poulet Mayo)"
                  value={newItemName}
                  onChange={e => setNewItemName(e.target.value)}
                  required
                />
                <textarea 
                  className="w-full p-2 rounded border border-gray-300 text-sm" 
                  placeholder="Description courte"
                  value={newItemDesc}
                  onChange={e => setNewItemDesc(e.target.value)}
                  required
                />
                <div className="flex space-x-2">
                   <div className="relative flex-1">
                      <DollarSign size={14} className="absolute left-3 top-3 text-gray-400"/>
                      <input 
                        type="number" 
                        step="0.1"
                        className="w-full pl-8 p-2 rounded border border-gray-300 text-sm" 
                        placeholder="Prix"
                        value={newItemPrice}
                        onChange={e => setNewItemPrice(e.target.value)}
                        required
                      />
                   </div>
                   <select 
                      className="p-2 rounded border border-gray-300 text-sm flex-1"
                      value={newItemCategory}
                      onChange={(e) => setNewItemCategory(e.target.value as any)}
                   >
                     <option value="plat">Plat</option>
                     <option value="entrée">Entrée</option>
                     <option value="boisson">Boisson</option>
                     <option value="dessert">Dessert</option>
                   </select>
                </div>
                <div className="flex justify-end space-x-2 pt-2">
                  <button type="button" onClick={() => setIsAddingItem(false)} className="px-3 py-1 text-sm text-gray-500">Annuler</button>
                  <button 
                    type="submit" 
                    disabled={loading}
                    className="px-4 py-1.5 bg-brand-600 text-white text-sm font-bold rounded-lg shadow-sm disabled:opacity-50"
                  >
                    {loading ? '...' : 'Enregistrer'}
                  </button>
                </div>
              </div>
            </form>
          )}

          {/* List Items */}
          <div className="divide-y divide-gray-100">
            {restaurant.menu.length === 0 ? (
                <div className="p-8 text-center text-gray-400 text-sm">
                    Votre carte est vide. Ajoutez votre premier plat !
                </div>
            ) : (
                restaurant.menu.map(item => (
                <div key={item.id} className="p-4 flex items-center justify-between hover:bg-gray-50">
                    <div className="flex items-center space-x-3">
                    <img src={item.image} alt={item.name} className="w-12 h-12 rounded-lg object-cover bg-gray-200" />
                    <div>
                        <p className="font-bold text-gray-800 text-sm">{item.name}</p>
                        <p className="text-xs text-gray-500">{item.price.toFixed(2)} $ • {item.category}</p>
                    </div>
                    </div>
                    <button onClick={() => deleteItem(item.id)} className="text-red-400 hover:text-red-600 p-2">
                    <Trash2 size={16} />
                    </button>
                </div>
                ))
            )}
          </div>
        </div>
      </main>
    </div>
  );
};

export interface Location {
  latitude: number;
  longitude: number;
}

export interface MenuItem {
  id: string;
  name: string;
  description: string;
  price: number;
  image: string;
  category: 'entrée' | 'plat' | 'boisson' | 'dessert';
  isAvailable: boolean;
}

export type BusinessType = 'restaurant' | 'bar' | 'terrasse' | 'snack';

export interface Restaurant {
  id: string;
  ownerId: string; // Lien avec le compte entreprise
  type: BusinessType;
  name: string;
  description: string;
  latitude: number;
  longitude: number;
  city: string; // Ville de l'établissement
  isOpen: boolean;
  rating: number; // 1-5
  reviewCount: number;
  preparationTime: number; // in minutes
  estimatedDeliveryTime: number; // in minutes (Temps moyen de livraison)
  deliveryAvailable: boolean;
  coverImage: string;
  menu: MenuItem[];
  // Calculated fields
  distance?: number; // km
  timeWalking?: number; // minutes
  timeMoto?: number; // minutes
}

export interface CartItem extends MenuItem {
  quantity: number;
  restaurantId: string;
  restaurantName: string;
}

export type ViewMode = 'list' | 'map' | 'restaurant_detail' | 'checkout' | 'success' | 'orders';

export interface UserState {
  location: Location | null;
  locationError: string | null;
  loadingLocation: boolean;
}

