      </header>

      {/* Tabs */}
      <div className="bg-white border-b border-gray-200 px-4 flex">
          <button 
            onClick={() => setActiveTab('menu')}
            className={`flex-1 py-4 text-sm font-bold border-b-2 ${activeTab === 'menu' ? 'border-brand-600 text-brand-600' : 'border-transparent text-gray-500'}`}
