          <button 
            onClick={() => setActiveTab('orders')}
            className={`flex-1 py-4 text-sm font-bold border-b-2 ${activeTab === 'orders' ? 'border-brand-600 text-brand-600' : 'border-transparent text-gray-500'}`}
