                            </div>

                            <div className="p-4 bg-white">
                                <ul className="space-y-2 mb-4">
                                    {order.items.map((item, i) => (
                                        <li key={i} className="flex justify-between text-sm text-gray-700 border-b border-dashed border-gray-100 pb-1 last:border-0">
                                            <span><span className="font-bold">x{item.quantity}</span> {item.name}</span>
                                        </li>
                                    ))}
                                </ul>

                                {/* Action Buttons */}
                                <div className="grid grid-cols-2 gap-2 mt-2">
                                    {order.status === 'pending' && (
                                        <>
                                            <button 
                                                onClick={() => updateOrderStatus(order.id, 'cancelled')}
                                                className="py-2 bg-red-50 text-red-600 text-xs font-bold rounded-lg"
                                            >
                                                Refuser
                                            </button>
                                            <button 
                                                onClick={() => updateOrderStatus(order.id, 'preparing')}
                                                className="py-2 bg-brand-600 text-white text-xs font-bold rounded-lg flex justify-center items-center"
                                            >
                                                <ChefHat size={14} className="mr-1"/> Cuisiner
                                            </button>
                                        </>
                                    )}
                                    {order.status === 'preparing' && (
                                         <button 
                                            onClick={() => updateOrderStatus(order.id, 'ready')}
                                            className="col-span-2 py-2 bg-blue-600 text-white text-xs font-bold rounded-lg flex justify-center items-center"
                                        >
                                            <CheckCircle size={14} className="mr-1"/> Prêt à servir
                                        </button>
                                    )}
                                    {order.status === 'ready' && (
                                         <button 
                                            onClick={() => updateOrderStatus(order.id, 'delivering')}
                                            className="col-span-2 py-2 bg-orange-500 text-white text-xs font-bold rounded-lg flex justify-center items-center"
                                        >
                                            <Bike size={14} className="mr-1"/> Expédier
                                        </button>
                                    )}
                                    {order.status === 'delivering' && (
                                         <button 
                                            onClick={() => updateOrderStatus(order.id, 'completed')}
                                            className="col-span-2 py-2 bg-green-600 text-white text-xs font-bold rounded-lg flex justify-center items-center"
                                        >
                                            <CheckCircle size={14} className="mr-1"/> Confirmer Livraison
                                        </button>
                                    )}
                                </div>
                            </div>
                        </div>
                    ))
                )}
            </div>
        )}

      </main>
    </div>
  );
};

