create table if not exists public.profiles (
  id uuid references auth.users on delete cascade not null primary key,
  full_name text,
  role text check (role in ('client', 'business')) not null,
  created_at timestamp with time zone default timezone('utc'::text, now()) not null
);

-- Add city column safely if it doesn't exist
do $$ 
begin 
  if not exists (select 1 from information_schema.columns where table_name = 'profiles' and column_name = 'city') then
    alter table public.profiles add column city text; 
  end if; 
end $$;

alter table public.profiles enable row level security;

-- Re-create policies to ensure they exist
drop policy if exists "Les profils sont visibles par tous" on profiles;
create policy "Les profils sont visibles par tous" on profiles for select using (true);

drop policy if exists "Les utilisateurs peuvent créer leur propre profil" on profiles;
create policy "Les utilisateurs peuvent créer leur propre profil" on profiles for insert with check (auth.uid() = id);

drop policy if exists "Les utilisateurs peuvent modifier leur propre profil" on profiles;
create policy "Les utilisateurs peuvent modifier leur propre profil" on profiles for update using (auth.uid() = id);


-- 2. Table des Restaurants
create table if not exists public.restaurants (
  id uuid default gen_random_uuid() primary key,
  owner_id uuid references auth.users not null,
  name text not null,
  type text check (type in ('restaurant', 'bar', 'terrasse', 'snack')) not null,
  description text,
  latitude double precision not null,
  longitude double precision not null,
  is_open boolean default true,
  rating double precision default 5.0,
  review_count int default 0,
  preparation_time int default 30,
  delivery_available boolean default true,
  cover_image text,
  created_at timestamp with time zone default timezone('utc'::text, now()) not null
);

-- Add columns safely
do $$ 
begin 
  if not exists (select 1 from information_schema.columns where table_name = 'restaurants' and column_name = 'city') then
    alter table public.restaurants add column city text; 
  end if; 
  if not exists (select 1 from information_schema.columns where table_name = 'restaurants' and column_name = 'estimated_delivery_time') then
    alter table public.restaurants add column estimated_delivery_time int default 20; 
  end if; 
end $$;

alter table public.restaurants enable row level security;

drop policy if exists "Les restaurants sont visibles par tous" on restaurants;
create policy "Les restaurants sont visibles par tous" on restaurants for select using (true);

drop policy if exists "Les propriétaires peuvent ajouter un restaurant" on restaurants;
create policy "Les propriétaires peuvent ajouter un restaurant" on restaurants for insert with check (auth.uid() = owner_id);

drop policy if exists "Les propriétaires peuvent modifier leur restaurant" on restaurants;
create policy "Les propriétaires peuvent modifier leur restaurant" on restaurants for update using (auth.uid() = owner_id);


-- 3. Table des Plats (Menu Items)
create table if not exists public.menu_items (
  id uuid default gen_random_uuid() primary key,
  restaurant_id uuid references public.restaurants on delete cascade not null,
  name text not null,
  description text,
  price double precision not null,
  category text check (category in ('entrée', 'plat', 'boisson', 'dessert')) not null,
  image text,
  is_available boolean default true,
  created_at timestamp with time zone default timezone('utc'::text, now()) not null
);

alter table public.menu_items enable row level security;

drop policy if exists "Le menu est visible par tous" on menu_items;
create policy "Le menu est visible par tous" on menu_items for select using (true);

drop policy if exists "Les propriétaires peuvent ajouter des plats" on menu_items;
create policy "Les propriétaires peuvent ajouter des plats" on menu_items for insert with check (
    exists ( select 1 from restaurants where id = menu_items.restaurant_id and owner_id = auth.uid() )
);

drop policy if exists "Les propriétaires peuvent modifier des plats" on menu_items;
create policy "Les propriétaires peuvent modifier des plats" on menu_items for update using (
    exists ( select 1 from restaurants where id = menu_items.restaurant_id and owner_id = auth.uid() )
);

drop policy if exists "Les propriétaires peuvent supprimer des plats" on menu_items;
create policy "Les propriétaires peuvent supprimer des plats" on menu_items for delete using (
    exists ( select 1 from restaurants where id = menu_items.restaurant_id and owner_id = auth.uid() )
);


-- 4. Table des Commandes (Orders)
create table if not exists public.orders (
  id uuid default gen_random_uuid() primary key,
  user_id uuid references auth.users not null,
  restaurant_id uuid references public.restaurants not null,
  status text check (status in ('pending', 'preparing', 'ready', 'delivering', 'completed', 'cancelled')) default 'pending',
  total_amount double precision not null,
  items jsonb not null,
  created_at timestamp with time zone default timezone('utc'::text, now()) not null
);

alter table public.orders enable row level security;

drop policy if exists "Clients can view their own orders" on orders;
create policy "Clients can view their own orders" on orders for select using (auth.uid() = user_id);

drop policy if exists "Restaurant owners can view orders for their restaurant" on orders;
create policy "Restaurant owners can view orders for their restaurant" 
  on orders for select using (
    exists (
      select 1 from restaurants 
      where id = orders.restaurant_id 
      and owner_id = auth.uid()
    )
  );

drop policy if exists "Clients can insert their own orders" on orders;
create policy "Clients can insert their own orders" on orders for insert with check (auth.uid() = user_id);

drop policy if exists "Restaurant owners can update orders" on orders;
create policy "Restaurant owners can update orders" 
  on orders for update using (
    exists (
      select 1 from restaurants 
      where id = orders.restaurant_id 
      and owner_id = auth.uid()
    )
  );

import React, { useState, useEffect, useMemo } from 'react';
import { MapPin, ShoppingBag, List, Map, Zap, ArrowLeft, Plus, Bike, Footprints, LogOut, Navigation, Filter, Clock, Receipt, CheckCircle, ChefHat, Package } from 'lucide-react';
import { supabase } from '../lib/supabase';
import { KINSHASA_CENTER_LAT, KINSHASA_CENTER_LNG, CITIES_RDC } from '../constants';
import { Restaurant, UserState, ViewMode, MenuItem, CartItem, User, Order } from '../types';
import { calculateTime, getDistanceFromLatLonInKm, formatDistance, formatTime } from '../utils/geo';
import { RestaurantCard } from './RestaurantCard';
import { MapView } from './MapView';
import { CartDrawer } from './CartDrawer';

// Speed constants
const SPEED_WALKING = 5;
const SPEED_MOTO = 30;

interface Props {
  user: User;
  allRestaurants: Restaurant[];
  onLogout: () => void;
}

export const CustomerView: React.FC<Props> = ({ user, allRestaurants, onLogout }) => {
  // State
  const [userState, setUserState] = useState<UserState>({
    location: null,
    locationError: null,
    loadingLocation: true,
  });

  const [restaurants, setRestaurants] = useState<Restaurant[]>([]);
  const [viewMode, setViewMode] = useState<ViewMode>('list');
  const [selectedRestaurant, setSelectedRestaurant] = useState<Restaurant | null>(null);
  const [cart, setCart] = useState<CartItem[]>([]);
  const [isCartOpen, setIsCartOpen] = useState(false);
  const [urgentMode, setUrgentMode] = useState(false);
  const [showSuccess, setShowSuccess] = useState(false);
  const [selectedCity, setSelectedCity] = useState<string>(user.city || 'Kinshasa');

  // Order States
  const [orders, setOrders] = useState<Order[]>([]);
  const [isCheckingOut, setIsCheckingOut] = useState(false);

  // Initial Geolocation
  useEffect(() => {
    if (!navigator.geolocation) {
      setUserState({
        location: null,
        locationError: "La géolocalisation n'est pas supportée par votre navigateur",
        loadingLocation: false
      });
      return;
    }

    navigator.geolocation.getCurrentPosition(
      (position) => {
        setUserState({
          location: {
            latitude: position.coords.latitude,
            longitude: position.coords.longitude,
          },
          locationError: null,
          loadingLocation: false
        });
      },
      (error) => {
        console.warn("Geo error:", error);
        setUserState({
            location: {
                latitude: KINSHASA_CENTER_LAT,
                longitude: KINSHASA_CENTER_LNG
            },
            locationError: "Position introuvable. Utilisation de la position par défaut (Kinshasa).",
            loadingLocation: false
        });
      },
      { enableHighAccuracy: true, timeout: 5000, maximumAge: 0 }
    );
  }, []);

  // Update Restaurants when location or database changes
  useEffect(() => {
    if (userState.location) {
      const updatedRestaurants = allRestaurants.map(r => {
        const dist = getDistanceFromLatLonInKm(
          userState.location!.latitude,
          userState.location!.longitude,
          r.latitude,
          r.longitude
        );
        return {
          ...r,
          distance: dist,
          timeWalking: calculateTime(dist, SPEED_WALKING),
          timeMoto: calculateTime(dist, SPEED_MOTO),
        };
      }).sort((a, b) => (a.distance || 0) - (b.distance || 0));

      setRestaurants(updatedRestaurants);
    } else {
      setRestaurants(allRestaurants);
    }
  }, [userState.location, allRestaurants]);

  // Load Orders when entering 'orders' view
  useEffect(() => {
    if (viewMode === 'orders') {
        fetchOrders();
    }
  }, [viewMode]);

  const fetchOrders = async () => {
    try {
        const { data, error } = await supabase
            .from('orders')
            .select(`
                *,
                restaurant:restaurants(name)
            `)
            .eq('user_id', user.id)
            .order('created_at', { ascending: false });

        if (error) throw error;

        if (data) {
            setOrders(data.map((o: any) => ({
                id: o.id,
                userId: o.user_id,
                restaurantId: o.restaurant_id,
                status: o.status,
                totalAmount: o.total_amount,
                items: o.items,
                createdAt: o.created_at,
                restaurant: o.restaurant
            })));
        }
    } catch (err) {
        console.error("Error fetching orders:", err);
    }
  };

  // Filter Logic (City + Urgent)
  const filteredRestaurants = useMemo(() => {
    let list = restaurants;

    // Filter by City
    if (selectedCity && selectedCity !== 'Toutes') {
      list = list.filter(r => r.city === selectedCity);
    }

    // Filter by Urgent Mode
    if (urgentMode) {
      list = list.filter(r => r.isOpen && r.preparationTime <= 20);
    }

    return list;
  }, [restaurants, urgentMode, selectedCity]);

  // Cart Logic
  const addToCart = (item: MenuItem, restaurant: Restaurant) => {
    // If cart has items from another restaurant, confirm clear
    if (cart.length > 0 && cart[0].restaurantId !== restaurant.id) {
        if(!window.confirm("Vous ne pouvez commander que dans un restaurant à la fois. Vider le panier actuel ?")) {
            return;
        }
        setCart([]);
    }

    setCart(prev => {
        const existing = prev.find(i => i.id === item.id);
        if (existing) {
             return prev.map(i => i.id === item.id ? { ...i, quantity: i.quantity + 1 } : i);
        }
        return [...prev, { ...item, quantity: 1, restaurantId: restaurant.id, restaurantName: restaurant.name }];
    });
  };

  const removeFromCart = (itemId: string) => {
    setCart(prev => {
        const index = prev.findIndex(i => i.id === itemId);
        if (index > -1) {
            const newArr = [...prev];
            newArr.splice(index, 1);
            return newArr;
        }
        return prev;
    });
  };

  const cartTotal = cart.reduce((sum, item) => sum + (item.price * item.quantity), 0);

  const handleCheckout = async () => {
    if (cart.length === 0) return;
    setIsCheckingOut(true);

    try {
        const restaurantId = cart[0].restaurantId;

        const { error } = await supabase
            .from('orders')
            .insert({
                user_id: user.id,
                restaurant_id: restaurantId,
                status: 'pending',
                total_amount: cartTotal,
                items: cart
            });

        if (error) throw error;

        setIsCartOpen(false);
        setShowSuccess(true);
        setCart([]);
        setTimeout(() => {
            setShowSuccess(false);
            setViewMode('orders'); // Redirect to orders view
            fetchOrders();
        }, 3000);

    } catch (err) {
        console.error("Checkout error:", err);
        alert("Une erreur est survenue lors de la commande.");
    } finally {
        setIsCheckingOut(false);
    }
  };

  const getStatusColor = (status: string) => {
    switch (status) {
        case 'pending': return 'bg-gray-100 text-gray-700';
        case 'preparing': return 'bg-yellow-100 text-yellow-800';
        case 'ready': return 'bg-blue-100 text-blue-800';
        case 'delivering': return 'bg-orange-100 text-orange-800';
        case 'completed': return 'bg-green-100 text-green-800';
        case 'cancelled': return 'bg-red-100 text-red-800';
        default: return 'bg-gray-100';
    }
  };

  const getStatusLabel = (status: string) => {
    switch (status) {
        case 'pending': return 'En attente';
        case 'preparing': return 'En cuisine';
        case 'ready': return 'Prêt';
        case 'delivering': return 'En livraison';
        case 'completed': return 'Livré';
        case 'cancelled': return 'Annulé';
        default: return status;
    }
  };

  const getProgressWidth = (status: string) => {
    switch(status) {
      case 'pending': return '10%';
      case 'preparing': return '35%';
      case 'ready': return '60%';
      case 'delivering': return '80%';
      case 'completed': return '100%';
      default: return '0%';
    }
  };

  // Views
  if (userState.loadingLocation) {
    return (
      <div className="min-h-screen flex flex-col items-center justify-center bg-brand-50">
        <div className="w-16 h-16 border-4 border-brand-500 border-t-transparent rounded-full animate-spin"></div>
        <p className="mt-4 text-brand-800 font-medium">Localisation en cours...</p>
      </div>
    );
  }

  return (
    <div className="min-h-screen pb-20 max-w-md mx-auto bg-gray-50 shadow-2xl overflow-hidden relative">

      {/* SUCCESS OVERLAY */}
      {showSuccess && (
        <div className="absolute inset-0 z-[60] bg-brand-500 flex flex-col items-center justify-center text-white p-6 text-center animate-fade-in">
           <div className="w-20 h-20 bg-white rounded-full flex items-center justify-center mb-6 shadow-xl">
              <ShoppingBag className="text-brand-500" size={40} />
           </div>
           <h2 className="text-3xl font-bold mb-2">Commande Reçue !</h2>
           <p className="text-brand-100">Votre repas est en préparation.</p>
           <div className="mt-8 bg-white/20 p-4 rounded-xl backdrop-blur-sm">
             <p className="font-mono text-sm">Vous pouvez suivre le statut dans "Commandes"</p>
           </div>
        </div>
      )}

      {/* HEADER */}
      <header className="bg-white sticky top-0 z-30 px-4 py-3 shadow-sm border-b border-gray-100">
        <div className="flex justify-between items-center mb-2">
            <div className="flex items-center">
                <h1 className="text-xl font-black text-brand-600 tracking-tight mr-2">DashMeals</h1>
                <span className="text-xs bg-brand-100 text-brand-800 px-2 py-0.5 rounded-full font-bold">Client</span>
            </div>
          <div className="flex items-center space-x-2">
            <button onClick={() => setIsCartOpen(true)} className="relative p-2 bg-gray-100 rounded-full hover:bg-gray-200 transition-colors">
                <ShoppingBag size={20} className="text-gray-700" />
                {cart.length > 0 && (
                <span className="absolute top-0 right-0 bg-red-500 text-white text-[10px] font-bold h-4 w-4 flex items-center justify-center rounded-full border-2 border-white">
                    {cart.length}
                </span>
                )}
            </button>
            <button onClick={onLogout} className="p-2 text-gray-400 hover:text-red-500">
                <LogOut size={20} />
            </button>
          </div>
        </div>

        {/* Location & City Filter - Only show in list/map mode */}
        {(viewMode === 'list' || viewMode === 'map') && (
            <div className="flex items-center space-x-2">
                <div className="flex-1 flex items-center text-sm text-gray-500 bg-gray-50 p-2 rounded-lg truncate">
                <MapPin size={14} className="mr-1.5 text-brand-500 flex-shrink-0" />
                <span className="truncate">
                    {userState.locationError ? "Mode Démo" : "Ma Position"}
                </span>
                </div>

                <select 
                className="bg-brand-50 text-brand-700 text-xs font-bold py-2 pl-2 pr-6 rounded-lg border border-brand-200 outline-none appearance-none bg-[url('data:image/svg+xml;charset=US-ASCII,%3Csvg%20xmlns%3D%22http%3A%2F%2Fwww.w3.org%2F2000%2Fsvg%22%20width%3D%22292.4%22%20height%3D%22292.4%22%3E%3Cpath%20fill%3D%22%23ea580c%22%20d%3D%22M287%2069.4a17.6%2017.6%200%200%200-13-5.4H18.4c-5%200-9.3%201.8-12.9%205.4A17.6%2017.6%200%200%200%200%2082.2c0%205%201.8%209.3%205.4%2012.9l128%20127.9c3.6%203.6%207.8%205.4%2012.8%205.4s9.2-1.8%2012.8-5.4L287%2095c3.5-3.5%205.4-7.8%205.4-12.8%200-5-1.9-9.2-5.5-12.8z%22%2F%3E%3C%2Fsvg%3E')] bg-[length:10px] bg-[right_8px_center] bg-no-repeat"
