create table if not exists public.profiles (
  id uuid references auth.users on delete cascade not null primary key,
  full_name text,
  role text check (role in ('client', 'business')) not null,
  created_at timestamp with time zone default timezone('utc'::text, now()) not null
);

-- Add city column safely if it doesn't exist
do $$ 
begin 
  if not exists (select 1 from information_schema.columns where table_name = 'profiles' and column_name = 'city') then
    alter table public.profiles add column city text; 
  end if; 
end $$;

alter table public.profiles enable row level security;

-- Re-create policies to ensure they exist
drop policy if exists "Les profils sont visibles par tous" on profiles;
create policy "Les profils sont visibles par tous" on profiles for select using (true);

drop policy if exists "Les utilisateurs peuvent créer leur propre profil" on profiles;
create policy "Les utilisateurs peuvent créer leur propre profil" on profiles for insert with check (auth.uid() = id);

drop policy if exists "Les utilisateurs peuvent modifier leur propre profil" on profiles;
create policy "Les utilisateurs peuvent modifier leur propre profil" on profiles for update using (auth.uid() = id);


-- 2. Table des Restaurants
create table if not exists public.restaurants (
  id uuid default gen_random_uuid() primary key,
  owner_id uuid references auth.users not null,
  name text not null,
  type text check (type in ('restaurant', 'bar', 'terrasse', 'snack')) not null,
  description text,
  latitude double precision not null,
  longitude double precision not null,
  is_open boolean default true,
  rating double precision default 5.0,
  review_count int default 0,
  preparation_time int default 30,
  delivery_available boolean default true,
  cover_image text,
  created_at timestamp with time zone default timezone('utc'::text, now()) not null
);

-- Add columns safely
do $$ 
begin 
  if not exists (select 1 from information_schema.columns where table_name = 'restaurants' and column_name = 'city') then
    alter table public.restaurants add column city text; 
  end if; 
  if not exists (select 1 from information_schema.columns where table_name = 'restaurants' and column_name = 'estimated_delivery_time') then
    alter table public.restaurants add column estimated_delivery_time int default 20; 
  end if; 
end $$;

alter table public.restaurants enable row level security;

drop policy if exists "Les restaurants sont visibles par tous" on restaurants;
create policy "Les restaurants sont visibles par tous" on restaurants for select using (true);

drop policy if exists "Les propriétaires peuvent ajouter un restaurant" on restaurants;
create policy "Les propriétaires peuvent ajouter un restaurant" on restaurants for insert with check (auth.uid() = owner_id);

drop policy if exists "Les propriétaires peuvent modifier leur restaurant" on restaurants;
create policy "Les propriétaires peuvent modifier leur restaurant" on restaurants for update using (auth.uid() = owner_id);


-- 3. Table des Plats (Menu Items)
create table if not exists public.menu_items (
  id uuid default gen_random_uuid() primary key,
  restaurant_id uuid references public.restaurants on delete cascade not null,
  name text not null,
  description text,
  price double precision not null,
  category text check (category in ('entrée', 'plat', 'boisson', 'dessert')) not null,
  image text,
  is_available boolean default true,
  created_at timestamp with time zone default timezone('utc'::text, now()) not null
);

alter table public.menu_items enable row level security;

drop policy if exists "Le menu est visible par tous" on menu_items;
create policy "Le menu est visible par tous" on menu_items for select using (true);

drop policy if exists "Les propriétaires peuvent ajouter des plats" on menu_items;
create policy "Les propriétaires peuvent ajouter des plats" on menu_items for insert with check (
    exists ( select 1 from restaurants where id = menu_items.restaurant_id and owner_id = auth.uid() )
);

drop policy if exists "Les propriétaires peuvent modifier des plats" on menu_items;
create policy "Les propriétaires peuvent modifier des plats" on menu_items for update using (
    exists ( select 1 from restaurants where id = menu_items.restaurant_id and owner_id = auth.uid() )
);

drop policy if exists "Les propriétaires peuvent supprimer des plats" on menu_items;
create policy "Les propriétaires peuvent supprimer des plats" on menu_items for delete using (
    exists ( select 1 from restaurants where id = menu_items.restaurant_id and owner_id = auth.uid() )
);


-- 4. Table des Commandes (Orders)
create table if not exists public.orders (
  id uuid default gen_random_uuid() primary key,
  user_id uuid references auth.users not null,
  restaurant_id uuid references public.restaurants not null,
  status text check (status in ('pending', 'preparing', 'ready', 'delivering', 'completed', 'cancelled')) default 'pending',
  total_amount double precision not null,
  items jsonb not null,
  created_at timestamp with time zone default timezone('utc'::text, now()) not null
);

alter table public.orders enable row level security;

drop policy if exists "Clients can view their own orders" on orders;
create policy "Clients can view their own orders" on orders for select using (auth.uid() = user_id);

drop policy if exists "Restaurant owners can view orders for their restaurant" on orders;
create policy "Restaurant owners can view orders for their restaurant" 
  on orders for select using (
    exists (
      select 1 from restaurants 
      where id = orders.restaurant_id 
      and owner_id = auth.uid()
    )
  );

drop policy if exists "Clients can insert their own orders" on orders;
create policy "Clients can insert their own orders" on orders for insert with check (auth.uid() = user_id);

drop policy if exists "Restaurant owners can update orders" on orders;
create policy "Restaurant owners can update orders" 
  on orders for update using (
    exists (
      select 1 from restaurants 
      where id = orders.restaurant_id 
      and owner_id = auth.uid()
    )
  );

-- 5. Table des Villes (Cities)
create table if not exists public.cities (
  id uuid default gen_random_uuid() primary key,
  name text not null unique,
  province text,
  latitude double precision,
  longitude double precision,
  is_active boolean default true,
  created_at timestamp with time zone default timezone('utc'::text, now()) not null
);

alter table public.cities enable row level security;

drop policy if exists "Les villes sont visibles par tous" on cities;
create policy "Les villes sont visibles par tous" on cities for select using (true);

