          </button>
          <button 
            onClick={() => setActiveTab('orders')}
            className={`flex-1 py-4 text-sm font-bold border-b-2 ${activeTab === 'orders' ? 'border-brand-600 text-brand-600' : 'border-transparent text-gray-500'}`}
          >
              <Receipt size={18} className="inline mr-2 mb-1"/> Commandes
          </button>
      </div>

      <main className="p-4 max-w-2xl mx-auto space-y-6">

        {activeTab === 'menu' ? (
            <>
                {/* Status Card */}
                <div className="bg-white rounded-2xl p-6 shadow-sm border border-gray-100 flex items-center justify-between">
                <div>
                    <h2 className="text-lg font-bold text-gray-800">{restaurant.name}</h2>
