import React, { useState, useEffect } from 'react';
import { supabase } from '../lib/supabase';
import { User, UserRole, BusinessType } from '../types';
import { CITIES_RDC } from '../constants';
import { User as UserIcon, Store, AlertCircle, MapPin } from 'lucide-react';

interface Props {
  onLogin: (user: User, businessData?: any) => void;
}

export const AuthScreen: React.FC<Props> = ({ onLogin }) => {
  const [isLogin, setIsLogin] = useState(true);
  const [role, setRole] = useState<UserRole>('client');
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  // Form States
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [name, setName] = useState('');
  const [city, setCity] = useState('Kinshasa');
  const [availableCities, setAvailableCities] = useState<string[]>(CITIES_RDC);

  // Business Specific States
  const [businessType, setBusinessType] = useState<BusinessType>('restaurant');
  const [businessName, setBusinessName] = useState('');

  // Fetch cities from DB on mount
  useEffect(() => {
    const fetchCities = async () => {
      try {
        const { data, error } = await supabase
          .from('cities')
          .select('name')
          .eq('is_active', true)
          .order('name');

        if (!error && data && data.length > 0) {
          setAvailableCities(data.map(c => c.name));
        }
      } catch (err) {
        console.warn("Could not fetch cities from DB, using defaults");
      }
    };
    fetchCities();
  }, []);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);
    setError(null);

    try {
      if (isLogin) {
        // LOGIN
        const { error } = await supabase.auth.signInWithPassword({
          email,
          password,
        });
        if (error) throw error;
      } else {
        // SIGN UP
        const { data: authData, error: authError } = await supabase.auth.signUp({
          email,
          password,
          options: {
            data: { full_name: name, role: role, city: city } // Metadata
          }
        });

        if (authError) throw authError;

        // Supabase sign up logic handling
        if (authData.user) {
          // Check for existing identity handling (Supabase sometimes returns user without error if exists)
          if (authData.user.identities && authData.user.identities.length === 0) {
             throw new Error("Cet email est déjà enregistré. Veuillez vous connecter.");
          }

          // 1. Create Profile in DB
          // Using upsert can be safer, but insert helps catch duplicates if logic fails
          const { error: profileError } = await supabase.from('profiles').insert({
            id: authData.user.id,
            role: role,
            full_name: name,
            city: city
          });

          if (profileError) {
             // Ignore duplicate key error for profiles if retrying signup
             if (!profileError.message.includes('duplicate key')) {
                throw profileError;
             }
          }

          // 2. If Business, Create Restaurant
          if (role === 'business') {
            const { error: restoError } = await supabase.from('restaurants').insert({
              owner_id: authData.user.id,
              name: businessName,
              type: businessType,
              city: city, 
              latitude: -4.301 + (Math.random() - 0.5) * 0.02, 
              longitude: 15.301 + (Math.random() - 0.5) * 0.02,
              description: `Bienvenue chez ${businessName}`,
              cover_image: `https://picsum.photos/800/600?random=${Date.now()}`,
              preparation_time: 30,
              estimated_delivery_time: 30 // Default 30 min delivery time
            });
            if (restoError) throw restoError;
          }
        }
      }
    } catch (err: any) {
      console.error("Auth Error:", err);
      let message = err.message || "Une erreur est survenue";
      const lowerMsg = message.toLowerCase();

      // Translate common Supabase errors
      if (lowerMsg.includes("rate limit") || lowerMsg.includes("too many requests") || err.status === 429) {
        message = "Trop de tentatives. Veuillez patienter quelques minutes avant de réessayer.";
      } else if (lowerMsg.includes("invalid login credentials")) {
        message = "Email ou mot de passe incorrect.";
      } else if (lowerMsg.includes("user already registered") || lowerMsg.includes("already registered")) {
        message = "Cet email est déjà associé à un compte. Connectez-vous.";
      } else if (lowerMsg.includes("password should be at least")) {
        message = "Le mot de passe doit contenir au moins 6 caractères.";
      }

      setError(message);
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="min-h-screen bg-brand-50 flex flex-col items-center justify-center p-4">
      <div className="bg-white w-full max-w-md rounded-2xl shadow-xl overflow-hidden">

        {/* Header */}
        <div className="bg-brand-600 p-6 text-center">
          <h1 className="text-3xl font-black text-white tracking-tight">DashMeals<span className="text-brand-200 text-xs font-normal ml-1">RDC</span></h1>
          <p className="text-brand-100 mt-2">La plateforme gourmande de Kinshasa</p>
        </div>

        {/* Tabs */}
        <div className="flex border-b">
          <button 
            type="button"
            onClick={() => setRole('client')}
            className={`flex-1 py-4 text-sm font-bold flex items-center justify-center ${role === 'client' ? 'text-brand-600 border-b-2 border-brand-600 bg-brand-50' : 'text-gray-500'}`}
          >
            <UserIcon size={18} className="mr-2" />
            Client
          </button>
          <button 
            type="button"
            onClick={() => setRole('business')}
            className={`flex-1 py-4 text-sm font-bold flex items-center justify-center ${role === 'business' ? 'text-brand-600 border-b-2 border-brand-600 bg-brand-50' : 'text-gray-500'}`}
          >
            <Store size={18} className="mr-2" />
            Entreprise
          </button>
        </div>

        {/* Form */}
        <form onSubmit={handleSubmit} className="p-6 space-y-4">
          <h2 className="text-xl font-bold text-gray-800 text-center mb-6">
            {isLogin ? 'Connexion' : 'Créer un compte'} {role === 'business' ? 'Partenaire' : ''}
          </h2>

          {error && (
            <div className="bg-red-50 text-red-600 p-3 rounded-lg text-sm flex items-center animate-pulse">
              <AlertCircle size={16} className="mr-2 flex-shrink-0" />
              <span>{error}</span>
            </div>
          )}

          {!isLogin && (
            <div>
              <label className="block text-xs font-bold text-gray-600 mb-1">Votre Nom</label>
              <input 
                type="text" 
                required 
                className="w-full p-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-brand-500 outline-none"
                placeholder="Ex: Jean K."
                value={name}
                onChange={(e) => setName(e.target.value)}
              />
            </div>
          )}

          {/* City Selection for both Roles during Signup */}
          {!isLogin && (
             <div>
                <label className="block text-xs font-bold text-gray-600 mb-1 flex items-center">
                  <MapPin size={12} className="mr-1"/> 
                  {role === 'business' ? 'Ville du commerce' : 'Votre Ville'}
                </label>
                <select 
                  className="w-full p-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-brand-500 outline-none bg-white text-gray-900"
                  value={city}
                  onChange={(e) => setCity(e.target.value)}
                >
                  {availableCities.map(c => (
                    <option key={c} value={c} className="text-gray-900">{c}</option>
                  ))}
                </select>
             </div>
          )}

          {/* Business Specific Fields during Signup */}
          {!isLogin && role === 'business' && (
            <div className="bg-gray-50 p-4 rounded-lg border border-gray-200 space-y-3">
              <h3 className="text-sm font-bold text-gray-700 flex items-center"><Store size={14} className="mr-2"/> Infos Établissement</h3>
              <div>
                <label className="block text-xs font-bold text-gray-500 mb-1">Nom du commerce</label>
                <input 
                  type="text" 
                  required 
                  className="w-full p-2 border border-gray-300 rounded focus:ring-1 focus:ring-brand-500 outline-none"
                  placeholder="Ex: Chez Ntemba"
                  value={businessName}
                  onChange={(e) => setBusinessName(e.target.value)}
                />
              </div>
              <div>
                <label className="block text-xs font-bold text-gray-500 mb-1">Type</label>
                <select 
                  className="w-full p-2 border border-gray-300 rounded bg-white text-gray-900"
                  value={businessType}
                  onChange={(e) => setBusinessType(e.target.value as BusinessType)}
                >
                  <option value="restaurant" className="text-gray-900">Restaurant</option>
                  <option value="bar" className="text-gray-900">Bar / Lounge</option>
                  <option value="terrasse" className="text-gray-900">Terrasse</option>
                  <option value="snack" className="text-gray-900">Snack / Fast-food</option>
                </select>
              </div>
            </div>
          )}

          <div>
            <label className="block text-xs font-bold text-gray-600 mb-1">Email</label>
            <input 
              type="email" 
              required 
              className="w-full p-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-brand-500 outline-none"
              placeholder="Ex: nom@mail.com"
              value={email}
              onChange={(e) => setEmail(e.target.value)}
            />
          </div>

          <div>
            <label className="block text-xs font-bold text-gray-600 mb-1">Mot de passe</label>
            <input 
              type="password" 
              required 
              className="w-full p-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-brand-500 outline-none"
              placeholder="••••••••"
              value={password}
              onChange={(e) => setPassword(e.target.value)}
            />
          </div>

          <button 
            type="submit"
            disabled={loading}
            className={`w-full bg-brand-600 hover:bg-brand-700 text-white font-bold py-3 rounded-xl shadow-lg transition-transform active:scale-95 mt-4 flex justify-center items-center ${loading ? 'opacity-70 cursor-not-allowed' : ''}`}
          >
            {loading ? <div className="w-5 h-5 border-2 border-white border-t-transparent rounded-full animate-spin"></div> : (isLogin ? 'Se connecter' : "S'inscrire")}
          </button>
        </form>

        <div className="bg-gray-50 p-4 text-center border-t">
          <button 
            type="button"
            onClick={() => setIsLogin(!isLogin)}
            className="text-sm text-brand-600 font-bold hover:underline"
          >
            {isLogin ? "Pas de compte ? S'inscrire" : "Déjà inscrit ? Se connecter"}
          </button>
        </div>
      </div>
    </div>
  );
};

