          <h2 className="text-2xl font-bold text-gray-800 mb-2">Vérifiez vos emails</h2>
          <p className="text-gray-600 mb-6">
            Un lien de confirmation a été envoyé à <strong>{email}</strong>. 
            Veuillez cliquer dessus pour activer votre compte.
          </p>
          <div className="bg-blue-50 p-4 rounded-lg text-sm text-blue-800 mb-6">
            <p className="mb-2"><strong>Important :</strong> Si vous avez déjà cliqué et que cela ne fonctionne pas, essayez de vous connecter ou demandez un nouveau lien.</p>
          </div>

          <div className="space-y-3">
             <button 
                onClick={() => {
                setNeedsConfirmation(false);
                setIsLogin(true);
                }}
                className="w-full bg-brand-600 hover:bg-brand-700 text-white font-bold py-3 rounded-xl shadow-lg transition-transform active:scale-95"
            >
                Retour à la connexion
            </button>

            <button 
                onClick={handleResendEmail}
                disabled={resendCooldown > 0 || loading}
                className="w-full bg-white border-2 border-brand-100 text-brand-600 font-bold py-3 rounded-xl hover:bg-brand-50 transition-colors flex items-center justify-center"
            >
               {loading ? 'Envoi...' : (resendCooldown > 0 ? `Attendre ${resendCooldown}s` : "Renvoyer l'email")}
            </button>
          </div>

        </div>
      </div>
    );
  }

  return (
