            {isLogin ? 'Connexion' : 'Créer un compte'} {role === 'business' ? 'Partenaire' : ''}
          </h2>

          {error && (
            <div className="bg-red-50 text-red-600 p-3 rounded-lg text-sm animate-pulse flex flex-col">
              <div className="flex items-center mb-1">
                 <AlertCircle size={16} className="mr-2 flex-shrink-0" />
                 <span>{error}</span>
              </div>
              {error.includes("confirmé") && (
                  <button 
                    type="button"
                    onClick={handleResendEmail}
                    className="mt-2 text-xs font-bold underline text-red-700 hover:text-red-900 self-start"
                  >
                     {resendCooldown > 0 ? `Patientez ${resendCooldown}s` : "Me renvoyer l'email de confirmation"}
                  </button>
              )}
            </div>
          )}

          {!isLogin && (
            <div>
              <label className="block text-xs font-bold text-gray-600 mb-1">Votre Nom</label>
