  const [role, setRole] = useState<UserRole>('client');
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  // Form States
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [name, setName] = useState('');
  const [city, setCity] = useState('Kinshasa');
  const [availableCities, setAvailableCities] = useState<string[]>(CITIES_RDC);

  // Business Specific States
  const [businessType, setBusinessType] = useState<BusinessType>('restaurant');
  const [businessName, setBusinessName] = useState('');

  // Fetch cities from DB on mount
  useEffect(() => {
    const fetchCities = async () => {
      try {
        const { data, error } = await supabase
          .from('cities')
          .select('name')
          .eq('is_active', true)
          .order('name');

        if (!error && data && data.length > 0) {
          setAvailableCities(data.map(c => c.name));
        }
      } catch (err) {
        console.warn("Could not fetch cities from DB, using defaults");
      }
    };
    fetchCities();
  }, []);

  const handleOAuthLogin = async (provider: 'google' | 'facebook') => {
    setLoading(true);
    setError(null);
    try {
      const { error } = await supabase.auth.signInWithOAuth({
        provider: provider,
        options: {
          redirectTo: window.location.origin,
          queryParams: {
            // On passe ces infos, mais elles ne seront stockées que si on utilise un trigger côté DB
            // L'App.tsx gérera la création du profil par défaut (Client) si nécessaire
            access_type: 'offline',
            prompt: 'consent',
          }
        }
      });
      if (error) throw error;
      // La redirection se fait automatiquement ici
    } catch (err: any) {
      console.error("OAuth Error:", err);
      setError(err.message || "Erreur de connexion sociale");
      setLoading(false);
    }
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (loading) return;

    setLoading(true);
    setError(null);

    try {
      if (isLogin) {
        // LOGIN
        const { error } = await supabase.auth.signInWithPassword({
          email,
          password,
        });
        if (error) throw error;
      } else {
        // SIGN UP
        // Tente de s'inscrire
        const { data: authData, error: authError } = await supabase.auth.signUp({
          email,
          password,
          options: {
            data: { full_name: name, role: role, city: city }, // Metadata
          }
        });

        // GESTION INTELLIGENTE : Si l'utilisateur existe déjà, on tente de le connecter directement
        if (authError && authError.message.includes("already registered")) {
            console.log("Utilisateur existant, tentative de connexion automatique...");
            const { error: loginError } = await supabase.auth.signInWithPassword({
                email,
                password
            });
            if (loginError) {
                // Si le mot de passe est faux lors de l'auto-connexion
                if (loginError.message.includes("Invalid login")) {
                    throw new Error("Cet email existe déjà mais le mot de passe est incorrect.");
                }
                throw loginError;
            }
            // Si connexion réussie, on s'arrête là, le listener dans App.tsx fera le reste
            return;
        }

        if (authError) throw authError;

        // Création du profil si nouvelle inscription réussie
        if (authData.user) {
          // 1. Create Profile in DB
          const { error: profileError } = await supabase.from('profiles').insert({
            id: authData.user.id,
            role: role,
            full_name: name,
            city: city
          });

          if (profileError) {
             // Ignore duplicate key error (race condition handled in App.tsx)
             if (!profileError.message.includes('duplicate key')) {
                console.warn("Profile creation warning:", profileError);
             }
          }

          // 2. If Business, Create Restaurant
          if (role === 'business') {
            const { error: restoError } = await supabase.from('restaurants').insert({
              owner_id: authData.user.id,
              name: businessName,
              type: businessType,
              city: city, 
              latitude: -4.301 + (Math.random() - 0.5) * 0.02, 
              longitude: 15.301 + (Math.random() - 0.5) * 0.02,
              description: `Bienvenue chez ${businessName}`,
              cover_image: `https://picsum.photos/800/600?random=${Date.now()}`,
              preparation_time: 30,
              estimated_delivery_time: 30
            });
            if (restoError) console.warn("Restaurant creation warning:", restoError);
          }
        }
      }
    } catch (err: any) {
      console.error("Auth Error:", err);
      let message = err.message || "Une erreur est survenue";
      const lowerMsg = message.toLowerCase();

      // Traduction et adoucissement des erreurs
      if (lowerMsg.includes("rate limit") || lowerMsg.includes("too many requests")) {
        message = "Veuillez patienter quelques secondes avant de réessayer.";
      } else if (lowerMsg.includes("invalid login credentials")) {
        message = "Email ou mot de passe incorrect.";
      } else if (lowerMsg.includes("password should be at least")) {
        message = "Le mot de passe doit contenir au moins 6 caractères.";
      }

      setError(message);

      // Si c'est une erreur de rate limit, on enlève le loading après un délai pour laisser l'utilisateur réessayer calmement
      if (lowerMsg.includes("rate limit")) {
          setTimeout(() => setLoading(false), 2000);
      } else {
          setLoading(false);
      }
    }
  };

  return (
    <div className="min-h-screen bg-brand-50 flex flex-col items-center justify-center p-4">
      <div className="bg-white w-full max-w-md rounded-2xl shadow-xl overflow-hidden">

        {/* Header */}
        <div className="bg-brand-600 p-6 text-center">
          <h1 className="text-3xl font-black text-white tracking-tight">DashMeals<span className="text-brand-200 text-xs font-normal ml-1">RDC</span></h1>
          <p className="text-brand-100 mt-2">La plateforme gourmande de Kinshasa</p>
        </div>

        {/* Tabs */}
        <div className="flex border-b">
          <button 
            type="button"
            onClick={() => setRole('client')}
            className={`flex-1 py-4 text-sm font-bold flex items-center justify-center ${role === 'client' ? 'text-brand-600 border-b-2 border-brand-600 bg-brand-50' : 'text-gray-500'}`}
          >
            <UserIcon size={18} className="mr-2" />
            Client
          </button>
          <button 
            type="button"
            onClick={() => setRole('business')}
            className={`flex-1 py-4 text-sm font-bold flex items-center justify-center ${role === 'business' ? 'text-brand-600 border-b-2 border-brand-600 bg-brand-50' : 'text-gray-500'}`}
          >
            <Store size={18} className="mr-2" />
            Entreprise
          </button>
        </div>

        <div className="p-6 pb-2">
            <h2 className="text-xl font-bold text-gray-800 text-center mb-6">
                {isLogin ? 'Connexion' : 'Créer un compte'} {role === 'business' ? 'Partenaire' : ''}
            </h2>

            {/* Social Login Buttons */}
            <div className="grid grid-cols-2 gap-3 mb-6">
                <button 
                    type="button"
                    onClick={() => handleOAuthLogin('google')}
                    className="flex items-center justify-center py-2.5 px-4 border border-gray-300 rounded-lg hover:bg-gray-50 transition-colors bg-white text-gray-700 font-bold text-sm"
                >
                    <svg className="h-5 w-5 mr-2" viewBox="0 0 24 24">
                        <path d="M22.56 12.25c0-.78-.07-1.53-.2-2.25H12v4.26h5.92c-.26 1.37-1.04 2.53-2.21 3.31v2.77h3.57c2.08-1.92 3.28-4.74 3.28-8.09z" fill="#4285F4"/>
                        <path d="M12 23c2.97 0 5.46-.98 7.28-2.66l-3.57-2.77c-.98.66-2.23 1.06-3.71 1.06-2.86 0-5.29-1.93-6.16-4.53H2.18v2.84C3.99 20.53 7.7 23 12 23z" fill="#34A853"/>
                        <path d="M5.84 14.09c-.22-.66-.35-1.36-.35-2.09s.13-1.43.35-2.09V7.07H2.18C1.43 8.55 1 10.22 1 12s.43 3.45 1.18 4.93l2.85-2.22.81-.62z" fill="#FBBC05"/>
                        <path d="M12 5.38c1.62 0 3.06.56 4.21 1.64l3.15-3.15C17.45 2.09 14.97 1 12 1 7.7 1 3.99 3.47 2.18 7.07l3.66 2.84c.87-2.6 3.3-4.53 6.16-4.53z" fill="#EA4335"/>
                    </svg>
                    Google
                </button>
                <button 
                    type="button"
                    onClick={() => handleOAuthLogin('facebook')}
                    className="flex items-center justify-center py-2.5 px-4 border border-gray-300 rounded-lg hover:bg-[#1877F2] hover:text-white hover:border-[#1877F2] transition-colors bg-white text-gray-700 font-bold text-sm group"
                >
                    <svg className="h-5 w-5 mr-2 fill-[#1877F2] group-hover:fill-white" viewBox="0 0 24 24">
                        <path d="M9.101 23.691v-7.98H6.627v-3.667h2.474v-1.58c0-4.085 1.848-5.978 5.858-5.978.401 0 .955.042 1.468.103a8.68 8.68 0 0 1 1.141.195v3.325a8.623 8.623 0 0 0-.653-.036c-2.148 0-2.797 1.66-2.797 3.54v1.241h4.44l-1 3.667h-3.44v7.98H9.101Z" />
                    </svg>
                    Facebook
