import React, { useState, useEffect } from 'react';
import { supabase } from './lib/supabase';
import { MOCK_RESTAURANTS } from './constants';
import { Restaurant, User, UserRole, MenuItem } from './types';
import { AuthScreen } from './components/AuthScreen';
import { CustomerView } from './components/CustomerView';
import { BusinessDashboard } from './components/BusinessDashboard';

function App() {
  const [restaurants, setRestaurants] = useState<Restaurant[]>([]);
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [loading, setLoading] = useState(true);

  // Initialisation et écoute de la session
  useEffect(() => {
    // 1. Check active session
    supabase.auth.getSession().then(({ data: { session } }) => {
      if (session?.user) {
        fetchUserProfile(session.user.id, session.user.email!, session.user.user_metadata);
      } else {
        setLoading(false);
      }
    });

    // 2. Listen for changes
    const {
      data: { subscription },
    } = supabase.auth.onAuthStateChange((_event, session) => {
      if (session?.user) {
        fetchUserProfile(session.user.id, session.user.email!, session.user.user_metadata);
      } else {
        setCurrentUser(null);
        setLoading(false);
      }
    });

    // 3. Load Restaurants
    fetchRestaurants();

    return () => subscription.unsubscribe();
  }, []);

  const fetchUserProfile = async (userId: string, email: string, metadata: any = {}) => {
    try {
      // Get Profile Role and City
      let { data: profile, error } = await supabase
        .from('profiles')
        .select('*')
        .eq('id', userId)
        .single();

      // CORRECTION: Si le profil n'existe pas (compte créé manuellement ou connexion immédiate après inscription), on le crée
      if (error || !profile) {
        console.warn("Profil introuvable. Tentative de création via métadonnées ou localStorage...", metadata);

        // RECUPERATION DU ROLE EN ATTENTE (Pour OAuth Google/Facebook)
        // On vérifie si l'utilisateur a choisi un rôle avant de cliquer sur "Se connecter avec Google"
        const pendingAuthDataStr = localStorage.getItem('dashmeals_pending_auth');
        const pendingAuthData = pendingAuthDataStr ? JSON.parse(pendingAuthDataStr) : null;

        // On nettoie le storage pour ne pas polluer les futures connexions
        if (pendingAuthData) {
            localStorage.removeItem('dashmeals_pending_auth');
        }

        // On utilise les métadonnées sauvegardées lors du signup pour déterminer le bon rôle
        const defaultProfile = {
            id: userId,
            full_name: metadata?.full_name || metadata?.name || email.split('@')[0],
            // Priorité : 1. Pending (localStorage) 2. Metadata (SignUp Email) 3. Default 'client'
            role: pendingAuthData?.role || metadata?.role || 'client', 
            city: pendingAuthData?.city || metadata?.city || 'Kinshasa'
        };

        const { error: insertError } = await supabase.from('profiles').insert(defaultProfile);

        if (insertError) {
             // Si erreur "duplicate key", c'est que le profil a été créé entre temps (race condition), on le recharge
             if (insertError.message.includes('duplicate key')) {
                 const { data: retryProfile } = await supabase.from('profiles').select('*').eq('id', userId).single();
                 if (retryProfile) profile = retryProfile;
             } else {
                 throw insertError;
             }
        } else {
             profile = defaultProfile;
        }
      }

      if (profile) {
        let businessId = undefined;
        // If business, get restaurant ID
        if (profile.role === 'business') {
          // IMPORTANT: Si c'est un nouveau business, on recharge la liste des restaurants pour voir le sien
          await fetchRestaurants();

          const { data: resto } = await supabase
            .from('restaurants')
            .select('id')
            .eq('owner_id', userId)
            .single();
          if (resto) businessId = resto.id;
        }

        setCurrentUser({
          id: userId,
          email: email,
          name: profile.full_name || 'Utilisateur',
          role: profile.role as UserRole,
          city: profile.city || 'Kinshasa',
          businessId,
        });
      }
    } catch (error) {
      console.error("Error fetching/creating profile:", error);
      // En cas d'erreur critique, on déconnecte pour éviter de bloquer l'UI
      await supabase.auth.signOut();
    } finally {
      setLoading(false);
    }
  };

  const fetchRestaurants = async () => {
    try {
      // Fetch restaurants with their menu items
      const { data, error } = await supabase
        .from('restaurants')
        .select(`
          *,
          menu_items (*)
        `);

      if (error) throw error;

      if (data) {
        // Map snake_case DB to camelCase Types
        const mappedRestaurants: Restaurant[] = data.map((r: any) => ({
          id: r.id,
          ownerId: r.owner_id,
          type: r.type,
          name: r.name,
          description: r.description,
          latitude: r.latitude,
          longitude: r.longitude,
          city: r.city || 'Kinshasa',
          isOpen: r.is_open,
          rating: r.rating,
          reviewCount: r.review_count,
          preparationTime: r.preparation_time,
          estimatedDeliveryTime: r.estimated_delivery_time || 20, // Default to 20 if null
          deliveryAvailable: r.delivery_available,
          coverImage: r.cover_image || 'https://picsum.photos/800/600?grayscale',
          menu: (r.menu_items || []).map((m: any) => ({
            id: m.id,
            name: m.name,
            description: m.description,
            price: m.price,
            image: m.image,
            category: m.category,
            isAvailable: m.is_available
          }))
        }));
        setRestaurants(mappedRestaurants);
      }
    } catch (err) {
      console.error("Error loading restaurants:", err);
      // Fallback to Mocks if DB is empty or error (optional)
      // setRestaurants(MOCK_RESTAURANTS);
    }
  };

  const handleLogout = async () => {
    await supabase.auth.signOut();
    setCurrentUser(null);
  };

  const handleUpdateRestaurant = async (updatedResto: Restaurant) => {
    // Optimistic UI Update
    setRestaurants(prev => prev.map(r => r.id === updatedResto.id ? updatedResto : r));

    // Update DB is handled in BusinessDashboard mostly, but for global refetch:
    fetchRestaurants();
  };

  if (loading) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-brand-50">
        <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-brand-600"></div>
      </div>
    );
  }

  // 1. Not Logged In -> Show Auth
  if (!currentUser) {
    return <AuthScreen onLogin={() => {}} />; // onLogin logic is now handled by auth state listener
  }

  // 2. Logged in as Business -> Show Dashboard
  if (currentUser.role === 'business') {
    const myRestaurant = restaurants.find(r => r.ownerId === currentUser.id);
    // If business user but restaurant data not loaded yet or created
    if (!myRestaurant) {
         return (
             <div className="min-h-screen flex items-center justify-center flex-col p-4 text-center">
                 <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-brand-600 mb-4"></div>
                 <h2 className="text-xl font-bold mb-2">Configuration en cours...</h2>
                 <p className="text-gray-500 max-w-xs">Votre restaurant est en cours de création. Cela peut prendre quelques secondes.</p>
                 <button onClick={fetchRestaurants} className="mt-6 bg-brand-50 text-brand-600 px-4 py-2 rounded-lg font-bold text-sm">Actualiser maintenant</button>
                 <button onClick={handleLogout} className="mt-4 text-gray-400 text-sm hover:text-red-500">Se déconnecter</button>
             </div>
         )
    }

    return (
      <BusinessDashboard 
        user={currentUser} 
        restaurant={myRestaurant} 
        onUpdateRestaurant={handleUpdateRestaurant}
        onLogout={handleLogout}
      />
    );
  }

  // 3. Logged in as Client -> Show Main App
  return (
    <CustomerView 
      user={currentUser}
      allRestaurants={restaurants}
      onLogout={handleLogout}
    />
  );
}

export default App;

