import React, { useState, useEffect } from 'react';
import { supabase } from './lib/supabase';
import { MOCK_RESTAURANTS } from './constants';
import { Restaurant, User, UserRole, MenuItem } from './types';
import { AuthScreen } from './components/AuthScreen';
import { CustomerView } from './components/CustomerView';
import { BusinessDashboard } from './components/BusinessDashboard';

function App() {
  const [restaurants, setRestaurants] = useState<Restaurant[]>([]);
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [loading, setLoading] = useState(true);

  // Initialisation et écoute de la session
  useEffect(() => {
    const initSession = async () => {
        try {
            const { data: { session }, error } = await supabase.auth.getSession();
            if (error) {
                console.warn("Erreur session (Clé API invalide ?):", error.message);
                // On continue sans session pour ne pas crasher
            }
            if (session?.user) {
                await fetchUserProfile(session.user.id, session.user.email!, session.user.user_metadata);
            }
        } catch (err) {
            console.error("Erreur init:", err);
        } finally {
            setLoading(false);
        }
    };

    initSession();

    const { data: { subscription } } = supabase.auth.onAuthStateChange((_event, session) => {
      if (session?.user) {
        fetchUserProfile(session.user.id, session.user.email!, session.user.user_metadata);
      } else {
        setCurrentUser(null);
        setLoading(false);
      }
    });

    fetchRestaurants();

    return () => subscription.unsubscribe();
  }, []);

  const fetchUserProfile = async (userId: string, email: string, metadata: any = {}) => {
    try {
      // 1. Tenter de récupérer le profil depuis Supabase
      let { data: profile, error } = await supabase
        .from('profiles')
        .select('*')
        .eq('id', userId)
        .maybeSingle();

      // Si erreur 403 (Forbidden) ou autre, on log mais on ne bloque pas
      if (error) {
          console.warn("Impossible de lire le profil DB (Erreur 403/RLS) :", error.message);
      }

      // 2. Si pas de profil trouvé ou erreur, on tente de le créer ou d'utiliser un profil mémoire
      if (!profile) {
        console.log("Profil introuvable ou inaccessible. Utilisation des métadonnées...");

        // Récupération rôle temporaire (OAuth)
        const pendingAuthDataStr = localStorage.getItem('dashmeals_pending_auth');
        const pendingAuthData = pendingAuthDataStr ? JSON.parse(pendingAuthDataStr) : null;
        if (pendingAuthData) localStorage.removeItem('dashmeals_pending_auth');

        const defaultProfile = {
            id: userId,
            full_name: metadata?.full_name || metadata?.name || email.split('@')[0],
            role: pendingAuthData?.role || metadata?.role || 'client', 
            city: pendingAuthData?.city || metadata?.city || 'Kinshasa'
        };

        // Tenter l'insertion en DB
        const { error: insertError } = await supabase.from('profiles').insert(defaultProfile);

        if (insertError) {
             console.warn("Échec création profil DB (Mode hors-ligne activé):", insertError.message);
             // FALLBACK : On utilise le profil en mémoire seulement
             profile = defaultProfile;
        } else {
             profile = defaultProfile;
        }
      }

      // 3. Configuration de l'utilisateur courant
      if (profile) {
        let businessId = undefined;

        if (profile.role === 'business') {
          // Recharger les restos pour voir si le sien existe
          await fetchRestaurants();

          // Tenter de trouver son resto
          const { data: resto } = await supabase
            .from('restaurants')
            .select('id')
            .eq('owner_id', userId)
            .maybeSingle();

          if (resto) businessId = resto.id;
        }

        setCurrentUser({
          id: userId,
          email: email,
          name: profile.full_name || 'Utilisateur',
          role: profile.role as UserRole,
          city: profile.city || 'Kinshasa',
          businessId,
        });
      }
    } catch (error) {
      console.error("Erreur critique profil:", error);
    } finally {
      setLoading(false);
    }
  };

  const fetchRestaurants = async () => {
    try {
      const { data, error } = await supabase
        .from('restaurants')
        .select(`*, menu_items (*)`);

      if (error) throw error;

      if (data && data.length > 0) {
        const mappedRestaurants: Restaurant[] = data.map((r: any) => ({
          id: r.id,
          ownerId: r.owner_id,
          type: r.type,
          name: r.name,
          description: r.description,
          latitude: r.latitude,
          longitude: r.longitude,
          city: r.city || 'Kinshasa',
          isOpen: r.is_open,
          rating: r.rating,
          reviewCount: r.review_count,
          preparationTime: r.preparation_time,
          estimatedDeliveryTime: r.estimated_delivery_time || 20,
          deliveryAvailable: r.delivery_available,
          coverImage: r.cover_image || 'https://picsum.photos/800/600?grayscale',
          menu: (r.menu_items || []).map((m: any) => ({
            id: m.id,
            name: m.name,
            description: m.description,
            price: m.price,
            image: m.image,
            category: m.category,
            isAvailable: m.is_available
          }))
        }));
        setRestaurants(mappedRestaurants);
      } else {
        // Si DB vide mais connectée, on garde la liste vide (ou on pourrait remettre les mocks)
        // setRestaurants(MOCK_RESTAURANTS); 
      }
    } catch (err) {
      console.warn("Impossible de charger les restaurants (Erreur connexion/403). Utilisation des données de démo.");
      setRestaurants(MOCK_RESTAURANTS);
    }
  };

  const handleLogout = async () => {
    await supabase.auth.signOut();
    setCurrentUser(null);
  };

  const handleUpdateRestaurant = async (updatedResto: Restaurant) => {
    setRestaurants(prev => prev.map(r => r.id === updatedResto.id ? updatedResto : r));
    // Tenter une synchro DB silencieuse
    fetchRestaurants();
  };

  if (loading) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-brand-50">
        <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-brand-600"></div>
      </div>
    );
  }

  // 1. Not Logged In -> Show Auth
  if (!currentUser) {
    return <AuthScreen onLogin={() => {}} />;
  }

  // 2. Logged in as Business
  if (currentUser.role === 'business') {
    const myRestaurant = restaurants.find(r => r.ownerId === currentUser.id);

    if (!myRestaurant) {
         return (
             <div className="min-h-screen flex items-center justify-center flex-col p-4 text-center">
                 <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-brand-600 mb-4"></div>
                 <h2 className="text-xl font-bold mb-2">Configuration en cours...</h2>
                 <p className="text-gray-500 max-w-xs mb-4">Création de votre espace restaurant.</p>
                 <button onClick={fetchRestaurants} className="bg-brand-50 text-brand-600 px-4 py-2 rounded-lg font-bold text-sm">Réessayer</button>
                 <button onClick={handleLogout} className="mt-4 text-gray-400 text-sm hover:text-red-500 block mx-auto">Se déconnecter</button>
             </div>
         )
    }

    return (
      <BusinessDashboard 
        user={currentUser} 
        restaurant={myRestaurant} 
        onUpdateRestaurant={handleUpdateRestaurant}
        onLogout={handleLogout}
      />
    );
  }

  // 3. Logged in as Client
  return (
    <CustomerView 
      user={currentUser}
      allRestaurants={restaurants}
      onLogout={handleLogout}
    />
  );
}

export default App;

