import { KINSHASA_CENTER_LAT, KINSHASA_CENTER_LNG, CITIES_RDC } from '../constants';
import { Restaurant, UserState, ViewMode, MenuItem, CartItem, User, Order } from '../types';
import { calculateTime, getDistanceFromLatLonInKm, formatDistance, formatTime } from '../utils/geo';
import { RestaurantCard } from '../components/RestaurantCard';
import { MapView } from '../components/MapView';
import { CartDrawer } from '../components/CartDrawer';

// Speed constants
const SPEED_WALKING = 5;
const SPEED_MOTO = 30;

interface Props {
  user: User;
  allRestaurants: Restaurant[];
  onLogout: () => void;
}

export const CustomerView: React.FC<Props> = ({ user, allRestaurants, onLogout }) => {
  // State
  const [userState, setUserState] = useState<UserState>({
    location: null,
    locationError: null,
    loadingLocation: true,
  });

  const [restaurants, setRestaurants] = useState<Restaurant[]>([]);
  const [viewMode, setViewMode] = useState<ViewMode>('list');
  const [selectedRestaurant, setSelectedRestaurant] = useState<Restaurant | null>(null);
  const [cart, setCart] = useState<CartItem[]>([]);
  const [isCartOpen, setIsCartOpen] = useState(false);
  const [urgentMode, setUrgentMode] = useState(false);
  const [showSuccess, setShowSuccess] = useState(false);
  const [selectedCity, setSelectedCity] = useState<string>(user.city || 'Kinshasa');

  // Order States
  const [orders, setOrders] = useState<Order[]>([]);
  const [isCheckingOut, setIsCheckingOut] = useState(false);

  // Initial Geolocation
  useEffect(() => {
    if (!navigator.geolocation) {
      setUserState({
        location: null,
        locationError: "La géolocalisation n'est pas supportée par votre navigateur",
        loadingLocation: false
      });
      return;
    }

    navigator.geolocation.getCurrentPosition(
      (position) => {
        setUserState({
          location: {
            latitude: position.coords.latitude,
            longitude: position.coords.longitude,
          },
          locationError: null,
          loadingLocation: false
        });
      },
      (error) => {
        console.warn("Geo error:", error);
        setUserState({
            location: {
                latitude: KINSHASA_CENTER_LAT,
                longitude: KINSHASA_CENTER_LNG
            },
            locationError: "Position introuvable. Utilisation de la position par défaut (Kinshasa).",
            loadingLocation: false
        });
      },
      { enableHighAccuracy: true, timeout: 5000, maximumAge: 0 }
    );
  }, []);

  // Update Restaurants when location or database changes
  useEffect(() => {
    if (userState.location) {
      const updatedRestaurants = allRestaurants.map(r => {
        const dist = getDistanceFromLatLonInKm(
          userState.location!.latitude,
          userState.location!.longitude,
          r.latitude,
          r.longitude
        );
        return {
          ...r,
          distance: dist,
          timeWalking: calculateTime(dist, SPEED_WALKING),
          timeMoto: calculateTime(dist, SPEED_MOTO),
        };
      }).sort((a, b) => (a.distance || 0) - (b.distance || 0));

      setRestaurants(updatedRestaurants);
    } else {
      setRestaurants(allRestaurants);
    }
  }, [userState.location, allRestaurants]);

  // Load Orders when entering 'orders' view
  useEffect(() => {
    if (viewMode === 'orders') {
        fetchOrders();
    }
  }, [viewMode]);

  const fetchOrders = async () => {
    try {
        const { data, error } = await supabase
            .from('orders')
            .select(`
                *,
                restaurant:restaurants(name)
            `)
            .eq('user_id', user.id)
            .order('created_at', { ascending: false });

        if (error) {
             // Si erreur 403, on utilise les commandes en mémoire locale si possible ou on laisse vide
             console.warn("Erreur chargement commandes (403):", error.message);
             // On pourrait charger depuis localStorage ici pour simuler
             const localOrders = localStorage.getItem('dashmeals_mock_orders');
             if (localOrders) {
                 setOrders(JSON.parse(localOrders));
             }
             return;
        }

        if (data) {
            setOrders(data.map((o: any) => ({
                id: o.id,
                userId: o.user_id,
                restaurantId: o.restaurant_id,
                status: o.status,
                totalAmount: o.total_amount,
                items: o.items,
                createdAt: o.created_at,
                restaurant: o.restaurant
            })));
        }
    } catch (err) {
        console.error("Error fetching orders:", err);
    }
  };

  // Filter Logic (City + Urgent)
  const filteredRestaurants = useMemo(() => {
    let list = restaurants;

    // Filter by City
    if (selectedCity && selectedCity !== 'Toutes') {
      list = list.filter(r => r.city === selectedCity);
    }

    // Filter by Urgent Mode
    if (urgentMode) {
      list = list.filter(r => r.isOpen && r.preparationTime <= 20);
    }

    return list;
  }, [restaurants, urgentMode, selectedCity]);

  // Cart Logic
  const addToCart = (item: MenuItem, restaurant: Restaurant) => {
    // If cart has items from another restaurant, confirm clear
    if (cart.length > 0 && cart[0].restaurantId !== restaurant.id) {
        if(!window.confirm("Vous ne pouvez commander que dans un restaurant à la fois. Vider le panier actuel ?")) {
            return;
        }
        setCart([]);
    }

    setCart(prev => {
        const existing = prev.find(i => i.id === item.id);
        if (existing) {
             return prev.map(i => i.id === item.id ? { ...i, quantity: i.quantity + 1 } : i);
        }
        return [...prev, { ...item, quantity: 1, restaurantId: restaurant.id, restaurantName: restaurant.name }];
    });
  };

  const removeFromCart = (itemId: string) => {
    setCart(prev => {
        const index = prev.findIndex(i => i.id === itemId);
        if (index > -1) {
            const newArr = [...prev];
            newArr.splice(index, 1);
            return newArr;
        }
        return prev;
    });
  };

  const cartTotal = cart.reduce((sum, item) => sum + (item.price * item.quantity), 0);

  const handleCheckout = async () => {
    if (cart.length === 0) return;
    setIsCheckingOut(true);

    const newOrder: Order = {
        id: `mock-${Date.now()}`,
        userId: user.id,
        restaurantId: cart[0].restaurantId,
        status: 'pending',
        totalAmount: cartTotal,
        items: cart,
        createdAt: new Date().toISOString(),
        restaurant: { name: cart[0].restaurantName }
    };

    try {
        const restaurantId = cart[0].restaurantId;

        const { error } = await supabase
            .from('orders')
            .insert({
                user_id: user.id,
                restaurant_id: restaurantId,
                status: 'pending',
                total_amount: cartTotal,
                items: cart
            });

        if (error) {
            console.warn("Commande DB échouée (403), passage en simulation:", error.message);
            // Sauvegarde locale pour simulation
            const existingMockOrders = JSON.parse(localStorage.getItem('dashmeals_mock_orders') || '[]');
            localStorage.setItem('dashmeals_mock_orders', JSON.stringify([newOrder, ...existingMockOrders]));
            // On simule une réussite
        } else {
             // Si réussite DB, rien à faire de spécial
        }

        // Flux de réussite UI (commun DB et Simulation)
        setIsCartOpen(false);
        setShowSuccess(true);
        setCart([]);
        setTimeout(() => {
            setShowSuccess(false);
            setViewMode('orders'); // Redirect to orders view
            fetchOrders();
            // Force update orders state for mock
            setOrders(prev => [newOrder, ...prev]);
        }, 3000);

    } catch (err) {
        console.error("Checkout error:", err);
        // Même en cas d'exception grave, on essaie de sauver l'expérience utilisateur
        setIsCartOpen(false);
        setShowSuccess(true);
        setTimeout(() => {
            setShowSuccess(false);
            setViewMode('orders');
            setOrders(prev => [newOrder, ...prev]);
        }, 3000);
    } finally {
        setIsCheckingOut(false);
    }
  };

  const getStatusColor = (status: string) => {
    switch (status) {
        case 'pending': return 'bg-gray-100 text-gray-700';
        case 'preparing': return 'bg-yellow-100 text-yellow-800';
        case 'ready': return 'bg-blue-100 text-blue-800';
        case 'delivering': return 'bg-orange-100 text-orange-800';
        case 'completed': return 'bg-green-100 text-green-800';
        case 'cancelled': return 'bg-red-100 text-red-800';
        default: return 'bg-gray-100';
    }
  };

  const getStatusLabel = (status: string) => {
    switch (status) {
        case 'pending': return 'En attente';
        case 'preparing': return 'En cuisine';
        case 'ready': return 'Prêt';
        case 'delivering': return 'En livraison';
        case 'completed': return 'Livré';
        case 'cancelled': return 'Annulé';
        default: return status;
    }
  };

  const getProgressWidth = (status: string) => {
    switch(status) {
      case 'pending': return '10%';
      case 'preparing': return '35%';
      case 'ready': return '60%';
      case 'delivering': return '80%';
      case 'completed': return '100%';
      default: return '0%';
    }
  };

  // Views
  if (userState.loadingLocation) {
    return (
      <div className="min-h-screen flex flex-col items-center justify-center bg-brand-50">
        <div className="w-16 h-16 border-4 border-brand-500 border-t-transparent rounded-full animate-spin"></div>
        <p className="mt-4 text-brand-800 font-medium">Localisation en cours...</p>
      </div>
    );
  }

  return (
    <div className="min-h-screen pb-20 max-w-md mx-auto bg-gray-50 shadow-2xl overflow-hidden relative">

      {/* SUCCESS OVERLAY */}
      {showSuccess && (
        <div className="absolute inset-0 z-[60] bg-brand-500 flex flex-col items-center justify-center text-white p-6 text-center animate-fade-in">
           <div className="w-20 h-20 bg-white rounded-full flex items-center justify-center mb-6 shadow-xl">
              <ShoppingBag className="text-brand-500" size={40} />
           </div>
           <h2 className="text-3xl font-bold mb-2">Commande Reçue !</h2>
           <p className="text-brand-100">Votre repas est en préparation.</p>
           <div className="mt-8 bg-white/20 p-4 rounded-xl backdrop-blur-sm">
             <p className="font-mono text-sm">Vous pouvez suivre le statut dans "Commandes"</p>
           </div>
        </div>
      )}

      {/* HEADER */}
      <header className="bg-white sticky top-0 z-30 px-4 py-3 shadow-sm border-b border-gray-100">
        <div className="flex justify-between items-center mb-2">
            <div className="flex items-center">
                <h1 className="text-xl font-black text-brand-600 tracking-tight mr-2">DashMeals</h1>
                <span className="text-xs bg-brand-100 text-brand-800 px-2 py-0.5 rounded-full font-bold">Client</span>
            </div>
          <div className="flex items-center space-x-2">
            <button onClick={() => setIsCartOpen(true)} className="relative p-2 bg-gray-100 rounded-full hover:bg-gray-200 transition-colors">
                <ShoppingBag size={20} className="text-gray-700" />
                {cart.length > 0 && (
                <span className="absolute top-0 right-0 bg-red-500 text-white text-[10px] font-bold h-4 w-4 flex items-center justify-center rounded-full border-2 border-white">
                    {cart.length}
                </span>
                )}
            </button>
            <button onClick={onLogout} className="p-2 text-gray-400 hover:text-red-500">
                <LogOut size={20} />
            </button>
          </div>
        </div>

        {/* Location & City Filter - Only show in list/map mode */}
        {(viewMode === 'list' || viewMode === 'map') && (
            <div className="flex items-center space-x-2">
                <div className="flex-1 flex items-center text-sm text-gray-500 bg-gray-50 p-2 rounded-lg truncate">
                <MapPin size={14} className="mr-1.5 text-brand-500 flex-shrink-0" />
                <span className="truncate">
                    {userState.locationError ? "Mode Démo" : "Ma Position"}
                </span>
                </div>

                <select 
                className="bg-brand-50 text-brand-700 text-xs font-bold py-2 pl-2 pr-6 rounded-lg border border-brand-200 outline-none appearance-none bg-[url('data:image/svg+xml;charset=US-ASCII,%3Csvg%20xmlns%3D%22http%3A%2F%2Fwww.w3.org%2F2000%2Fsvg%22%20width%3D%22292.4%22%20height%3D%22292.4%22%3E%3Cpath%20fill%3D%22%23ea580c%22%20d%3D%22M287%2069.4a17.6%2017.6%200%200%200-13-5.4H18.4c-5%200-9.3%201.8-12.9%205.4A17.6%2017.6%200%200%200%200%2082.2c0%205%201.8%209.3%205.4%2012.9l128%20127.9c3.6%203.6%207.8%205.4%2012.8%205.4s9.2-1.8%2012.8-5.4L287%2095c3.5-3.5%205.4-7.8%205.4-12.8%200-5-1.9-9.2-5.5-12.8z%22%2F%3E%3C%2Fsvg%3E')] bg-[length:10px] bg-[right_8px_center] bg-no-repeat"
                value={selectedCity}
                onChange={(e) => setSelectedCity(e.target.value)}
                >
                <option value="Toutes">Toutes les villes</option>
                {CITIES_RDC.map(city => (
                    <option key={city} value={city}>{city}</option>
                ))}
                </select>
            </div>
        )}
      </header>

      {/* MAIN CONTENT AREA */}
      <main className="p-4">

        {viewMode === 'list' || viewMode === 'map' ? (
            <>
                {/* FILTERS */}
                <div className="flex space-x-3 mb-6 overflow-x-auto no-scrollbar pb-1">
                    <button 
                        onClick={() => setUrgentMode(!urgentMode)}
                        className={`flex items-center px-4 py-2 rounded-full font-bold text-sm shadow-sm transition-all border whitespace-nowrap ${urgentMode ? 'bg-red-500 text-white border-red-500 animate-pulse-fast' : 'bg-white text-gray-700 border-gray-200'}`}
                    >
                        <Zap size={16} className={`mr-1 ${urgentMode ? 'fill-white' : 'fill-none'}`} />
                        Urgent - J'ai faim !
                    </button>
                    <button className="px-4 py-2 rounded-full bg-white border border-gray-200 text-gray-600 font-medium text-sm whitespace-nowrap shadow-sm">
                        🍖 Grillades
                    </button>
                    <button className="px-4 py-2 rounded-full bg-white border border-gray-200 text-gray-600 font-medium text-sm whitespace-nowrap shadow-sm">
                        🍗 Poulet
                    </button>
                </div>

                {/* CONTENT */}
                {viewMode === 'list' ? (
                    <div className="space-y-4">
                        {filteredRestaurants.map(restaurant => (
                            <RestaurantCard 
                                key={restaurant.id} 
                                restaurant={restaurant} 
                                onClick={() => {
                                    setSelectedRestaurant(restaurant);
                                    setViewMode('restaurant_detail');
                                }} 
                            />
                        ))}
                        {filteredRestaurants.length === 0 && (
                            <div className="text-center py-10 text-gray-500">
                                <p>Aucun restaurant trouvé à <strong>{selectedCity}</strong> :(</p>
                                {urgentMode && <button onClick={() => setUrgentMode(false)} className="text-brand-500 underline mt-2">Désactiver le mode urgent</button>}
                            </div>
                        )}
                    </div>
                ) : (
                    <MapView 
                        restaurants={filteredRestaurants} 
                        userLocation={userState.location} 
                        onSelect={(r) => {
                            setSelectedRestaurant(r);
                            setViewMode('restaurant_detail');
                        }}
                    />
                )}
            </>
        ) : viewMode === 'restaurant_detail' && selectedRestaurant ? (
            <div className="animate-in slide-in-from-right duration-300">
                <button 
                    onClick={() => setViewMode('list')} 
                    className="mb-4 flex items-center text-gray-600 font-medium hover:text-brand-600"
                >
                    <ArrowLeft size={18} className="mr-1" /> Retour
                </button>

                <div className="bg-white rounded-2xl shadow-sm border border-gray-100 overflow-hidden mb-6">
                    <img src={selectedRestaurant.coverImage} className="w-full h-48 object-cover" alt="Cover" />
                    <div className="p-4">
                        <div className="flex justify-between items-start">
                           <h1 className="text-2xl font-bold text-gray-900">{selectedRestaurant.name}</h1>
                           <span className="text-xs bg-gray-100 text-gray-600 px-2 py-1 rounded-lg">{selectedRestaurant.city}</span>
                        </div>
                        <p className="text-gray-500 mb-4">{selectedRestaurant.description}</p>

                        {/* Primary Stats */}
                        <div className="flex items-center space-x-4 text-sm text-gray-600 mb-4">
                            <span className="flex items-center bg-gray-100 px-2 py-1 rounded"><Navigation size={14} className="mr-1"/> {formatDistance(selectedRestaurant.distance || 0)}</span>
                            <span className="flex items-center bg-gray-100 px-2 py-1 rounded"><Zap size={14} className="mr-1 text-yellow-500"/> {selectedRestaurant.preparationTime} min</span>
                        </div>

                        {/* Travel Times with Icons */}
                        <div className="grid grid-cols-2 gap-3 mb-2">
                             <div className="flex items-center p-3 bg-orange-50 rounded-lg text-orange-700 border border-orange-100">
                                <Bike size={20} className="mr-3" />
                                <div>
                                    <p className="text-[10px] font-bold uppercase tracking-wider opacity-70">En Moto</p>
                                    <p className="font-bold text-lg leading-none">{selectedRestaurant.timeMoto ? formatTime(selectedRestaurant.timeMoto) : '--'}</p>
                                </div>
                            </div>
                            <div className="flex items-center p-3 bg-blue-50 rounded-lg text-blue-700 border border-blue-100">
                                <Footprints size={20} className="mr-3" />
                                <div>
                                     <p className="text-[10px] font-bold uppercase tracking-wider opacity-70">À pied</p>
                                     <p className="font-bold text-lg leading-none">{selectedRestaurant.timeWalking ? formatTime(selectedRestaurant.timeWalking) : '--'}</p>
                                </div>
                            </div>
                        </div>

                    </div>
                </div>

                <h3 className="text-lg font-bold mb-3">Menu</h3>
                <div className="space-y-3">
                    {selectedRestaurant.menu.map(item => (
                        <div key={item.id} className="bg-white p-3 rounded-xl border border-gray-100 shadow-sm flex space-x-3">
                            <img src={item.image} className="w-20 h-20 rounded-lg object-cover bg-gray-100" alt={item.name} />
                            <div className="flex-1 flex flex-col justify-between">
                                <div>
                                    <h4 className="font-bold text-gray-800">{item.name}</h4>
                                    <p className="text-xs text-gray-500 line-clamp-1">{item.description}</p>
                                </div>
                                <div className="flex justify-between items-end mt-2">
                                    <span className="font-bold text-brand-600">${item.price.toFixed(2)}</span>
                                    <button 
                                        onClick={() => addToCart(item, selectedRestaurant)}
                                        className="bg-brand-50 text-brand-600 p-2 rounded-full hover:bg-brand-100 transition-colors"
                                    >
                                        <Plus size={16} />
                                    </button>
                                </div>
                            </div>
                        </div>
                    ))}
                </div>
            </div>
        ) : viewMode === 'orders' ? (
            <div className="animate-in slide-in-from-right duration-300">
                <h2 className="text-xl font-black text-gray-800 mb-4 flex items-center">
                    <Receipt className="mr-2 text-brand-600"/> Historique
                </h2>

                {orders.length === 0 ? (
                    <div className="text-center text-gray-400 py-10">
                        <ShoppingBag size={48} className="mx-auto mb-2 opacity-20"/>
                        <p>Aucune commande effectuée.</p>
                        <button onClick={() => setViewMode('list')} className="mt-4 text-brand-600 font-bold underline">Commander un plat</button>
                    </div>
                ) : (
                    <div className="space-y-4">
                        {orders.map(order => {
                           const isCompleted = order.status === 'completed';
                           const isCancelled = order.status === 'cancelled';
                           return (
                            <div key={order.id} className="bg-white rounded-xl shadow-sm border border-gray-100 p-4">
                                <div className="flex justify-between items-start mb-2">
                                    <div>
                                        <h3 className="font-bold text-gray-800">{order.restaurant?.name || 'Restaurant inconnu'}</h3>
                                        <p className="text-[10px] text-gray-400">
                                            {new Date(order.createdAt).toLocaleDateString('fr-FR', { day: 'numeric', month: 'short', hour: '2-digit', minute: '2-digit'})}
                                        </p>
                                    </div>
                                    <span className={`text-[10px] font-bold px-2 py-1 rounded-full uppercase tracking-wide ${getStatusColor(order.status)}`}>
                                        {getStatusLabel(order.status)}
                                    </span>
                                </div>

                                {/* Progress Bar for Active Orders */}
                                {!isCompleted && !isCancelled && (
                                    <div className="mb-4 mt-2">
                                        <div className="h-1.5 w-full bg-gray-100 rounded-full overflow-hidden">
                                            <div 
                                                className="h-full bg-brand-500 transition-all duration-1000 ease-out"
                                                style={{ width: getProgressWidth(order.status) }}
                                            ></div>
                                        </div>
                                        <div className="flex justify-between text-[10px] text-gray-400 mt-1 font-medium">
                                            <span>Reçu</span>
                                            <span>Préparation</span>
                                            <span>Livraison</span>
                                        </div>
                                    </div>
                                )}

                                <div className="space-y-1 mb-3 bg-gray-50 p-2 rounded-lg">
                                    {order.items.map((item, idx) => (
                                        <div key={idx} className="flex justify-between text-sm text-gray-700">
                                            <span>{item.quantity}x {item.name}</span>
                                            <span className="font-medium">${(item.price * item.quantity).toFixed(2)}</span>
                                        </div>
                                    ))}
                                </div>
                                <div className="flex justify-between items-center pt-2 border-t border-gray-100">
                                    <span className="text-sm font-bold text-gray-500">Total</span>
                                    <span className="text-lg font-black text-brand-600">${order.totalAmount.toFixed(2)}</span>
                                </div>
                            </div>
                           );
                        })}
                    </div>
                )}
            </div>
        ) : null}
      </main>

      {/* BOTTOM NAV */}
      <nav className="fixed bottom-0 left-0 right-0 bg-white border-t border-gray-200 px-6 py-3 flex justify-around items-center z-40 max-w-md mx-auto">
        <button 
            onClick={() => setViewMode('list')} 
            className={`flex flex-col items-center space-y-1 ${viewMode === 'list' || viewMode === 'restaurant_detail' ? 'text-brand-600' : 'text-gray-400'}`}
        >
            <List size={22} />
            <span className="text-[10px] font-medium">Liste</span>
        </button>

        {/* Urgent Button Floating */}
        <div className="relative -top-6">
            <button 
                onClick={() => setUrgentMode(!urgentMode)}
                className={`w-14 h-14 rounded-full flex items-center justify-center shadow-lg border-4 border-gray-50 transition-all ${urgentMode ? 'bg-red-500 text-white scale-110' : 'bg-brand-500 text-white'}`}
            >
                <Zap size={24} className={urgentMode ? 'animate-pulse' : ''} />
            </button>
        </div>

        <button 
            onClick={() => setViewMode('map')} 
            className={`flex flex-col items-center space-y-1 ${viewMode === 'map' ? 'text-brand-600' : 'text-gray-400'}`}
        >
            <Map size={22} />
            <span className="text-[10px] font-medium">Carte</span>
        </button>

        <button 
            onClick={() => setViewMode('orders')} 
            className={`flex flex-col items-center space-y-1 ${viewMode === 'orders' ? 'text-brand-600' : 'text-gray-400'}`}
        >
            <Receipt size={22} />
            <span className="text-[10px] font-medium">Commandes</span>
        </button>
      </nav>

      {/* CART DRAWER */}
      <CartDrawer 
        isOpen={isCartOpen} 
        onClose={() => setIsCartOpen(false)} 
        items={cart} 
        onRemove={removeFromCart} 
        onCheckout={handleCheckout}
        total={cartTotal}
        isLoading={isCheckingOut}
      />

    </div>
  );
};

import React, { useState, useEffect, useMemo } from 'react';
import { MapPin, ShoppingBag, List, Map, Zap, ArrowLeft, Plus, Bike, Footprints, LogOut, Navigation, Filter, Clock, Receipt, CheckCircle, ChefHat, Package, Search, X } from 'lucide-react';
import { supabase } from '../lib/supabase';
import { KINSHASA_CENTER_LAT, KINSHASA_CENTER_LNG, CITIES_RDC } from '../constants';
import { Restaurant, UserState, ViewMode, MenuItem, CartItem, User, Order } from '../types';
import { calculateTime, getDistanceFromLatLonInKm, formatDistance, formatTime } from '../utils/geo';
import { RestaurantCard } from '../components/RestaurantCard';
import { MapView } from '../components/MapView';
import { CartDrawer } from '../components/CartDrawer';

// Speed constants
const SPEED_WALKING = 5;
const SPEED_MOTO = 30;

interface Props {
  user: User;
  allRestaurants: Restaurant[];
  onLogout: () => void;
}

export const CustomerView: React.FC<Props> = ({ user, allRestaurants, onLogout }) => {
  // State
  const [userState, setUserState] = useState<UserState>({
    location: null,
    locationError: null,
    loadingLocation: true,
  });

  const [restaurants, setRestaurants] = useState<Restaurant[]>([]);
  const [viewMode, setViewMode] = useState<ViewMode>('list');
  const [selectedRestaurant, setSelectedRestaurant] = useState<Restaurant | null>(null);
  const [cart, setCart] = useState<CartItem[]>([]);
  const [isCartOpen, setIsCartOpen] = useState(false);
  const [urgentMode, setUrgentMode] = useState(false);
  const [searchQuery, setSearchQuery] = useState('');
  const [showSuccess, setShowSuccess] = useState(false);
  const [selectedCity, setSelectedCity] = useState<string>(user.city || 'Kinshasa');

  // Order States
  const [orders, setOrders] = useState<Order[]>([]);
  const [isCheckingOut, setIsCheckingOut] = useState(false);

  // Initial Geolocation
  useEffect(() => {
    if (!navigator.geolocation) {
      setUserState({
        location: null,
        locationError: "La géolocalisation n'est pas supportée par votre navigateur",
        loadingLocation: false
      });
      return;
    }

    navigator.geolocation.getCurrentPosition(
      (position) => {
        setUserState({
          location: {
            latitude: position.coords.latitude,
            longitude: position.coords.longitude,
          },
          locationError: null,
          loadingLocation: false
        });
      },
      (error) => {
        console.warn("Geo error:", error);
        setUserState({
            location: {
                latitude: KINSHASA_CENTER_LAT,
                longitude: KINSHASA_CENTER_LNG
            },
            locationError: "Position introuvable. Utilisation de la position par défaut (Kinshasa).",
            loadingLocation: false
        });
      },
      { enableHighAccuracy: true, timeout: 5000, maximumAge: 0 }
    );
  }, []);

  // Update Restaurants when location or database changes
  useEffect(() => {
    if (userState.location) {
      const updatedRestaurants = allRestaurants.map(r => {
        const dist = getDistanceFromLatLonInKm(
          userState.location!.latitude,
          userState.location!.longitude,
          r.latitude,
          r.longitude
        );
        return {
          ...r,
          distance: dist,
          timeWalking: calculateTime(dist, SPEED_WALKING),
          timeMoto: calculateTime(dist, SPEED_MOTO),
        };
      }).sort((a, b) => (a.distance || 0) - (b.distance || 0));

      setRestaurants(updatedRestaurants);
    } else {
      setRestaurants(allRestaurants);
    }
  }, [userState.location, allRestaurants]);

  // Load Orders when entering 'orders' view
  useEffect(() => {
    if (viewMode === 'orders') {
        fetchOrders();
    }
  }, [viewMode]);

  const fetchOrders = async () => {
    try {
        const { data, error } = await supabase
            .from('orders')
            .select(`
                *,
                restaurant:restaurants(name)
            `)
            .eq('user_id', user.id)
            .order('created_at', { ascending: false });

        if (error) {
             // Si erreur 403, on utilise les commandes en mémoire locale si possible ou on laisse vide
             console.warn("Erreur chargement commandes (403):", error.message);
             // On pourrait charger depuis localStorage ici pour simuler
             const localOrders = localStorage.getItem('dashmeals_mock_orders');
             if (localOrders) {
                 setOrders(JSON.parse(localOrders));
             }
             return;
        }

        if (data) {
            setOrders(data.map((o: any) => ({
                id: o.id,
                userId: o.user_id,
                restaurantId: o.restaurant_id,
                status: o.status,
                totalAmount: o.total_amount,
                items: o.items,
                createdAt: o.created_at,
                restaurant: o.restaurant
            })));
        }
    } catch (err) {
        console.error("Error fetching orders:", err);
    }
  };

  // Filter Logic (City + Urgent + Search)
  const filteredRestaurants = useMemo(() => {
    let list = restaurants;

    // Filter by City
    if (selectedCity && selectedCity !== 'Toutes') {
      list = list.filter(r => r.city === selectedCity);
    }

    // Filter by Urgent Mode
    if (urgentMode) {
      list = list.filter(r => r.isOpen && r.preparationTime <= 20);
    }

    // Filter by Search Query
    if (searchQuery) {
        const query = searchQuery.toLowerCase();
        list = list.filter(r => 
            r.name.toLowerCase().includes(query) || 
            r.description.toLowerCase().includes(query)
        );
    }

    return list;
  }, [restaurants, urgentMode, selectedCity, searchQuery]);

  // Cart Logic
  const addToCart = (item: MenuItem, restaurant: Restaurant) => {
    // If cart has items from another restaurant, confirm clear
    if (cart.length > 0 && cart[0].restaurantId !== restaurant.id) {
        if(!window.confirm("Vous ne pouvez commander que dans un restaurant à la fois. Vider le panier actuel ?")) {
            return;
        }
        setCart([]);
    }

    setCart(prev => {
        const existing = prev.find(i => i.id === item.id);
        if (existing) {
             return prev.map(i => i.id === item.id ? { ...i, quantity: i.quantity + 1 } : i);
        }
        return [...prev, { ...item, quantity: 1, restaurantId: restaurant.id, restaurantName: restaurant.name }];
    });
  };

  const removeFromCart = (itemId: string) => {
    setCart(prev => {
        const index = prev.findIndex(i => i.id === itemId);
        if (index > -1) {
            const newArr = [...prev];
            newArr.splice(index, 1);
            return newArr;
        }
        return prev;
    });
  };

  const cartTotal = cart.reduce((sum, item) => sum + (item.price * item.quantity), 0);

  const handleCheckout = async () => {
    if (cart.length === 0) return;
    setIsCheckingOut(true);

    const newOrder: Order = {
        id: `mock-${Date.now()}`,
        userId: user.id,
        restaurantId: cart[0].restaurantId,
        status: 'pending',
        totalAmount: cartTotal,
        items: cart,
        createdAt: new Date().toISOString(),
        restaurant: { name: cart[0].restaurantName }
    };

    try {
        const restaurantId = cart[0].restaurantId;

        const { error } = await supabase
            .from('orders')
            .insert({
                user_id: user.id,
                restaurant_id: restaurantId,
                status: 'pending',
                total_amount: cartTotal,
                items: cart
            });

        if (error) {
            console.warn("Commande DB échouée (403), passage en simulation:", error.message);
            // Sauvegarde locale pour simulation
            const existingMockOrders = JSON.parse(localStorage.getItem('dashmeals_mock_orders') || '[]');
            localStorage.setItem('dashmeals_mock_orders', JSON.stringify([newOrder, ...existingMockOrders]));
            // On simule une réussite
        } else {
             // Si réussite DB, rien à faire de spécial
        }

        // Flux de réussite UI (commun DB et Simulation)
        setIsCartOpen(false);
        setShowSuccess(true);
        setCart([]);
        setTimeout(() => {
            setShowSuccess(false);
            setViewMode('orders'); // Redirect to orders view
            fetchOrders();
            // Force update orders state for mock
            setOrders(prev => [newOrder, ...prev]);
        }, 3000);

    } catch (err) {
        console.error("Checkout error:", err);
        // Même en cas d'exception grave, on essaie de sauver l'expérience utilisateur
        setIsCartOpen(false);
        setShowSuccess(true);
        setTimeout(() => {
            setShowSuccess(false);
            setViewMode('orders');
            setOrders(prev => [newOrder, ...prev]);
        }, 3000);
    } finally {
        setIsCheckingOut(false);
    }
  };

  const getStatusColor = (status: string) => {
    switch (status) {
        case 'pending': return 'bg-gray-100 text-gray-700';
        case 'preparing': return 'bg-yellow-100 text-yellow-800';
        case 'ready': return 'bg-blue-100 text-blue-800';
        case 'delivering': return 'bg-orange-100 text-orange-800';
        case 'completed': return 'bg-green-100 text-green-800';
        case 'cancelled': return 'bg-red-100 text-red-800';
        default: return 'bg-gray-100';
    }
  };

  const getStatusLabel = (status: string) => {
    switch (status) {
        case 'pending': return 'En attente';
        case 'preparing': return 'En cuisine';
        case 'ready': return 'Prêt';
        case 'delivering': return 'En livraison';
        case 'completed': return 'Livré';
        case 'cancelled': return 'Annulé';
        default: return status;
    }
  };

  const getProgressWidth = (status: string) => {
    switch(status) {
      case 'pending': return '10%';
      case 'preparing': return '35%';
      case 'ready': return '60%';
      case 'delivering': return '80%';
      case 'completed': return '100%';
      default: return '0%';
    }
  };

  // Views
  if (userState.loadingLocation) {
    return (
      <div className="min-h-screen flex flex-col items-center justify-center bg-brand-50">
        <div className="w-16 h-16 border-4 border-brand-500 border-t-transparent rounded-full animate-spin"></div>
        <p className="mt-4 text-brand-800 font-medium">Localisation en cours...</p>
      </div>
    );
  }

  return (
    <div className="min-h-screen pb-20 max-w-md mx-auto bg-gray-50 shadow-2xl overflow-hidden relative">

      {/* SUCCESS OVERLAY */}
      {showSuccess && (
        <div className="absolute inset-0 z-[60] bg-brand-500 flex flex-col items-center justify-center text-white p-6 text-center animate-fade-in">
           <div className="w-20 h-20 bg-white rounded-full flex items-center justify-center mb-6 shadow-xl">
              <ShoppingBag className="text-brand-500" size={40} />
           </div>
           <h2 className="text-3xl font-bold mb-2">Commande Reçue !</h2>
           <p className="text-brand-100">Votre repas est en préparation.</p>
           <div className="mt-8 bg-white/20 p-4 rounded-xl backdrop-blur-sm">
             <p className="font-mono text-sm">Vous pouvez suivre le statut dans "Commandes"</p>
           </div>
        </div>
      )}

      {/* HEADER */}
      <header className="bg-white sticky top-0 z-30 px-4 py-3 shadow-sm border-b border-gray-100">
        <div className="flex justify-between items-center mb-2">
            <div className="flex items-center">
                <h1 className="text-xl font-black text-brand-600 tracking-tight mr-2">DashMeals</h1>
                <span className="text-xs bg-brand-100 text-brand-800 px-2 py-0.5 rounded-full font-bold">Client</span>
            </div>
          <div className="flex items-center space-x-2">
            <button onClick={() => setIsCartOpen(true)} className="relative p-2 bg-gray-100 rounded-full hover:bg-gray-200 transition-colors">
                <ShoppingBag size={20} className="text-gray-700" />
                {cart.length > 0 && (
                <span className="absolute top-0 right-0 bg-red-500 text-white text-[10px] font-bold h-4 w-4 flex items-center justify-center rounded-full border-2 border-white">
                    {cart.length}
                </span>
                )}
            </button>
            <button onClick={onLogout} className="p-2 text-gray-400 hover:text-red-500">
                <LogOut size={20} />
            </button>
          </div>
        </div>

        {/* Location & City Filter - Only show in list/map mode */}
        {(viewMode === 'list' || viewMode === 'map') && (
            <div className="flex items-center space-x-2">
                <div className="flex-1 flex items-center text-sm text-gray-500 bg-gray-50 p-2 rounded-lg truncate">
                <MapPin size={14} className="mr-1.5 text-brand-500 flex-shrink-0" />
                <span className="truncate">
                    {userState.locationError ? "Mode Démo" : "Ma Position"}
                </span>
                </div>

                <select 
                className="bg-brand-50 text-brand-700 text-xs font-bold py-2 pl-2 pr-6 rounded-lg border border-brand-200 outline-none appearance-none bg-[url('data:image/svg+xml;charset=US-ASCII,%3Csvg%20xmlns%3D%22http%3A%2F%2Fwww.w3.org%2F2000%2Fsvg%22%20width%3D%22292.4%22%20height%3D%22292.4%22%3E%3Cpath%20fill%3D%22%23ea580c%22%20d%3D%22M287%2069.4a17.6%2017.6%200%200%200-13-5.4H18.4c-5%200-9.3%201.8-12.9%205.4A17.6%2017.6%200%200%200%200%2082.2c0%205%201.8%209.3%205.4%2012.9l128%20127.9c3.6%203.6%207.8%205.4%2012.8%205.4s9.2-1.8%2012.8-5.4L287%2095c3.5-3.5%205.4-7.8%205.4-12.8%200-5-1.9-9.2-5.5-12.8z%22%2F%3E%3C%2Fsvg%3E')] bg-[length:10px] bg-[right_8px_center] bg-no-repeat"
                value={selectedCity}
                onChange={(e) => setSelectedCity(e.target.value)}
                >
                <option value="Toutes">Toutes les villes</option>
                {CITIES_RDC.map(city => (
                    <option key={city} value={city}>{city}</option>
                ))}
                </select>
            </div>
        )}
      </header>

      {/* MAIN CONTENT AREA */}
      <main className="p-4">

        {viewMode === 'list' || viewMode === 'map' ? (
            <>
                {/* SEARCH BAR */}
                <div className="mb-4 relative">
                    <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 text-gray-400" size={18} />
                    <input 
                        type="text"
                        placeholder="Rechercher un restaurant..."
                        className="w-full pl-10 pr-10 py-3 rounded-xl border border-gray-200 focus:ring-2 focus:ring-brand-500 outline-none text-sm bg-white shadow-sm"
                        value={searchQuery}
                        onChange={(e) => setSearchQuery(e.target.value)}
                    />
                    {searchQuery && (
                        <button 
                            onClick={() => setSearchQuery('')}
                            className="absolute right-3 top-1/2 transform -translate-y-1/2 text-gray-400 hover:text-gray-600 p-1"
                        >
                            <X size={16} />
                        </button>
                    )}
                </div>

                {/* FILTERS */}
                <div className="flex space-x-3 mb-6 overflow-x-auto no-scrollbar pb-1">
                    <button 
                        onClick={() => setUrgentMode(!urgentMode)}
                        className={`flex items-center px-4 py-2 rounded-full font-bold text-sm shadow-sm transition-all border whitespace-nowrap ${urgentMode ? 'bg-red-500 text-white border-red-500 animate-pulse-fast' : 'bg-white text-gray-700 border-gray-200'}`}
                    >
                        <Zap size={16} className={`mr-1 ${urgentMode ? 'fill-white' : 'fill-none'}`} />
                        Urgent - J'ai faim !
                    </button>
                    <button className="px-4 py-2 rounded-full bg-white border border-gray-200 text-gray-600 font-medium text-sm whitespace-nowrap shadow-sm">
                        🍖 Grillades
                    </button>
                    <button className="px-4 py-2 rounded-full bg-white border border-gray-200 text-gray-600 font-medium text-sm whitespace-nowrap shadow-sm">
                        🍗 Poulet
                    </button>
                </div>

                {/* CONTENT */}
                {viewMode === 'list' ? (
                    <div className="space-y-4">
                        {filteredRestaurants.map(restaurant => (
                            <RestaurantCard 
                                key={restaurant.id} 
                                restaurant={restaurant} 
                                onClick={() => {
                                    setSelectedRestaurant(restaurant);
                                    setViewMode('restaurant_detail');
                                }} 
                            />
                        ))}
                        {filteredRestaurants.length === 0 && (
                            <div className="text-center py-10 text-gray-500">
                                <p>Aucun restaurant trouvé {selectedCity !== 'Toutes' ? `à ${selectedCity}` : ''} {searchQuery ? `pour "${searchQuery}"` : ''} :(</p>
                                {urgentMode && <button onClick={() => setUrgentMode(false)} className="text-brand-500 underline mt-2">Désactiver le mode urgent</button>}
                            </div>
                        )}
                    </div>
                ) : (
                    <MapView 
                        restaurants={filteredRestaurants} 
                        userLocation={userState.location} 
                        onSelect={(r) => {
                            setSelectedRestaurant(r);
                            setViewMode('restaurant_detail');
                        }}
                    />
                )}
            </>
        ) : viewMode === 'restaurant_detail' && selectedRestaurant ? (
            <div className="animate-in slide-in-from-right duration-300">
                <button 
                    onClick={() => setViewMode('list')} 
                    className="mb-4 flex items-center text-gray-600 font-medium hover:text-brand-600"
                >
                    <ArrowLeft size={18} className="mr-1" /> Retour
                </button>

                <div className="bg-white rounded-2xl shadow-sm border border-gray-100 overflow-hidden mb-6">
                    <img src={selectedRestaurant.coverImage} className="w-full h-48 object-cover" alt="Cover" />
                    <div className="p-4">
                        <div className="flex justify-between items-start">
                           <h1 className="text-2xl font-bold text-gray-900">{selectedRestaurant.name}</h1>
                           <span className="text-xs bg-gray-100 text-gray-600 px-2 py-1 rounded-lg">{selectedRestaurant.city}</span>
                        </div>
                        <p className="text-gray-500 mb-4">{selectedRestaurant.description}</p>

                        {/* Primary Stats */}
                        <div className="flex items-center space-x-4 text-sm text-gray-600 mb-4">
                            <span className="flex items-center bg-gray-100 px-2 py-1 rounded"><Navigation size={14} className="mr-1"/> {formatDistance(selectedRestaurant.distance || 0)}</span>
                            <span className="flex items-center bg-gray-100 px-2 py-1 rounded"><Zap size={14} className="mr-1 text-yellow-500"/> {selectedRestaurant.preparationTime} min</span>
                        </div>

                        {/* Travel Times with Icons */}
                        <div className="grid grid-cols-2 gap-3 mb-2">
                             <div className="flex items-center p-3 bg-orange-50 rounded-lg text-orange-700 border border-orange-100">
                                <Bike size={20} className="mr-3" />
                                <div>
                                    <p className="text-[10px] font-bold uppercase tracking-wider opacity-70">En Moto</p>
                                    <p className="font-bold text-lg leading-none">{selectedRestaurant.timeMoto ? formatTime(selectedRestaurant.timeMoto) : '--'}</p>
                                </div>
                            </div>
                            <div className="flex items-center p-3 bg-blue-50 rounded-lg text-blue-700 border border-blue-100">
                                <Footprints size={20} className="mr-3" />
                                <div>
                                     <p className="text-[10px] font-bold uppercase tracking-wider opacity-70">À pied</p>
                                     <p className="font-bold text-lg leading-none">{selectedRestaurant.timeWalking ? formatTime(selectedRestaurant.timeWalking) : '--'}</p>
                                </div>
                            </div>
                        </div>

                    </div>
                </div>

                <h3 className="text-lg font-bold mb-3">Menu</h3>
                <div className="space-y-3">
                    {selectedRestaurant.menu.map(item => (
                        <div key={item.id} className="bg-white p-3 rounded-xl border border-gray-100 shadow-sm flex space-x-3">
                            <img src={item.image} className="w-20 h-20 rounded-lg object-cover bg-gray-100" alt={item.name} />
                            <div className="flex-1 flex flex-col justify-between">
                                <div>
                                    <h4 className="font-bold text-gray-800">{item.name}</h4>
                                    <p className="text-xs text-gray-500 line-clamp-1">{item.description}</p>
                                </div>
                                <div className="flex justify-between items-end mt-2">
                                    <span className="font-bold text-brand-600">${item.price.toFixed(2)}</span>
                                    <button 
                                        onClick={() => addToCart(item, selectedRestaurant)}
                                        className="bg-brand-50 text-brand-600 p-2 rounded-full hover:bg-brand-100 transition-colors"
                                    >
                                        <Plus size={16} />
                                    </button>
                                </div>
                            </div>
                        </div>
                    ))}
                </div>
            </div>
        ) : viewMode === 'orders' ? (
            <div className="animate-in slide-in-from-right duration-300">
                <h2 className="text-xl font-black text-gray-800 mb-4 flex items-center">
                    <Receipt className="mr-2 text-brand-600"/> Historique
                </h2>

                {orders.length === 0 ? (
                    <div className="text-center text-gray-400 py-10">
                        <ShoppingBag size={48} className="mx-auto mb-2 opacity-20"/>
                        <p>Aucune commande effectuée.</p>
                        <button onClick={() => setViewMode('list')} className="mt-4 text-brand-600 font-bold underline">Commander un plat</button>
                    </div>
                ) : (
                    <div className="space-y-4">
                        {orders.map(order => {
                           const isCompleted = order.status === 'completed';
                           const isCancelled = order.status === 'cancelled';
                           return (
                            <div key={order.id} className="bg-white rounded-xl shadow-sm border border-gray-100 p-4">
                                <div className="flex justify-between items-start mb-2">
                                    <div>
                                        <h3 className="font-bold text-gray-800">{order.restaurant?.name || 'Restaurant inconnu'}</h3>
                                        <p className="text-[10px] text-gray-400">
                                            {new Date(order.createdAt).toLocaleDateString('fr-FR', { day: 'numeric', month: 'short', hour: '2-digit', minute: '2-digit'})}
                                        </p>
                                    </div>
                                    <span className={`text-[10px] font-bold px-2 py-1 rounded-full uppercase tracking-wide ${getStatusColor(order.status)}`}>
                                        {getStatusLabel(order.status)}
                                    </span>
                                </div>

                                {/* Progress Bar for Active Orders */}
                                {!isCompleted && !isCancelled && (
                                    <div className="mb-4 mt-2">
                                        <div className="h-1.5 w-full bg-gray-100 rounded-full overflow-hidden">
                                            <div 
                                                className="h-full bg-brand-500 transition-all duration-1000 ease-out"
                                                style={{ width: getProgressWidth(order.status) }}
                                            ></div>
                                        </div>
                                        <div className="flex justify-between text-[10px] text-gray-400 mt-1 font-medium">
                                            <span>Reçu</span>
                                            <span>Préparation</span>
                                            <span>Livraison</span>
                                        </div>
                                    </div>
                                )}

                                <div className="space-y-1 mb-3 bg-gray-50 p-2 rounded-lg">
                                    {order.items.map((item, idx) => (
                                        <div key={idx} className="flex justify-between text-sm text-gray-700">
                                            <span>{item.quantity}x {item.name}</span>
                                            <span className="font-medium">${(item.price * item.quantity).toFixed(2)}</span>
                                        </div>
                                    ))}
                                </div>
                                <div className="flex justify-between items-center pt-2 border-t border-gray-100">
                                    <span className="text-sm font-bold text-gray-500">Total</span>
                                    <span className="text-lg font-black text-brand-600">${order.totalAmount.toFixed(2)}</span>
                                </div>
                            </div>
                           );
                        })}
                    </div>
                )}
            </div>
        ) : null}
      </main>

      {/* BOTTOM NAV */}
      <nav className="fixed bottom-0 left-0 right-0 bg-white border-t border-gray-200 px-6 py-3 flex justify-around items-center z-40 max-w-md mx-auto">
        <button 
            onClick={() => setViewMode('list')} 
            className={`flex flex-col items-center space-y-1 ${viewMode === 'list' || viewMode === 'restaurant_detail' ? 'text-brand-600' : 'text-gray-400'}`}
        >
            <List size={22} />
            <span className="text-[10px] font-medium">Liste</span>
        </button>

        {/* Urgent Button Floating */}
        <div className="relative -top-6">
            <button 
                onClick={() => setUrgentMode(!urgentMode)}
                className={`w-14 h-14 rounded-full flex items-center justify-center shadow-lg border-4 border-gray-50 transition-all ${urgentMode ? 'bg-red-500 text-white scale-110' : 'bg-brand-500 text-white'}`}
            >
                <Zap size={24} className={urgentMode ? 'animate-pulse' : ''} />
            </button>
        </div>

        <button 
            onClick={() => setViewMode('map')} 
            className={`flex flex-col items-center space-y-1 ${viewMode === 'map' ? 'text-brand-600' : 'text-gray-400'}`}
        >
            <Map size={22} />
            <span className="text-[10px] font-medium">Carte</span>
        </button>

        <button 
            onClick={() => setViewMode('orders')} 
            className={`flex flex-col items-center space-y-1 ${viewMode === 'orders' ? 'text-brand-600' : 'text-gray-400'}`}
        >
            <Receipt size={22} />
            <span className="text-[10px] font-medium">Commandes</span>
        </button>
      </nav>

      {/* CART DRAWER */}
      <CartDrawer 
        isOpen={isCartOpen} 
        onClose={() => setIsCartOpen(false)} 
        items={cart} 
        onRemove={removeFromCart} 
        onCheckout={handleCheckout}
        total={cartTotal}
        isLoading={isCheckingOut}
      />

    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { supabase } from './lib/supabase';
import { MOCK_RESTAURANTS } from './constants';
import { Restaurant, User, UserRole, MenuItem, BusinessType } from './types';
import { AuthScreen } from './components/AuthScreen';
import { CustomerView } from './components/CustomerView';
import { BusinessDashboard } from './components/BusinessDashboard';
import { AlertTriangle, Store, ArrowRight } from 'lucide-react';

function App() {
  const [restaurants, setRestaurants] = useState<Restaurant[]>([]);
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [loading, setLoading] = useState(true);
  const [isOfflineMode, setIsOfflineMode] = useState(false);

  // États pour la création manuelle de restaurant (Fallback)
  const [newRestoName, setNewRestoName] = useState('');
  const [newRestoType, setNewRestoType] = useState<BusinessType>('restaurant');
  const [creationLoading, setCreationLoading] = useState(false);

  // Initialisation et écoute de la session
  useEffect(() => {
    const initSession = async () => {
        try {
            const { data: { session }, error } = await supabase.auth.getSession();
            if (error) {
                console.warn("Erreur session:", error.message);
                setIsOfflineMode(true);
            }
            if (session?.user) {
                await fetchUserProfile(session.user.id, session.user.email!, session.user.user_metadata);
            }
        } catch (err) {
            console.error("Erreur init:", err);
            setIsOfflineMode(true);
        } finally {
            setLoading(false);
        }
    };

    initSession();

    const { data: { subscription } } = supabase.auth.onAuthStateChange((_event, session) => {
      if (session?.user) {
        fetchUserProfile(session.user.id, session.user.email!, session.user.user_metadata);
      } else {
        setCurrentUser(null);
        setLoading(false);
      }
    });

    fetchRestaurants();

    return () => subscription.unsubscribe();
  }, []);

  const fetchUserProfile = async (userId: string, email: string, metadata: any = {}) => {
    try {
      let { data: profile, error } = await supabase
        .from('profiles')
        .select('*')
        .eq('id', userId)
        .maybeSingle();

      if (error) {
          console.warn("Erreur lecture profil (403/Offline):", error.message);
          setIsOfflineMode(true);
      }

      // Si pas de profil ou erreur, création profil mémoire
      if (!profile) {
        console.log("Utilisation profil mémoire...");

        const pendingAuthDataStr = localStorage.getItem('dashmeals_pending_auth');
        const pendingAuthData = pendingAuthDataStr ? JSON.parse(pendingAuthDataStr) : null;
        if (pendingAuthData) localStorage.removeItem('dashmeals_pending_auth');

        const defaultProfile = {
            id: userId,
            full_name: metadata?.full_name || metadata?.name || email.split('@')[0],
            role: pendingAuthData?.role || metadata?.role || 'client', 
            city: pendingAuthData?.city || metadata?.city || 'Kinshasa'
        };

        // On tente l'insert DB mais on ne bloque pas si ça échoue (403)
        supabase.from('profiles').insert(defaultProfile).then(({ error }) => {
            if (error) {
                console.warn("Insert profil échoué, continué en mémoire");
                setIsOfflineMode(true);
            }
        });

        profile = defaultProfile;
      }

      if (profile) {
        let businessId = undefined;

        if (profile.role === 'business') {
          // Si business, on check si le resto existe
          // En mode offline/403, on ne trouvera rien, donc l'UI Business demandera de créer
          // C'est acceptable pour le mode dégradé
          const { data: resto } = await supabase
            .from('restaurants')
            .select('id')
            .eq('owner_id', userId)
            .maybeSingle();

          if (resto) businessId = resto.id;
        }

        setCurrentUser({
          id: userId,
          email: email,
          name: profile.full_name || 'Utilisateur',
          role: profile.role as UserRole,
          city: profile.city || 'Kinshasa',
          businessId,
        });
      }
    } catch (error) {
      console.error("Erreur critique profil:", error);
    } finally {
      setLoading(false);
    }
  };

  const fetchRestaurants = async () => {
    try {
      const { data, error } = await supabase
        .from('restaurants')
        .select(`*, menu_items (*)`);

      if (error) throw error;

      if (data && data.length > 0) {
        const mappedRestaurants: Restaurant[] = data.map((r: any) => ({
          id: r.id,
          ownerId: r.owner_id,
          type: r.type,
          name: r.name,
          description: r.description,
          latitude: r.latitude,
          longitude: r.longitude,
          city: r.city || 'Kinshasa',
          isOpen: r.is_open,
          rating: r.rating,
          reviewCount: r.review_count,
          preparationTime: r.preparation_time,
          estimatedDeliveryTime: r.estimated_delivery_time || 20,
          deliveryAvailable: r.delivery_available,
          coverImage: r.cover_image || 'https://picsum.photos/800/600?grayscale',
          menu: (r.menu_items || []).map((m: any) => ({
            id: m.id,
            name: m.name,
            description: m.description,
            price: m.price,
            image: m.image,
            category: m.category,
            isAvailable: m.is_available
          }))
        }));
        setRestaurants(mappedRestaurants);
        setIsOfflineMode(false); // Si ça marche, on n'est pas hors ligne
      } else {
        // DB vide ou connectée mais pas de données
        // On pourrait laisser vide, mais pour la démo on remet les Mocks si vide
        if (data && data.length === 0) {
             console.log("DB vide, chargement Mocks...");
             setRestaurants(MOCK_RESTAURANTS);
        }
      }
    } catch (err) {
      console.warn("Erreur chargement restaurants (403 probable). Utilisation des données MOCK.");
      setRestaurants(MOCK_RESTAURANTS);
      setIsOfflineMode(true);
    }
  };

  const handleLogout = async () => {
    await supabase.auth.signOut();
    setCurrentUser(null);
  };

  const handleUpdateRestaurant = async (updatedResto: Restaurant) => {
    setRestaurants(prev => prev.map(r => r.id === updatedResto.id ? updatedResto : r));
    // En mode offline, on ne refetch pas pour ne pas écraser les changements locaux avec une erreur
    if (!isOfflineMode) fetchRestaurants();
  };

  // Fonction pour forcer la création du restaurant si l'automatisme a échoué
  const handleManualRestaurantCreation = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!currentUser) return;
    setCreationLoading(true);

    const newRestaurantPayload = {
        owner_id: currentUser.id,
        name: newRestoName || "Mon Restaurant",
        type: newRestoType,
        city: currentUser.city || 'Kinshasa',
        description: `Bienvenue chez ${newRestoName}`,
        latitude: -4.325 + (Math.random() * 0.01), // Random pos near center
        longitude: 15.322 + (Math.random() * 0.01),
        is_open: true,
        preparation_time: 30,
        estimated_delivery_time: 30,
        cover_image: 'https://picsum.photos/800/600?food'
    };

    try {
        // 1. Tenter l'insertion DB
        const { data, error } = await supabase
            .from('restaurants')
            .insert(newRestaurantPayload)
            .select()
            .single();

        if (error) throw error;

        // 2. Si succès, recharger
        await fetchRestaurants();
    } catch (err: any) {
        console.warn("Erreur création DB (Mode Offline activé):", err.message);

        // 3. Fallback Mode Offline / Démo
        const mockResto: Restaurant = {
            id: `temp-${Date.now()}`,
            ownerId: currentUser.id,
            name: newRestoName || "Mon Restaurant (Mode Démo)",
            type: newRestoType,
            city: currentUser.city || 'Kinshasa',
            description: "Restaurant créé en mode démonstration.",
            latitude: -4.325,
            longitude: 15.322,
            isOpen: true,
            rating: 5.0,
            reviewCount: 0,
            preparationTime: 30,
            estimatedDeliveryTime: 30,
            deliveryAvailable: true,
            coverImage: 'https://picsum.photos/800/600?food',
            menu: []
        };

        setRestaurants(prev => [...prev, mockResto]);
        setIsOfflineMode(true);
    } finally {
        setCreationLoading(false);
    }
  };

  if (loading) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-brand-50">
        <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-brand-600"></div>
      </div>
    );
  }

  // 1. Not Logged In -> Show Auth
  if (!currentUser) {
    return <AuthScreen onLogin={() => {}} />;
  }

  // Banner component
  const OfflineBanner = () => isOfflineMode ? (
    <div className="bg-yellow-500 text-white text-xs font-bold px-4 py-1 text-center flex justify-center items-center sticky top-0 z-50">
        <AlertTriangle size={14} className="mr-2" />
        Mode Démo (Connexion Base de Données instable ou Permissions 403)
    </div>
  ) : null;

  // 2. Logged in as Business
  if (currentUser.role === 'business') {
    const myRestaurant = restaurants.find(r => r.ownerId === currentUser.id);

    // CAS CRITIQUE : L'utilisateur est Business mais n'a pas de restaurant (Echec initialisation)
    // On affiche un formulaire de rattrapage au lieu du chargement infini
    if (!myRestaurant) {
         return (
             <div className="min-h-screen bg-gray-50 flex flex-col items-center justify-center p-4">
                 <OfflineBanner />

                 <div className="bg-white max-w-md w-full rounded-2xl shadow-xl p-8 text-center animate-in fade-in zoom-in duration-300">
                     <div className="w-16 h-16 bg-brand-100 text-brand-600 rounded-full flex items-center justify-center mx-auto mb-4">
                        <Store size={32} />
                     </div>

                     <h2 className="text-2xl font-black text-gray-800 mb-2">Finalisation</h2>
                     <p className="text-gray-500 mb-6">Nous devons configurer votre établissement pour continuer.</p>

                     <form onSubmit={handleManualRestaurantCreation} className="space-y-4 text-left">
                        <div>
                            <label className="block text-xs font-bold text-gray-600 mb-1">Nom du restaurant</label>
                            <input 
                                type="text"
                                required
                                className="w-full p-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-brand-500 outline-none"
                                placeholder="Ex: Chez Maman..."
                                value={newRestoName}
                                onChange={e => setNewRestoName(e.target.value)}
                            />
                        </div>

                        <div>
                            <label className="block text-xs font-bold text-gray-600 mb-1">Type d'établissement</label>
                            <select 
                                className="w-full p-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-brand-500 outline-none bg-white"
                                value={newRestoType}
                                onChange={e => setNewRestoType(e.target.value as BusinessType)}
                            >
                                <option value="restaurant">Restaurant</option>
                                <option value="snack">Snack / Fast Food</option>
                                <option value="bar">Bar / Lounge</option>
                                <option value="terrasse">Terrasse</option>
                            </select>
                        </div>

                        <button 
                            type="submit"
                            disabled={creationLoading}
                            className="w-full bg-brand-600 hover:bg-brand-700 text-white font-bold py-3 rounded-xl shadow-lg flex justify-center items-center mt-4"
                        >
                            {creationLoading ? (
                                <div className="w-5 h-5 border-2 border-white border-t-transparent rounded-full animate-spin"></div>
                            ) : (
                                <>Créer mon espace <ArrowRight size={18} className="ml-2"/></>
                            )}
                        </button>
                     </form>

                     <button onClick={handleLogout} className="mt-6 text-gray-400 text-sm hover:text-red-500 underline">
                         Annuler et se déconnecter
                     </button>
                 </div>
             </div>
         )
    }

    return (
      <>
        <OfflineBanner />
        <BusinessDashboard 
            user={currentUser} 
            restaurant={myRestaurant} 
            onUpdateRestaurant={handleUpdateRestaurant}
            onLogout={handleLogout}
        />
      </>
    );
  }

  // 3. Logged in as Client
  return (
    <>
      <OfflineBanner />
      <CustomerView 
        user={currentUser}
        allRestaurants={restaurants}
        onLogout={handleLogout}
      />
    </>
  );
}

export default App;

import React, { useState, useEffect } from 'react';
import { supabase } from '../lib/supabase';
import { Restaurant, MenuItem, User, Order, OrderStatus } from '../types';
import { 
  Plus, Trash2, Power, LogOut, Coffee, DollarSign, Clock, Truck, 
  Receipt, CheckCircle, ChefHat, Bike, LayoutDashboard, Settings, 
  TrendingUp, Users, ShoppingBag, X, Save, Image as ImageIcon, MapPin
} from 'lucide-react';

interface Props {
  user: User;
  restaurant: Restaurant;
  onUpdateRestaurant: (updated: Restaurant) => void;
  onLogout: () => void;
}

type DashboardView = 'overview' | 'orders' | 'menu' | 'settings';

export const BusinessDashboard: React.FC<Props> = ({ user, restaurant, onUpdateRestaurant, onLogout }) => {
  const [activeView, setActiveView] = useState<DashboardView>('overview');
  const [orders, setOrders] = useState<Order[]>([]);
  const [isSidebarOpen, setIsSidebarOpen] = useState(false); // For mobile

  // Menu Management State
  const [isAddingItem, setIsAddingItem] = useState(false);
  const [loading, setLoading] = useState(false);
  const [updatingTimes, setUpdatingTimes] = useState(false);

  // Settings State
  const [settingsForm, setSettingsForm] = useState({
      name: restaurant.name,
      description: restaurant.description,
      coverImage: restaurant.coverImage,
      city: restaurant.city
  });
  const [isSavingSettings, setIsSavingSettings] = useState(false);

  // Time editing state
  const [prepTime, setPrepTime] = useState(restaurant.preparationTime.toString());
  const [deliveryTime, setDeliveryTime] = useState(restaurant.estimatedDeliveryTime.toString());

  // New Item State
  const [newItemName, setNewItemName] = useState('');
  const [newItemDesc, setNewItemDesc] = useState('');
  const [newItemPrice, setNewItemPrice] = useState('');
  const [newItemCategory, setNewItemCategory] = useState<MenuItem['category']>('plat');

  // Load orders
  useEffect(() => {
    fetchRestaurantOrders();
    const interval = setInterval(fetchRestaurantOrders, 30000); // Auto-refresh every 30s
    return () => clearInterval(interval);
  }, []);

  // Sync settings form if restaurant prop changes
  useEffect(() => {
      setSettingsForm({
          name: restaurant.name,
          description: restaurant.description,
          coverImage: restaurant.coverImage,
          city: restaurant.city
      });
  }, [restaurant]);

  const fetchRestaurantOrders = async () => {
    try {
        const { data, error } = await supabase
            .from('orders')
            .select(`*, profiles:user_id(full_name)`)
            .eq('restaurant_id', restaurant.id)
            .order('created_at', { ascending: false });

        if (error) {
             // Fallback for demo mode if table doesn't exist or permission denied
             console.warn("Fetch orders failed, using local/demo mode if needed");
             const localOrders = localStorage.getItem('dashmeals_mock_orders');
             if (localOrders) {
                const parsed = JSON.parse(localOrders).filter((o:any) => o.restaurantId === restaurant.id);
                setOrders(parsed);
             }
             return;
        }

        if (data) {
            setOrders(data.map((o: any) => ({
                id: o.id,
                userId: o.user_id,
                restaurantId: o.restaurant_id,
                status: o.status,
                totalAmount: o.total_amount,
                items: o.items,
                createdAt: o.created_at,
                customer: { full_name: o.profiles?.full_name || 'Client Inconnu' }
            })));
        }
    } catch (err) {
        console.error("Error fetching restaurant orders:", err);
    }
  };

  const updateOrderStatus = async (orderId: string, newStatus: OrderStatus) => {
    try {
        const { error } = await supabase
            .from('orders')
            .update({ status: newStatus })
            .eq('id', orderId);

        if (error) {
            // Demo mode fallback
            const updatedOrders = orders.map(o => o.id === orderId ? { ...o, status: newStatus } : o);
            setOrders(updatedOrders);
            // Update local storage for persistence in demo
            const allMockOrders = JSON.parse(localStorage.getItem('dashmeals_mock_orders') || '[]');
            const newAllMock = allMockOrders.map((o:any) => o.id === orderId ? { ...o, status: newStatus } : o);
            localStorage.setItem('dashmeals_mock_orders', JSON.stringify(newAllMock));
        } else {
            setOrders(prev => prev.map(o => o.id === orderId ? { ...o, status: newStatus } : o));
        }
    } catch (err) {
        console.error("Error updating status:", err);
    }
  };

  const updateTimes = async () => {
    setUpdatingTimes(true);
    try {
      const newPrep = parseInt(prepTime) || 0;
      const newDeliv = parseInt(deliveryTime) || 0;

      const { error } = await supabase
        .from('restaurants')
        .update({ 
            preparation_time: newPrep,
            estimated_delivery_time: newDeliv
        })
        .eq('id', restaurant.id);

      if (error) throw error;

      onUpdateRestaurant({
          ...restaurant,
          preparationTime: newPrep,
          estimatedDeliveryTime: newDeliv
      });
      alert("Temps mis à jour !");
    } catch (err) {
        console.error("Error updating times", err);
        // Fallback demo
        onUpdateRestaurant({
            ...restaurant,
            preparationTime: parseInt(prepTime),
            estimatedDeliveryTime: parseInt(deliveryTime)
        });
    } finally {
        setUpdatingTimes(false);
    }
  };

  const toggleOpen = async () => {
    try {
      const newState = !restaurant.isOpen;
      const { error } = await supabase.from('restaurants').update({ is_open: newState }).eq('id', restaurant.id);
      if (error) throw error;
      onUpdateRestaurant({ ...restaurant, isOpen: newState });
    } catch (err) {
        // Fallback demo
        onUpdateRestaurant({ ...restaurant, isOpen: !restaurant.isOpen });
    }
  };

  const saveSettings = async (e: React.FormEvent) => {
      e.preventDefault();
      setIsSavingSettings(true);
      try {
          const { error } = await supabase
            .from('restaurants')
            .update({
                name: settingsForm.name,
                description: settingsForm.description,
                cover_image: settingsForm.coverImage,
                city: settingsForm.city
            })
            .eq('id', restaurant.id);

          if(error) throw error;

          onUpdateRestaurant({
              ...restaurant,
              ...settingsForm
          });
          alert("Paramètres enregistrés !");
      } catch (err) {
          console.error("Error saving settings", err);
          // Demo fallback
          onUpdateRestaurant({
            ...restaurant,
            ...settingsForm
        });
      } finally {
          setIsSavingSettings(false);
      }
  };

  const deleteItem = async (itemId: string) => {
    if (!window.confirm("Supprimer cet élément ?")) return;
    try {
      const { error } = await supabase.from('menu_items').delete().eq('id', itemId);
      if (error) throw error;
      onUpdateRestaurant({ ...restaurant, menu: restaurant.menu.filter(m => m.id !== itemId) });
    } catch (err) {
       // Demo
       onUpdateRestaurant({ ...restaurant, menu: restaurant.menu.filter(m => m.id !== itemId) });
    }
  };

  const addItem = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);
    const price = parseFloat(newItemPrice);
    const newItemPayload = {
      restaurant_id: restaurant.id,
      name: newItemName,
      description: newItemDesc,
      price: price,
      category: newItemCategory,
      is_available: true,
      image: `https://picsum.photos/200/200?random=${Date.now()}`
    };

    try {
      const { data, error } = await supabase.from('menu_items').insert(newItemPayload).select().single();

      if (error) throw error;

      if (data) {
        const newItem: MenuItem = {
          id: data.id, name: data.name, description: data.description, price: data.price,
          category: data.category as any, isAvailable: data.is_available, image: data.image
        };
        onUpdateRestaurant({ ...restaurant, menu: [...restaurant.menu, newItem] });
      }
    } catch (err) {
      // Demo Fallback
      const mockItem: MenuItem = {
          id: `mock-item-${Date.now()}`,
          name: newItemName,
          description: newItemDesc,
          price: price,
          category: newItemCategory,
          isAvailable: true,
          image: newItemPayload.image
      };
      onUpdateRestaurant({ ...restaurant, menu: [...restaurant.menu, mockItem] });
    } finally {
      setNewItemName(''); setNewItemDesc(''); setNewItemPrice(''); setIsAddingItem(false);
      setLoading(false);
    }
  };

  const getStatusBadge = (status: OrderStatus) => {
      switch(status) {
          case 'pending': return <span className="bg-gray-200 text-gray-700 px-2 py-1 rounded text-xs font-bold uppercase">En attente</span>;
          case 'preparing': return <span className="bg-yellow-100 text-yellow-700 px-2 py-1 rounded text-xs font-bold uppercase animate-pulse">En cuisine</span>;
          case 'ready': return <span className="bg-blue-100 text-blue-700 px-2 py-1 rounded text-xs font-bold uppercase">Prêt</span>;
          case 'delivering': return <span className="bg-orange-100 text-orange-700 px-2 py-1 rounded text-xs font-bold uppercase">Livraison</span>;
          case 'completed': return <span className="bg-green-100 text-green-700 px-2 py-1 rounded text-xs font-bold uppercase">Terminé</span>;
          case 'cancelled': return <span className="bg-red-100 text-red-700 px-2 py-1 rounded text-xs font-bold uppercase">Annulé</span>;
      }
  };

  // Stats Calculations
  const completedOrders = orders.filter(o => o.status === 'completed');
  const revenue = completedOrders.reduce((sum, o) => sum + o.totalAmount, 0);
  const activeOrders = orders.filter(o => ['pending', 'preparing', 'ready', 'delivering'].includes(o.status));

  // --- RENDER HELPERS ---

  const renderSidebarItem = (view: DashboardView, icon: React.ReactNode, label: string) => (
      <button 
        onClick={() => { setActiveView(view); setIsSidebarOpen(false); }}
        className={`w-full flex items-center space-x-3 px-4 py-3 rounded-xl transition-all font-medium ${activeView === view ? 'bg-brand-50 text-brand-700 font-bold shadow-sm' : 'text-gray-500 hover:bg-gray-50 hover:text-gray-900'}`}
      >
          {icon}
          <span>{label}</span>
      </button>
  );

  const renderOverview = () => (
      <div className="space-y-6 animate-in fade-in duration-500">
          <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
              {/* Revenue Card */}
              <div className="bg-white p-6 rounded-2xl shadow-sm border border-gray-100 flex items-center justify-between">
                  <div>
                      <p className="text-sm font-bold text-gray-400">Chiffre d'affaires</p>
                      <h3 className="text-2xl font-black text-gray-900 mt-1">${revenue.toFixed(2)}</h3>
                  </div>
                  <div className="w-12 h-12 bg-green-50 rounded-full flex items-center justify-center text-green-600">
                      <DollarSign size={24} />
                  </div>
              </div>
              {/* Active Orders Card */}
