import React, { useState, useEffect, useRef } from 'react';
import { Send, X, Phone, User, Store } from 'lucide-react';
import { supabase } from '../lib/supabase';
import { Message } from '../types';

interface Props {
  orderId: string;
  currentUser: { id: string; role: 'client' | 'business' };
  otherUserName: string;
  otherUserPhone?: string;
  onClose: () => void;
}

export const ChatWindow: React.FC<Props> = ({ orderId, currentUser, otherUserName, otherUserPhone, onClose }) => {
  const [messages, setMessages] = useState<Message[]>([]);
  const [newMessage, setNewMessage] = useState('');
  const [loading, setLoading] = useState(true);
  const messagesEndRef = useRef<HTMLDivElement>(null);

  // Scroll to bottom helper
  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  };

  useEffect(() => {
    fetchMessages();

    // Subscribe to new messages
    const channel = supabase
      .channel(`chat:${orderId}`)
      .on('postgres_changes', {
        event: 'INSERT',
        schema: 'public',
        table: 'messages',
        filter: `order_id=eq.${orderId}`
      }, (payload) => {
        const newMsg = {
            id: payload.new.id,
            orderId: payload.new.order_id,
            senderId: payload.new.sender_id,
            content: payload.new.content,
            createdAt: payload.new.created_at,
            isRead: payload.new.is_read
        };
        setMessages(prev => [...prev, newMsg]);
        scrollToBottom();
      })
      .subscribe();

    return () => {
      supabase.removeChannel(channel);
    };
  }, [orderId]);

  useEffect(() => {
    scrollToBottom();
  }, [messages]);

  const fetchMessages = async () => {
    try {
      const { data, error } = await supabase
        .from('messages')
        .select('*')
        .eq('order_id', orderId)
        .order('created_at', { ascending: true });

      if (error) throw error;

      if (data) {
        setMessages(data.map((m: any) => ({
          id: m.id,
          orderId: m.order_id,
          senderId: m.sender_id,
          content: m.content,
          createdAt: m.created_at,
          isRead: m.is_read
        })));
      }
    } catch (err) {
      console.warn("Erreur chargement messages (Mode démo possible)", err);
      // Demo fallback
      const local = localStorage.getItem(`chat_${orderId}`);
      if (local) setMessages(JSON.parse(local));
    } finally {
      setLoading(false);
    }
  };

  const handleSend = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!newMessage.trim()) return;

    const tempId = Date.now().toString();
    const msgPayload = {
      order_id: orderId,
      sender_id: currentUser.id,
      content: newMessage.trim(),
      is_read: false
    };

    // Optimistic UI update
    const optimisticMsg: Message = {
      id: tempId,
      orderId: orderId,
      senderId: currentUser.id,
      content: newMessage.trim(),
      createdAt: new Date().toISOString(),
      isRead: false
    };

    setMessages(prev => [...prev, optimisticMsg]);
    setNewMessage('');

    try {
      const { error } = await supabase.from('messages').insert(msgPayload);
      if (error) throw error;
    } catch (err) {
      console.error("Erreur envoi:", err);
      // Demo Mode Fallback
      const current = JSON.parse(localStorage.getItem(`chat_${orderId}`) || '[]');
      localStorage.setItem(`chat_${orderId}`, JSON.stringify([...current, optimisticMsg]));
    }
  };

  const handleCall = () => {
      if (otherUserPhone) {
          window.open(`tel:${otherUserPhone}`);
      } else {
          alert("Numéro de téléphone non disponible.");
      }
  };

  return (
    <div className="fixed inset-0 z-50 flex items-end sm:items-center justify-center pointer-events-none">
      <div className="absolute inset-0 bg-black/20 pointer-events-auto" onClick={onClose}></div>

      <div className="bg-white w-full sm:w-[400px] h-[80vh] sm:h-[600px] rounded-t-2xl sm:rounded-2xl shadow-2xl flex flex-col pointer-events-auto overflow-hidden animate-slide-in-up">

        {/* Header */}
        <div className="bg-brand-600 p-4 text-white flex justify-between items-center shadow-md">
          <div className="flex items-center space-x-3">
             <div className="w-10 h-10 bg-white/20 rounded-full flex items-center justify-center backdrop-blur-sm">
                {currentUser.role === 'client' ? <Store size={20}/> : <User size={20}/>}
             </div>
             <div>
                <h3 className="font-bold text-sm leading-tight">{otherUserName}</h3>
                <p className="text-[10px] opacity-80">Commande #{orderId.slice(0,4)}</p>
             </div>
          </div>
          <div className="flex items-center space-x-1">
             <button onClick={handleCall} className="p-2 hover:bg-white/10 rounded-full transition-colors">
                <Phone size={20} />
             </button>
             <button onClick={onClose} className="p-2 hover:bg-white/10 rounded-full transition-colors">
                <X size={20} />
             </button>
          </div>
        </div>

        {/* Messages Area */}
        <div className="flex-1 bg-gray-50 overflow-y-auto p-4 space-y-3">
            {messages.length === 0 && !loading && (
                <div className="text-center text-gray-400 text-xs mt-10">
                    <p>Commencez la discussion avec {otherUserName}.</p>
                </div>
            )}

            {messages.map((msg) => {
                const isMe = msg.senderId === currentUser.id;
                return (
                    <div key={msg.id} className={`flex ${isMe ? 'justify-end' : 'justify-start'}`}>
                        <div className={`max-w-[80%] rounded-2xl px-4 py-2 text-sm shadow-sm ${
                            isMe 
                            ? 'bg-brand-500 text-white rounded-tr-none' 
                            : 'bg-white text-gray-800 border border-gray-200 rounded-tl-none'
                        }`}>
                            <p>{msg.content}</p>
                            <span className={`text-[9px] block text-right mt-1 ${isMe ? 'text-brand-100' : 'text-gray-400'}`}>
                                {new Date(msg.createdAt).toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'})}
                            </span>
                        </div>
                    </div>
                );
            })}
            <div ref={messagesEndRef} />
        </div>

        {/* Input Area */}
        <form onSubmit={handleSend} className="p-3 bg-white border-t border-gray-100 flex items-center gap-2">
            <input 
                type="text" 
                className="flex-1 bg-gray-100 border-0 rounded-full px-4 py-3 text-sm focus:ring-2 focus:ring-brand-500 outline-none transition-all"
                placeholder="Votre message..."
                value={newMessage}
                onChange={e => setNewMessage(e.target.value)}
            />
            <button 
                type="submit" 
                disabled={!newMessage.trim()}
                className="bg-brand-600 text-white p-3 rounded-full hover:bg-brand-700 disabled:opacity-50 disabled:cursor-not-allowed shadow-sm transition-transform active:scale-90"
            >
                <Send size={18} className="ml-0.5" />
            </button>
        </form>

      </div>
    </div>
  );
};

import React, { useState, useEffect, useMemo } from 'react';
import { MapPin, ShoppingBag, List, Map, Zap, ArrowLeft, Plus, Bike, Footprints, LogOut, Navigation, Filter, Clock, Receipt, CheckCircle, ChefHat, Package, Search, X, MessageSquare, Phone } from 'lucide-react';
import { supabase } from '../lib/supabase';
import { KINSHASA_CENTER_LAT, KINSHASA_CENTER_LNG, CITIES_RDC } from '../constants';
import { Restaurant, UserState, ViewMode, MenuItem, CartItem, User, Order } from '../types';
import { calculateTime, getDistanceFromLatLonInKm, formatDistance, formatTime } from '../utils/geo';
import { RestaurantCard } from '../components/RestaurantCard';
import { MapView } from '../components/MapView';
import { CartDrawer } from '../components/CartDrawer';
import { ChatWindow } from '../components/ChatWindow';

// Speed constants
const SPEED_WALKING = 5;
const SPEED_MOTO = 30;

interface Props {
  user: User;
  allRestaurants: Restaurant[];
  onLogout: () => void;
}

export const CustomerView: React.FC<Props> = ({ user, allRestaurants, onLogout }) => {
  // State
  const [userState, setUserState] = useState<UserState>({
    location: null,
    locationError: null,
    loadingLocation: true,
  });

  const [restaurants, setRestaurants] = useState<Restaurant[]>([]);
  const [viewMode, setViewMode] = useState<ViewMode>('list');
  const [selectedRestaurant, setSelectedRestaurant] = useState<Restaurant | null>(null);
  const [cart, setCart] = useState<CartItem[]>([]);
  const [isCartOpen, setIsCartOpen] = useState(false);
  const [urgentMode, setUrgentMode] = useState(false);
  const [searchQuery, setSearchQuery] = useState('');
  const [showSuccess, setShowSuccess] = useState(false);
  const [selectedCity, setSelectedCity] = useState<string>(user.city || 'Kinshasa');

  // Order States
  const [orders, setOrders] = useState<Order[]>([]);
  const [isCheckingOut, setIsCheckingOut] = useState(false);

  // Chat State
  const [activeChatOrder, setActiveChatOrder] = useState<Order | null>(null);

  // Initial Geolocation
  useEffect(() => {
    if (!navigator.geolocation) {
      setUserState({
        location: null,
        locationError: "La géolocalisation n'est pas supportée par votre navigateur",
        loadingLocation: false
      });
      return;
    }

    navigator.geolocation.getCurrentPosition(
      (position) => {
        setUserState({
          location: {
            latitude: position.coords.latitude,
            longitude: position.coords.longitude,
          },
          locationError: null,
          loadingLocation: false
        });
      },
      (error) => {
        console.warn("Geo error:", error);
        setUserState({
            location: {
                latitude: KINSHASA_CENTER_LAT,
                longitude: KINSHASA_CENTER_LNG
            },
            locationError: "Position introuvable. Utilisation de la position par défaut (Kinshasa).",
            loadingLocation: false
        });
      },
      { enableHighAccuracy: true, timeout: 5000, maximumAge: 0 }
    );
  }, []);

  // Update Restaurants when location or database changes
  useEffect(() => {
    if (userState.location) {
      const updatedRestaurants = allRestaurants.map(r => {
        const dist = getDistanceFromLatLonInKm(
          userState.location!.latitude,
          userState.location!.longitude,
          r.latitude,
          r.longitude
        );
        return {
          ...r,
          distance: dist,
          timeWalking: calculateTime(dist, SPEED_WALKING),
          timeMoto: calculateTime(dist, SPEED_MOTO),
        };
      }).sort((a, b) => (a.distance || 0) - (b.distance || 0));

      setRestaurants(updatedRestaurants);
    } else {
      setRestaurants(allRestaurants);
    }
  }, [userState.location, allRestaurants]);

  // Load Orders when entering 'orders' view
  useEffect(() => {
    if (viewMode === 'orders') {
        fetchOrders();
    }
  }, [viewMode]);

  const fetchOrders = async () => {
    try {
        // Note: join restaurant table to get name and phone
        const { data, error } = await supabase
            .from('orders')
            .select(`
                *,
                restaurant:restaurants(name, phone_number)
            `)
            .eq('user_id', user.id)
            .order('created_at', { ascending: false });

        if (error) {
             console.warn("Erreur chargement commandes (403):", error.message);
             const localOrders = localStorage.getItem('dashmeals_mock_orders');
             if (localOrders) {
                 setOrders(JSON.parse(localOrders));
             }
             return;
        }

        if (data) {
            setOrders(data.map((o: any) => ({
                id: o.id,
                userId: o.user_id,
                restaurantId: o.restaurant_id,
                status: o.status,
                totalAmount: o.total_amount,
                items: o.items,
                createdAt: o.created_at,
                restaurant: {
                    name: o.restaurant?.name || 'Inconnu',
                    phone_number: o.restaurant?.phone_number
                }
            })));
        }
    } catch (err) {
        console.error("Error fetching orders:", err);
    }
  };

  // Filter Logic (City + Urgent + Search)
  const filteredRestaurants = useMemo(() => {
    let list = restaurants;

    // Filter by City
    if (selectedCity && selectedCity !== 'Toutes') {
      list = list.filter(r => r.city === selectedCity);
    }

    // Filter by Urgent Mode
    if (urgentMode) {
      list = list.filter(r => r.isOpen && r.preparationTime <= 20);
    }

    // Filter by Search Query
    if (searchQuery) {
        const query = searchQuery.toLowerCase();
        list = list.filter(r => 
            r.name.toLowerCase().includes(query) || 
            r.description.toLowerCase().includes(query)
        );
    }

    return list;
  }, [restaurants, urgentMode, selectedCity, searchQuery]);

  // Cart Logic
  const addToCart = (item: MenuItem, restaurant: Restaurant) => {
    // If cart has items from another restaurant, confirm clear
    if (cart.length > 0 && cart[0].restaurantId !== restaurant.id) {
        if(!window.confirm("Vous ne pouvez commander que dans un restaurant à la fois. Vider le panier actuel ?")) {
            return;
        }
        setCart([]);
    }

    setCart(prev => {
        const existing = prev.find(i => i.id === item.id);
        if (existing) {
             return prev.map(i => i.id === item.id ? { ...i, quantity: i.quantity + 1 } : i);
        }
        return [...prev, { ...item, quantity: 1, restaurantId: restaurant.id, restaurantName: restaurant.name }];
    });
  };

  const removeFromCart = (itemId: string) => {
    setCart(prev => {
        const index = prev.findIndex(i => i.id === itemId);
        if (index > -1) {
            const newArr = [...prev];
            newArr.splice(index, 1);
            return newArr;
        }
        return prev;
    });
  };

  const cartTotal = cart.reduce((sum, item) => sum + (item.price * item.quantity), 0);

  const handleCheckout = async () => {
    if (cart.length === 0) return;
    setIsCheckingOut(true);

    const newOrder: Order = {
        id: `mock-${Date.now()}`,
        userId: user.id,
        restaurantId: cart[0].restaurantId,
        status: 'pending',
        totalAmount: cartTotal,
        items: cart,
        createdAt: new Date().toISOString(),
        restaurant: { name: cart[0].restaurantName }
    };

    try {
        const restaurantId = cart[0].restaurantId;

        const { error } = await supabase
            .from('orders')
            .insert({
                user_id: user.id,
                restaurant_id: restaurantId,
                status: 'pending',
                total_amount: cartTotal,
                items: cart
            });

        if (error) {
            console.warn("Commande DB échouée (403), passage en simulation:", error.message);
            const existingMockOrders = JSON.parse(localStorage.getItem('dashmeals_mock_orders') || '[]');
            localStorage.setItem('dashmeals_mock_orders', JSON.stringify([newOrder, ...existingMockOrders]));
        }

        setIsCartOpen(false);
        setShowSuccess(true);
        setCart([]);
        setTimeout(() => {
            setShowSuccess(false);
            setViewMode('orders'); 
            fetchOrders();
            setOrders(prev => [newOrder, ...prev]);
        }, 3000);

    } catch (err) {
        console.error("Checkout error:", err);
        setIsCartOpen(false);
        setShowSuccess(true);
        setTimeout(() => {
            setShowSuccess(false);
            setViewMode('orders');
            setOrders(prev => [newOrder, ...prev]);
        }, 3000);
    } finally {
        setIsCheckingOut(false);
    }
  };

  const getStatusColor = (status: string) => {
    switch (status) {
        case 'pending': return 'bg-gray-100 text-gray-700';
        case 'preparing': return 'bg-yellow-100 text-yellow-800';
        case 'ready': return 'bg-blue-100 text-blue-800';
        case 'delivering': return 'bg-orange-100 text-orange-800';
        case 'completed': return 'bg-green-100 text-green-800';
        case 'cancelled': return 'bg-red-100 text-red-800';
        default: return 'bg-gray-100';
    }
  };

  const getStatusLabel = (status: string) => {
    switch (status) {
        case 'pending': return 'En attente';
        case 'preparing': return 'En cuisine';
        case 'ready': return 'Prêt';
        case 'delivering': return 'En livraison';
        case 'completed': return 'Livré';
        case 'cancelled': return 'Annulé';
        default: return status;
    }
  };

  const getProgressWidth = (status: string) => {
    switch(status) {
      case 'pending': return '10%';
      case 'preparing': return '35%';
      case 'ready': return '60%';
      case 'delivering': return '80%';
      case 'completed': return '100%';
      default: return '0%';
    }
  };

  // Views
  if (userState.loadingLocation) {
    return (
      <div className="min-h-screen flex flex-col items-center justify-center bg-brand-50">
        <div className="w-16 h-16 border-4 border-brand-500 border-t-transparent rounded-full animate-spin"></div>
        <p className="mt-4 text-brand-800 font-medium">Localisation en cours...</p>
      </div>
    );
  }

  return (
    <div className="min-h-screen pb-20 max-w-md mx-auto bg-gray-50 shadow-2xl overflow-hidden relative">

      {/* CHAT OVERLAY */}
      {activeChatOrder && (
          <ChatWindow 
            orderId={activeChatOrder.id}
            currentUser={{ id: user.id, role: 'client' }}
            otherUserName={activeChatOrder.restaurant?.name || 'Restaurant'}
            otherUserPhone={activeChatOrder.restaurant?.phone_number || '+243999999999'}
            onClose={() => setActiveChatOrder(null)}
          />
      )}

      {/* SUCCESS OVERLAY */}
      {showSuccess && (
        <div className="absolute inset-0 z-[60] bg-brand-500 flex flex-col items-center justify-center text-white p-6 text-center animate-fade-in">
           <div className="w-20 h-20 bg-white rounded-full flex items-center justify-center mb-6 shadow-xl">
              <ShoppingBag className="text-brand-500" size={40} />
           </div>
           <h2 className="text-3xl font-bold mb-2">Commande Reçue !</h2>
           <p className="text-brand-100">Votre repas est en préparation.</p>
           <div className="mt-8 bg-white/20 p-4 rounded-xl backdrop-blur-sm">
             <p className="font-mono text-sm">Vous pouvez suivre le statut dans "Commandes"</p>
           </div>
        </div>
      )}

      {/* HEADER */}
      <header className="bg-white sticky top-0 z-30 px-4 py-3 shadow-sm border-b border-gray-100">
        <div className="flex justify-between items-center mb-2">
            <div className="flex items-center">
                <h1 className="text-xl font-black text-brand-600 tracking-tight mr-2">DashMeals</h1>
