        {/* Location & City Filter - Only show in list/map mode */}
        {(viewMode === 'list' || viewMode === 'map') && (
            <div className="flex items-center space-x-2">
                <div className="flex-1 flex items-center text-sm text-gray-500 bg-gray-50 p-2 rounded-lg truncate">
                <MapPin size={14} className="mr-1.5 text-brand-500 flex-shrink-0" />
                <span className="truncate">
                    {userState.locationError ? "Mode Démo" : "Ma Position"}
                </span>
                </div>

                <select 
                className="bg-brand-50 text-brand-700 text-xs font-bold py-2 pl-2 pr-6 rounded-lg border border-brand-200 outline-none appearance-none bg-[url('data:image/svg+xml;charset=US-ASCII,%3Csvg%20xmlns%3D%22http%3A%2F%2Fwww.w3.org%2F2000%2Fsvg%22%20width%3D%22292.4%22%20height%3D%22292.4%22%3E%3Cpath%20fill%3D%22%23ea580c%22%20d%3D%22M287%2069.4a17.6%2017.6%200%200%200-13-5.4H18.4c-5%200-9.3%201.8-12.9%205.4A17.6%2017.6%200%200%200%200%2082.2c0%205%201.8%209.3%205.4%2012.9l128%20127.9c3.6%203.6%207.8%205.4%2012.8%205.4s9.2-1.8%2012.8-5.4L287%2095c3.5-3.5%205.4-7.8%205.4-12.8%200-5-1.9-9.2-5.5-12.8z%22%2F%3E%3C%2Fsvg%3E')] bg-[length:10px] bg-[right_8px_center] bg-no-repeat"
                value={selectedCity}
                onChange={(e) => setSelectedCity(e.target.value)}
                >
                <option value="Toutes">Toutes les villes</option>
                {CITIES_RDC.map(city => (
                    <option key={city} value={city}>{city}</option>
                ))}
                </select>
            </div>
        )}
      </header>

      {/* MAIN CONTENT AREA */}
      <main className="p-4">

        {viewMode === 'list' || viewMode === 'map' ? (
            <>
                {/* SEARCH BAR */}
                <div className="mb-4 relative">
                    <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 text-gray-400" size={18} />
                    <input 
                        type="text"
                        placeholder="Rechercher un restaurant..."
                        className="w-full pl-10 pr-10 py-3 rounded-xl border border-gray-200 focus:ring-2 focus:ring-brand-500 outline-none text-sm bg-white shadow-sm"
                        value={searchQuery}
                        onChange={(e) => setSearchQuery(e.target.value)}
                    />
                    {searchQuery && (
                        <button 
                            onClick={() => setSearchQuery('')}
                            className="absolute right-3 top-1/2 transform -translate-y-1/2 text-gray-400 hover:text-gray-600 p-1"
                        >
                            <X size={16} />
                        </button>
                    )}
                </div>

                {/* FILTERS */}
                <div className="flex space-x-3 mb-6 overflow-x-auto no-scrollbar pb-1">
                    <button 
                        onClick={() => setUrgentMode(!urgentMode)}
                        className={`flex items-center px-4 py-2 rounded-full font-bold text-sm shadow-sm transition-all border whitespace-nowrap ${urgentMode ? 'bg-red-500 text-white border-red-500 animate-pulse-fast' : 'bg-white text-gray-700 border-gray-200'}`}
                    >
                        <Zap size={16} className={`mr-1 ${urgentMode ? 'fill-white' : 'fill-none'}`} />
                        Urgent - J'ai faim !
                    </button>
                    <button className="px-4 py-2 rounded-full bg-white border border-gray-200 text-gray-600 font-medium text-sm whitespace-nowrap shadow-sm">
                        🍖 Grillades
                    </button>
                    <button className="px-4 py-2 rounded-full bg-white border border-gray-200 text-gray-600 font-medium text-sm whitespace-nowrap shadow-sm">
                        🍗 Poulet
                    </button>
                </div>

                {/* CONTENT */}
                {viewMode === 'list' ? (
                    <div className="space-y-4">
                        {filteredRestaurants.map(restaurant => (
                            <RestaurantCard 
                                key={restaurant.id} 
                                restaurant={restaurant} 
                                onClick={() => {
                                    setSelectedRestaurant(restaurant);
                                    setViewMode('restaurant_detail');
                                }} 
                            />
                        ))}
                        {filteredRestaurants.length === 0 && (
                            <div className="text-center py-10 text-gray-500">
                                <p>Aucun restaurant trouvé {selectedCity !== 'Toutes' ? `à ${selectedCity}` : ''} {searchQuery ? `pour "${searchQuery}"` : ''} :(</p>
                                {urgentMode && <button onClick={() => setUrgentMode(false)} className="text-brand-500 underline mt-2">Désactiver le mode urgent</button>}
                            </div>
                        )}
                    </div>
                ) : (
                    <MapView 
                        restaurants={filteredRestaurants} 
                        userLocation={userState.location} 
                        onSelect={(r) => {
                            setSelectedRestaurant(r);
                            setViewMode('restaurant_detail');
                        }}
                    />
                )}
            </>
        ) : viewMode === 'restaurant_detail' && selectedRestaurant ? (
            <div className="animate-in slide-in-from-right duration-300">
                <button 
                    onClick={() => setViewMode('list')} 
                    className="mb-4 flex items-center text-gray-600 font-medium hover:text-brand-600"
                >
                    <ArrowLeft size={18} className="mr-1" /> Retour
                </button>

                <div className="bg-white rounded-2xl shadow-sm border border-gray-100 overflow-hidden mb-6">
                    <img src={selectedRestaurant.coverImage} className="w-full h-48 object-cover" alt="Cover" />
                    <div className="p-4">
                        <div className="flex justify-between items-start">
                           <h1 className="text-2xl font-bold text-gray-900">{selectedRestaurant.name}</h1>
                           <span className="text-xs bg-gray-100 text-gray-600 px-2 py-1 rounded-lg">{selectedRestaurant.city}</span>
                        </div>
                        <p className="text-gray-500 mb-4">{selectedRestaurant.description}</p>

                        {/* Primary Stats */}
                        <div className="flex items-center space-x-4 text-sm text-gray-600 mb-4">
                            <span className="flex items-center bg-gray-100 px-2 py-1 rounded"><Navigation size={14} className="mr-1"/> {formatDistance(selectedRestaurant.distance || 0)}</span>
                            <span className="flex items-center bg-gray-100 px-2 py-1 rounded"><Zap size={14} className="mr-1 text-yellow-500"/> {selectedRestaurant.preparationTime} min</span>
                        </div>

                        {/* Travel Times with Icons */}
                        <div className="grid grid-cols-2 gap-3 mb-2">
                             <div className="flex items-center p-3 bg-orange-50 rounded-lg text-orange-700 border border-orange-100">
                                <Bike size={20} className="mr-3" />
                                <div>
                                    <p className="text-[10px] font-bold uppercase tracking-wider opacity-70">En Moto</p>
                                    <p className="font-bold text-lg leading-none">{selectedRestaurant.timeMoto ? formatTime(selectedRestaurant.timeMoto) : '--'}</p>
                                </div>
                            </div>
                            <div className="flex items-center p-3 bg-blue-50 rounded-lg text-blue-700 border border-blue-100">
                                <Footprints size={20} className="mr-3" />
                                <div>
                                     <p className="text-[10px] font-bold uppercase tracking-wider opacity-70">À pied</p>
                                     <p className="font-bold text-lg leading-none">{selectedRestaurant.timeWalking ? formatTime(selectedRestaurant.timeWalking) : '--'}</p>
                                </div>
                            </div>
                        </div>

                    </div>
                </div>

                <h3 className="text-lg font-bold mb-3">Menu</h3>
                <div className="space-y-3">
                    {selectedRestaurant.menu.map(item => (
                        <div key={item.id} className="bg-white p-3 rounded-xl border border-gray-100 shadow-sm flex space-x-3">
                            <img src={item.image} className="w-20 h-20 rounded-lg object-cover bg-gray-100" alt={item.name} />
                            <div className="flex-1 flex flex-col justify-between">
                                <div>
                                    <h4 className="font-bold text-gray-800">{item.name}</h4>
                                    <p className="text-xs text-gray-500 line-clamp-1">{item.description}</p>
                                </div>
                                <div className="flex justify-between items-end mt-2">
                                    <span className="font-bold text-brand-600">${item.price.toFixed(2)}</span>
                                    <button 
                                        onClick={() => addToCart(item, selectedRestaurant)}
                                        className="bg-brand-50 text-brand-600 p-2 rounded-full hover:bg-brand-100 transition-colors"
                                    >
                                        <Plus size={16} />
                                    </button>
                                </div>
                            </div>
                        </div>
                    ))}
                </div>
            </div>
        ) : viewMode === 'orders' ? (
            <div className="animate-in slide-in-from-right duration-300">
                <h2 className="text-xl font-black text-gray-800 mb-4 flex items-center">
                    <Receipt className="mr-2 text-brand-600"/> Historique
                </h2>

                {orders.length === 0 ? (
                    <div className="text-center text-gray-400 py-10">
                        <ShoppingBag size={48} className="mx-auto mb-2 opacity-20"/>
                        <p>Aucune commande effectuée.</p>
                        <button onClick={() => setViewMode('list')} className="mt-4 text-brand-600 font-bold underline">Commander un plat</button>
                    </div>
                ) : (
                    <div className="space-y-4">
                        {orders.map(order => {
                           const isCompleted = order.status === 'completed';
                           const isCancelled = order.status === 'cancelled';
                           return (
                            <div key={order.id} className="bg-white rounded-xl shadow-sm border border-gray-100 p-4">
                                <div className="flex justify-between items-start mb-2">
                                    <div>
                                        <h3 className="font-bold text-gray-800">{order.restaurant?.name || 'Restaurant inconnu'}</h3>
                                        <p className="text-[10px] text-gray-400">
                                            {new Date(order.createdAt).toLocaleDateString('fr-FR', { day: 'numeric', month: 'short', hour: '2-digit', minute: '2-digit'})}
                                        </p>
                                    </div>
                                    <span className={`text-[10px] font-bold px-2 py-1 rounded-full uppercase tracking-wide ${getStatusColor(order.status)}`}>
                                        {getStatusLabel(order.status)}
                                    </span>
                                </div>

                                {/* Progress Bar for Active Orders */}
                                {!isCompleted && !isCancelled && (
                                    <div className="mb-4 mt-2">
                                        <div className="h-1.5 w-full bg-gray-100 rounded-full overflow-hidden">
                                            <div 
                                                className="h-full bg-brand-500 transition-all duration-1000 ease-out"
                                                style={{ width: getProgressWidth(order.status) }}
                                            ></div>
                                        </div>
                                        <div className="flex justify-between text-[10px] text-gray-400 mt-1 font-medium">
                                            <span>Reçu</span>
                                            <span>Préparation</span>
                                            <span>Livraison</span>
                                        </div>
                                    </div>
                                )}

                                <div className="space-y-1 mb-3 bg-gray-50 p-2 rounded-lg">
                                    {order.items.map((item, idx) => (
                                        <div key={idx} className="flex justify-between text-sm text-gray-700">
                                            <span>{item.quantity}x {item.name}</span>
                                            <span className="font-medium">${(item.price * item.quantity).toFixed(2)}</span>
                                        </div>
                                    ))}
                                </div>
                                <div className="flex justify-between items-center pt-2 border-t border-gray-100">
                                    <span className="text-sm font-bold text-gray-500">Total</span>
                                    <div className="flex items-center space-x-3">
                                        <span className="text-lg font-black text-brand-600">${order.totalAmount.toFixed(2)}</span>
                                    </div>
                                </div>

                                {/* ACTIONS: CHAT & CALL (Visible pour les commandes en cours) */}
                                {!isCompleted && !isCancelled && (
                                    <div className="mt-3 grid grid-cols-2 gap-2">
                                        <button 
                                            onClick={() => window.open(`tel:${order.restaurant?.phone_number || '+243999999999'}`)}
                                            className="flex items-center justify-center py-2 bg-gray-100 text-gray-700 rounded-lg text-xs font-bold hover:bg-gray-200 transition-colors"
                                        >
                                            <Phone size={14} className="mr-2" /> Appeler
                                        </button>
                                        <button 
                                            onClick={() => setActiveChatOrder(order)}
                                            className="flex items-center justify-center py-2 bg-brand-100 text-brand-700 rounded-lg text-xs font-bold hover:bg-brand-200 transition-colors"
                                        >
                                            <MessageSquare size={14} className="mr-2" /> Message
                                        </button>
                                    </div>
                                )}
                            </div>
                           );
                        })}
                    </div>
                )}
            </div>
        ) : null}
      </main>

      {/* BOTTOM NAV */}
      <nav className="fixed bottom-0 left-0 right-0 bg-white border-t border-gray-200 px-6 py-3 flex justify-around items-center z-40 max-w-md mx-auto">
        <button 
            onClick={() => setViewMode('list')} 
            className={`flex flex-col items-center space-y-1 ${viewMode === 'list' || viewMode === 'restaurant_detail' ? 'text-brand-600' : 'text-gray-400'}`}
        >
            <List size={22} />
            <span className="text-[10px] font-medium">Liste</span>
        </button>

        {/* Urgent Button Floating */}
        <div className="relative -top-6">
            <button 
                onClick={() => setUrgentMode(!urgentMode)}
                className={`w-14 h-14 rounded-full flex items-center justify-center shadow-lg border-4 border-gray-50 transition-all ${urgentMode ? 'bg-red-500 text-white scale-110' : 'bg-brand-500 text-white'}`}
            >
                <Zap size={24} className={urgentMode ? 'animate-pulse' : ''} />
            </button>
        </div>

        <button 
            onClick={() => setViewMode('map')} 
            className={`flex flex-col items-center space-y-1 ${viewMode === 'map' ? 'text-brand-600' : 'text-gray-400'}`}
        >
            <Map size={22} />
            <span className="text-[10px] font-medium">Carte</span>
        </button>

        <button 
            onClick={() => setViewMode('orders')} 
            className={`flex flex-col items-center space-y-1 ${viewMode === 'orders' ? 'text-brand-600' : 'text-gray-400'}`}
        >
            <Receipt size={22} />
            <span className="text-[10px] font-medium">Commandes</span>
        </button>
      </nav>

      {/* CART DRAWER */}
      <CartDrawer 
        isOpen={isCartOpen} 
        onClose={() => setIsCartOpen(false)} 
        items={cart} 
        onRemove={removeFromCart} 
        onCheckout={handleCheckout}
        total={cartTotal}
        isLoading={isCheckingOut}
      />

    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { supabase } from '../lib/supabase';
import { Restaurant, MenuItem, User, Order, OrderStatus } from '../types';
import { 
  Plus, Trash2, Power, LogOut, Coffee, DollarSign, Clock, Truck, 
  Receipt, CheckCircle, ChefHat, Bike, LayoutDashboard, Settings, 
  TrendingUp, Users, ShoppingBag, X, Save, Image as ImageIcon, MapPin,
  MessageSquare, Phone
} from 'lucide-react';
import { ChatWindow } from '../components/ChatWindow';

interface Props {
  user: User;
  restaurant: Restaurant;
  onUpdateRestaurant: (updated: Restaurant) => void;
  onLogout: () => void;
}

type DashboardView = 'overview' | 'orders' | 'menu' | 'settings';

export const BusinessDashboard: React.FC<Props> = ({ user, restaurant, onUpdateRestaurant, onLogout }) => {
  const [activeView, setActiveView] = useState<DashboardView>('overview');
  const [orders, setOrders] = useState<Order[]>([]);
  const [isSidebarOpen, setIsSidebarOpen] = useState(false); // For mobile

  // Menu Management State
  const [isAddingItem, setIsAddingItem] = useState(false);
  const [loading, setLoading] = useState(false);
  const [updatingTimes, setUpdatingTimes] = useState(false);

  // Settings State
  const [settingsForm, setSettingsForm] = useState({
      name: restaurant.name,
      description: restaurant.description,
      coverImage: restaurant.coverImage,
      city: restaurant.city
  });
  const [isSavingSettings, setIsSavingSettings] = useState(false);

  // Time editing state
  const [prepTime, setPrepTime] = useState(restaurant.preparationTime.toString());
  const [deliveryTime, setDeliveryTime] = useState(restaurant.estimatedDeliveryTime.toString());

  // New Item State
  const [newItemName, setNewItemName] = useState('');
  const [newItemDesc, setNewItemDesc] = useState('');
  const [newItemPrice, setNewItemPrice] = useState('');
  const [newItemCategory, setNewItemCategory] = useState<MenuItem['category']>('plat');

  // Chat State
  const [activeChatOrder, setActiveChatOrder] = useState<Order | null>(null);

  // Load orders
  useEffect(() => {
    fetchRestaurantOrders();
    const interval = setInterval(fetchRestaurantOrders, 30000); // Auto-refresh every 30s
    return () => clearInterval(interval);
  }, []);

  // Sync settings form if restaurant prop changes
  useEffect(() => {
      setSettingsForm({
          name: restaurant.name,
          description: restaurant.description,
          coverImage: restaurant.coverImage,
          city: restaurant.city
      });
  }, [restaurant]);

  const fetchRestaurantOrders = async () => {
    try {
        const { data, error } = await supabase
            .from('orders')
            .select(`*, profiles:user_id(full_name, id)`) // Note: real schema would have phone here
            .eq('restaurant_id', restaurant.id)
            .order('created_at', { ascending: false });

        if (error) {
             // Fallback for demo mode if table doesn't exist or permission denied
             console.warn("Fetch orders failed, using local/demo mode if needed");
             const localOrders = localStorage.getItem('dashmeals_mock_orders');
             if (localOrders) {
                const parsed = JSON.parse(localOrders).filter((o:any) => o.restaurantId === restaurant.id);
                setOrders(parsed);
             }
             return;
        }

        if (data) {
            setOrders(data.map((o: any) => ({
                id: o.id,
                userId: o.user_id,
                restaurantId: o.restaurant_id,
                status: o.status,
                totalAmount: o.total_amount,
                items: o.items,
                createdAt: o.created_at,
                customer: { 
                    full_name: o.profiles?.full_name || 'Client Inconnu',
                    // Mock phone number since not in profile yet
                    phone_number: '+243000000000'
                }
            })));
        }
    } catch (err) {
        console.error("Error fetching restaurant orders:", err);
    }
  };

  const updateOrderStatus = async (orderId: string, newStatus: OrderStatus) => {
    try {
        const { error } = await supabase
            .from('orders')
            .update({ status: newStatus })
            .eq('id', orderId);

        if (error) {
            // Demo mode fallback
            const updatedOrders = orders.map(o => o.id === orderId ? { ...o, status: newStatus } : o);
            setOrders(updatedOrders);
            // Update local storage for persistence in demo
            const allMockOrders = JSON.parse(localStorage.getItem('dashmeals_mock_orders') || '[]');
            const newAllMock = allMockOrders.map((o:any) => o.id === orderId ? { ...o, status: newStatus } : o);
            localStorage.setItem('dashmeals_mock_orders', JSON.stringify(newAllMock));
        } else {
            setOrders(prev => prev.map(o => o.id === orderId ? { ...o, status: newStatus } : o));
        }
    } catch (err) {
        console.error("Error updating status:", err);
    }
  };

  const updateTimes = async () => {
    setUpdatingTimes(true);
    try {
      const newPrep = parseInt(prepTime) || 0;
      const newDeliv = parseInt(deliveryTime) || 0;

      const { error } = await supabase
        .from('restaurants')
        .update({ 
            preparation_time: newPrep,
            estimated_delivery_time: newDeliv
        })
        .eq('id', restaurant.id);

      if (error) throw error;

      onUpdateRestaurant({
          ...restaurant,
          preparationTime: newPrep,
          estimatedDeliveryTime: newDeliv
      });
      alert("Temps mis à jour !");
    } catch (err) {
        console.error("Error updating times", err);
        // Fallback demo
        onUpdateRestaurant({
            ...restaurant,
            preparationTime: parseInt(prepTime),
            estimatedDeliveryTime: parseInt(deliveryTime)
        });
    } finally {
        setUpdatingTimes(false);
    }
  };

  const toggleOpen = async () => {
    try {
      const newState = !restaurant.isOpen;
      const { error } = await supabase.from('restaurants').update({ is_open: newState }).eq('id', restaurant.id);
      if (error) throw error;
      onUpdateRestaurant({ ...restaurant, isOpen: newState });
    } catch (err) {
        // Fallback demo
        onUpdateRestaurant({ ...restaurant, isOpen: !restaurant.isOpen });
    }
  };

  const saveSettings = async (e: React.FormEvent) => {
      e.preventDefault();
      setIsSavingSettings(true);
      try {
          const { error } = await supabase
            .from('restaurants')
            .update({
                name: settingsForm.name,
                description: settingsForm.description,
                cover_image: settingsForm.coverImage,
                city: settingsForm.city
            })
            .eq('id', restaurant.id);

          if(error) throw error;

          onUpdateRestaurant({
              ...restaurant,
              ...settingsForm
          });
          alert("Paramètres enregistrés !");
      } catch (err) {
          console.error("Error saving settings", err);
          // Demo fallback
          onUpdateRestaurant({
            ...restaurant,
            ...settingsForm
        });
      } finally {
          setIsSavingSettings(false);
      }
  };

  const deleteItem = async (itemId: string) => {
    if (!window.confirm("Supprimer cet élément ?")) return;
    try {
      const { error } = await supabase.from('menu_items').delete().eq('id', itemId);
      if (error) throw error;
      onUpdateRestaurant({ ...restaurant, menu: restaurant.menu.filter(m => m.id !== itemId) });
    } catch (err) {
       // Demo
       onUpdateRestaurant({ ...restaurant, menu: restaurant.menu.filter(m => m.id !== itemId) });
    }
  };

  const addItem = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);
    const price = parseFloat(newItemPrice);
    const newItemPayload = {
      restaurant_id: restaurant.id,
      name: newItemName,
      description: newItemDesc,
      price: price,
      category: newItemCategory,
      is_available: true,
      image: `https://picsum.photos/200/200?random=${Date.now()}`
    };

    try {
      const { data, error } = await supabase.from('menu_items').insert(newItemPayload).select().single();

      if (error) throw error;

      if (data) {
        const newItem: MenuItem = {
          id: data.id, name: data.name, description: data.description, price: data.price,
          category: data.category as any, isAvailable: data.is_available, image: data.image
        };
        onUpdateRestaurant({ ...restaurant, menu: [...restaurant.menu, newItem] });
      }
    } catch (err) {
      // Demo Fallback
      const mockItem: MenuItem = {
          id: `mock-item-${Date.now()}`,
          name: newItemName,
          description: newItemDesc,
          price: price,
          category: newItemCategory,
          isAvailable: true,
          image: newItemPayload.image
      };
      onUpdateRestaurant({ ...restaurant, menu: [...restaurant.menu, mockItem] });
    } finally {
      setNewItemName(''); setNewItemDesc(''); setNewItemPrice(''); setIsAddingItem(false);
      setLoading(false);
    }
  };

  const getStatusBadge = (status: OrderStatus) => {
      switch(status) {
          case 'pending': return <span className="bg-gray-200 text-gray-700 px-2 py-1 rounded text-xs font-bold uppercase">En attente</span>;
          case 'preparing': return <span className="bg-yellow-100 text-yellow-700 px-2 py-1 rounded text-xs font-bold uppercase animate-pulse">En cuisine</span>;
          case 'ready': return <span className="bg-blue-100 text-blue-700 px-2 py-1 rounded text-xs font-bold uppercase">Prêt</span>;
          case 'delivering': return <span className="bg-orange-100 text-orange-700 px-2 py-1 rounded text-xs font-bold uppercase">Livraison</span>;
          case 'completed': return <span className="bg-green-100 text-green-700 px-2 py-1 rounded text-xs font-bold uppercase">Terminé</span>;
          case 'cancelled': return <span className="bg-red-100 text-red-700 px-2 py-1 rounded text-xs font-bold uppercase">Annulé</span>;
      }
  };

  // Stats Calculations
  const completedOrders = orders.filter(o => o.status === 'completed');
  const revenue = completedOrders.reduce((sum, o) => sum + o.totalAmount, 0);
  const activeOrders = orders.filter(o => ['pending', 'preparing', 'ready', 'delivering'].includes(o.status));

  // --- RENDER HELPERS ---

  const renderSidebarItem = (view: DashboardView, icon: React.ReactNode, label: string) => (
      <button 
        onClick={() => { setActiveView(view); setIsSidebarOpen(false); }}
        className={`w-full flex items-center space-x-3 px-4 py-3 rounded-xl transition-all font-medium ${activeView === view ? 'bg-brand-50 text-brand-700 font-bold shadow-sm' : 'text-gray-500 hover:bg-gray-50 hover:text-gray-900'}`}
      >
          {icon}
          <span>{label}</span>
      </button>
  );

  const renderOverview = () => (
      <div className="space-y-6 animate-in fade-in duration-500">
          <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
              {/* Revenue Card */}
              <div className="bg-white p-6 rounded-2xl shadow-sm border border-gray-100 flex items-center justify-between">
                  <div>
                      <p className="text-sm font-bold text-gray-400">Chiffre d'affaires</p>
                      <h3 className="text-2xl font-black text-gray-900 mt-1">${revenue.toFixed(2)}</h3>
                  </div>
                  <div className="w-12 h-12 bg-green-50 rounded-full flex items-center justify-center text-green-600">
                      <DollarSign size={24} />
                  </div>
              </div>
              {/* Active Orders Card */}
              <div className="bg-white p-6 rounded-2xl shadow-sm border border-gray-100 flex items-center justify-between">
                  <div>
                      <p className="text-sm font-bold text-gray-400">En cours</p>
                      <h3 className="text-2xl font-black text-gray-900 mt-1">{activeOrders.length}</h3>
                  </div>
                  <div className="w-12 h-12 bg-orange-50 rounded-full flex items-center justify-center text-orange-600">
                      <Clock size={24} />
                  </div>
              </div>
              {/* Total Orders Card */}
              <div className="bg-white p-6 rounded-2xl shadow-sm border border-gray-100 flex items-center justify-between">
                  <div>
                      <p className="text-sm font-bold text-gray-400">Total Commandes</p>
                      <h3 className="text-2xl font-black text-gray-900 mt-1">{orders.length}</h3>
                  </div>
                  <div className="w-12 h-12 bg-blue-50 rounded-full flex items-center justify-center text-blue-600">
                      <ShoppingBag size={24} />
                  </div>
              </div>
          </div>

          <div className="flex flex-col md:flex-row gap-6">
              {/* Status & Times */}
              <div className="bg-white p-6 rounded-2xl shadow-sm border border-gray-100 flex-1">
                  <h3 className="font-bold text-gray-800 mb-4 flex items-center">
                      <Power size={18} className="mr-2 text-brand-600"/> Statut & Horaires
                  </h3>
                  <div className="flex items-center justify-between mb-6 p-4 bg-gray-50 rounded-xl">
                      <div>
                          <p className="font-bold text-gray-700">{restaurant.isOpen ? 'Ouvert aux clients' : 'Fermé actuellement'}</p>
                          <p className="text-xs text-gray-500">Changez le statut à tout moment.</p>
                      </div>
                      <button 
                        onClick={toggleOpen}
                        className={`px-4 py-2 rounded-lg font-bold text-sm transition-colors ${restaurant.isOpen ? 'bg-green-500 text-white hover:bg-green-600' : 'bg-red-500 text-white hover:bg-red-600'}`}
                      >
                          {restaurant.isOpen ? 'Fermer' : 'Ouvrir'}
                      </button>
                  </div>

                  <div className="space-y-4">
                      <div>
                          <label className="text-xs font-bold text-gray-500 block mb-1">Temps de préparation (min)</label>
                          <input 
                              type="number" 
                              className="w-full p-2 border border-gray-300 rounded-lg"
                              value={prepTime}
                              onChange={e => setPrepTime(e.target.value)}
                          />
                      </div>
                      <div>
                          <label className="text-xs font-bold text-gray-500 block mb-1">Temps de livraison moyen (min)</label>
                          <input 
                              type="number" 
                              className="w-full p-2 border border-gray-300 rounded-lg"
                              value={deliveryTime}
                              onChange={e => setDeliveryTime(e.target.value)}
                          />
                      </div>
                      <button 
                        onClick={updateTimes}
                        disabled={updatingTimes}
                        className="w-full bg-brand-50 text-brand-700 font-bold py-2 rounded-lg hover:bg-brand-100"
                      >
                          {updatingTimes ? 'Mise à jour...' : 'Sauvegarder les temps'}
                      </button>
                  </div>
              </div>

              {/* Recent Orders Shortlist */}
              <div className="bg-white p-6 rounded-2xl shadow-sm border border-gray-100 flex-1">
                  <h3 className="font-bold text-gray-800 mb-4 flex items-center">
                      <TrendingUp size={18} className="mr-2 text-brand-600"/> Activité Récente
                  </h3>
                  <div className="space-y-3">
                      {orders.slice(0, 5).map(order => (
                          <div key={order.id} className="flex justify-between items-center p-3 bg-gray-50 rounded-lg cursor-pointer hover:bg-gray-100 transition-colors" onClick={() => setActiveView('orders')}>
                              <div>
                                  <p className="text-sm font-bold text-gray-700">{order.customer?.full_name}</p>
                                  <p className="text-xs text-gray-400">{new Date(order.createdAt).toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'})}</p>
                              </div>
                              <div className="text-right">
                                  <p className="text-sm font-bold text-gray-900">${order.totalAmount.toFixed(2)}</p>
                                  <span className={`text-[10px] font-bold px-1.5 py-0.5 rounded ${order.status === 'completed' ? 'bg-green-100 text-green-700' : 'bg-gray-200 text-gray-600'}`}>
                                      {order.status}
                                  </span>
                              </div>
                          </div>
                      ))}
                      {orders.length === 0 && <p className="text-gray-400 text-center text-sm">Aucune activité récente.</p>}
                  </div>
                  <button onClick={() => setActiveView('orders')} className="w-full mt-4 text-brand-600 text-sm font-bold hover:underline">
                      Voir toutes les commandes
                  </button>
              </div>
          </div>
      </div>
  );

  const renderOrders = () => {
      const active = orders.filter(o => ['pending', 'preparing', 'ready', 'delivering'].includes(o.status));
      const history = orders.filter(o => ['completed', 'cancelled'].includes(o.status));

      return (
          <div className="space-y-6 animate-in fade-in duration-500">
              <h2 className="text-2xl font-black text-gray-800">Gestion des Commandes</h2>

              {/* Active Orders Section */}
              <div className="bg-white rounded-2xl shadow-sm border border-gray-100 overflow-hidden">
                  <div className="bg-brand-50 p-4 border-b border-brand-100">
                      <h3 className="font-bold text-brand-800 flex items-center">
                          <Clock className="mr-2" size={20}/> En cours ({active.length})
                      </h3>
                  </div>
                  <div className="divide-y divide-gray-100">
                      {active.length === 0 ? (
                          <div className="p-8 text-center text-gray-400">Aucune commande en cours.</div>
                      ) : (
                          active.map(order => (
                              <div key={order.id} className="p-4 md:flex justify-between items-start hover:bg-gray-50 transition-colors">
                                  <div className="mb-4 md:mb-0">
                                      <div className="flex items-center space-x-2 mb-1">
