  restaurant?: {
    name: string;
    phone_number?: string;
  };
  customer?: {
    full_name: string;
    phone_number?: string;
  };
}

// Chat Types
export interface Message {
  id: string;
  orderId: string;
  senderId: string;
  content: string;
  createdAt: string;
  isRead: boolean;
}

