      if (data) {
        setPromotions(data.map((p: any) => ({
          id: p.id,
          restaurantId: p.restaurant_id,
          mediaUrl: p.media_url,
          mediaType: p.media_type,
          caption: p.caption,
          createdAt: p.created_at
        })));
      }
    } catch (err) {
      console.warn("Promotions fetch error (likely 403 in demo)", err);
    }
  };

