                            <div key={order.id} className="bg-white rounded-xl shadow-sm border border-gray-100 p-4">
                                <div className="flex justify-between items-start mb-2">
                                    <div>
                                        <h3 className="font-bold text-gray-800">{order.restaurant?.name || 'Restaurant inconnu'}</h3>
                                        <p className="text-[10px] text-gray-400">{new Date(order.createdAt).toLocaleDateString('fr-FR', { day: 'numeric', month: 'short', hour: '2-digit', minute: '2-digit'})}</p>
                                    </div>
                                    <span className={`text-[10px] font-bold px-2 py-1 rounded-full uppercase tracking-wide ${getStatusColor(order.status)}`}>{getStatusLabel(order.status)}</span>
                                </div>
                                {!isCompleted && !isCancelled && (
                                    <div className="mb-4 mt-2">
                                        <div className="h-1.5 w-full bg-gray-100 rounded-full overflow-hidden">
                                            <div className="h-full bg-brand-500 transition-all duration-1000 ease-out" style={{ width: getProgressWidth(order.status) }}></div>
                                        </div>
                                        <div className="flex justify-between text-[10px] text-gray-400 mt-1 font-medium"><span>Reçu</span><span>Préparation</span><span>Livraison</span></div>
                                    </div>
                                )}
                                <div className="space-y-1 mb-3 bg-gray-50 p-2 rounded-lg">
                                    {order.items.map((item, idx) => (
                                        <div key={idx} className="flex justify-between text-sm text-gray-700"><span>{item.quantity}x {item.name}</span><span className="font-medium">${(item.price * item.quantity).toFixed(2)}</span></div>
                                    ))}
                                </div>
                                <div className="flex justify-between items-center pt-2 border-t border-gray-100"><span className="text-sm font-bold text-gray-500">Total</span><div className="flex items-center space-x-3"><span className="text-lg font-black text-brand-600">${order.totalAmount.toFixed(2)}</span></div></div>
                                {!isCompleted && !isCancelled && (
                                    <div className="mt-3 grid grid-cols-2 gap-2">
                                        <button onClick={() => window.open(`tel:${order.restaurant?.phone_number || '+243999999999'}`)} className="flex items-center justify-center py-2 bg-gray-100 text-gray-700 rounded-lg text-xs font-bold hover:bg-gray-200 transition-colors"><Phone size={14} className="mr-2" /> Appeler</button>
                                        <button onClick={() => setActiveChatOrder(order)} className="flex items-center justify-center py-2 bg-brand-100 text-brand-700 rounded-lg text-xs font-bold hover:bg-brand-200 transition-colors"><MessageSquare size={14} className="mr-2" /> Message</button>
                                    </div>
                                )}
                            </div>
                           );
                        })}
                    </div>
                )}
            </div>
        ) : null}
      </main>

      <nav className="fixed bottom-0 left-0 right-0 bg-white border-t border-gray-200 px-6 py-3 flex justify-around items-center z-40 max-w-md mx-auto">
        <button onClick={() => setViewMode('list')} className={`flex flex-col items-center space-y-1 ${viewMode === 'list' || viewMode === 'restaurant_detail' ? 'text-brand-600' : 'text-gray-400'}`}><List size={22} /><span className="text-[10px] font-medium">Liste</span></button>
        <div className="relative -top-6"><button onClick={() => setUrgentMode(!urgentMode)} className={`w-14 h-14 rounded-full flex items-center justify-center shadow-lg border-4 border-gray-50 transition-all ${urgentMode ? 'bg-red-500 text-white scale-110' : 'bg-brand-500 text-white'}`}><Zap size={24} className={urgentMode ? 'animate-pulse' : ''} /></button></div>
        <button onClick={() => setViewMode('map')} className={`flex flex-col items-center space-y-1 ${viewMode === 'map' ? 'text-brand-600' : 'text-gray-400'}`}><Map size={22} /><span className="text-[10px] font-medium">Carte</span></button>
        <button onClick={() => setViewMode('orders')} className={`flex flex-col items-center space-y-1 ${viewMode === 'orders' ? 'text-brand-600' : 'text-gray-400'}`}><Receipt size={22} /><span className="text-[10px] font-medium">Commandes</span></button>
      </nav>

      <CartDrawer isOpen={isCartOpen} onClose={() => setIsCartOpen(false)} items={cart} onRemove={removeFromCart} onCheckout={handleCheckout} total={cartTotal} isLoading={isCheckingOut} />
    </div>
  );
};

import React from 'react';
import { Clock, Bike, Star, Footprints, Timer, Flame } from 'lucide-react';
import { Restaurant } from '../types';
import { formatDistance, formatTime } from '../utils/geo';

interface Props {
  restaurant: Restaurant;
  onClick: () => void;
}

export const RestaurantCard: React.FC<Props> = ({ restaurant, onClick }) => {
  // Simulate "Popular" by taking the first 3 items from the menu
  // In a real production environment, this would be sorted by an 'order_count' property from the database
  const popularItems = restaurant.menu ? restaurant.menu.slice(0, 3) : [];

  return (
    <div 
      onClick={onClick}
      className="bg-white rounded-xl shadow-sm border border-gray-100 overflow-hidden active:scale-95 transition-transform duration-200 cursor-pointer mb-4"
    >
      {/* Image Header */}
      <div className="relative h-36 w-full">
        <img 
          src={restaurant.coverImage} 
          alt={restaurant.name} 
          className="w-full h-full object-cover"
        />
        <div className="absolute top-2 right-2">
           {restaurant.isOpen ? (
             <span className="bg-green-500 text-white text-xs font-bold px-2 py-1 rounded-full shadow-sm">
               Ouvert
             </span>
           ) : (
             <span className="bg-red-500 text-white text-xs font-bold px-2 py-1 rounded-full shadow-sm">
               Fermé
             </span>
           )}
        </div>
        {restaurant.distance !== undefined && (
          <div className="absolute bottom-2 left-2 bg-black/60 backdrop-blur-sm text-white text-xs font-medium px-2 py-1 rounded-md">
            {formatDistance(restaurant.distance)}
          </div>
        )}
      </div>

      {/* Content */}
      <div className="p-4">
        <div className="flex justify-between items-start mb-1">
          <h3 className="text-lg font-bold text-gray-900 leading-tight">{restaurant.name}</h3>
          <div className="flex items-center space-x-1 bg-yellow-50 px-1.5 py-0.5 rounded text-yellow-700">
            <Star size={12} className="fill-yellow-500 text-yellow-500" />
            <span className="text-xs font-bold">{restaurant.rating}</span>
          </div>
        </div>

        <p className="text-gray-500 text-sm mb-3 line-clamp-1">{restaurant.description}</p>

        {/* Popular Dishes Section */}
        {popularItems.length > 0 && (
          <div className="mb-4">
            <div className="flex items-center mb-2">
              <Flame size={12} className="text-red-500 mr-1 fill-red-500" />
              <span className="text-xs font-bold text-gray-700">Populaires</span>
            </div>
            <div className="flex space-x-3 overflow-x-auto no-scrollbar pb-1">
              {popularItems.map((item) => (
                <div key={item.id} className="flex-shrink-0 w-20">
                  <div className="h-16 w-20 rounded-lg overflow-hidden mb-1 border border-gray-100 relative bg-gray-50">
                     <img src={item.image} alt={item.name} className="w-full h-full object-cover" />
                  </div>
                  <p className="text-[10px] font-bold text-gray-800 truncate">{item.name}</p>
                  <p className="text-[10px] text-brand-600 font-bold">${item.price.toFixed(2)}</p>
                </div>
              ))}
            </div>
          </div>
        )}

        {/* Times Grid */}
        <div className="grid grid-cols-2 gap-2 text-xs mb-3">
          {/* Estimated Delivery Time (from DB) */}
          <div className="flex items-center text-green-700 bg-green-50 p-2 rounded-lg border border-green-100 col-span-2 justify-center">
            <Timer size={14} className="mr-1.5" />
            <span className="font-bold opacity-80 mr-1">Livraison estimée:</span>
            <span className="font-bold text-sm">~{restaurant.estimatedDeliveryTime} min</span>
          </div>

          {/* Travel Times (Calculated) */}
          <div className="flex items-center text-orange-700 bg-orange-50 p-2 rounded-lg border border-orange-100">
            <Bike size={14} className="mr-1.5 opacity-70" />
            <span className="font-medium mr-1">Trajet:</span>
            <span className="font-bold">{restaurant.timeMoto ? formatTime(restaurant.timeMoto) : '--'}</span>
          </div>

          <div className="flex items-center text-blue-700 bg-blue-50 p-2 rounded-lg border border-blue-100">
            <Footprints size={14} className="mr-1.5 opacity-70" />
             <span className="font-medium mr-1">Trajet:</span>
            <span className="font-bold">{restaurant.timeWalking ? formatTime(restaurant.timeWalking) : '--'}</span>
          </div>
        </div>

        {/* Prep Time */}
        <div className="flex items-center text-gray-400 text-xs">
          <Clock size={12} className="mr-1" />
          <span>Préparation cuisine: ~{restaurant.preparationTime} min</span>
        </div>
      </div>
    </div>
  );
};

