interface Props {
  orders: Order[];
  onChat: (order: Order) => void;
  onBrowse: () => void;
}

export const OrdersView: React.FC<Props> = ({ orders, onChat, onBrowse }) => {
  const getStatusColor = (status: string) => {
    switch (status) {
        case 'pending': return 'bg-gray-100 text-gray-700';
        case 'preparing': return 'bg-yellow-100 text-yellow-800';
        case 'ready': return 'bg-blue-100 text-blue-800';
        case 'delivering': return 'bg-orange-100 text-orange-800';
        case 'completed': return 'bg-green-100 text-green-800';
        case 'cancelled': return 'bg-red-100 text-red-800';
        default: return 'bg-gray-100';
    }
  };

  const getStatusLabel = (status: string) => {
    switch (status) {
        case 'pending': return 'En attente';
        case 'preparing': return 'En cuisine';
        case 'ready': return 'Prêt';
        case 'delivering': return 'En livraison';
        case 'completed': return 'Livré';
        case 'cancelled': return 'Annulé';
        default: return status;
    }
  };

  const getProgressWidth = (status: string) => {
    switch(status) {
      case 'pending': return '10%'; 
      case 'preparing': return '35%'; 
      case 'ready': return '60%'; 
      case 'delivering': return '80%'; 
      case 'completed': return '100%'; 
      default: return '0%';
    }
  };

  return (
    <div className="animate-in slide-in-from-right duration-300">
        <h2 className="text-xl font-black text-gray-800 mb-4 flex items-center">
            <Receipt className="mr-2 text-brand-600"/> Historique
        </h2>
        {orders.length === 0 ? (
            <div className="text-center text-gray-400 py-10">
                <ShoppingBag size={48} className="mx-auto mb-2 opacity-20"/>
                <p>Aucune commande effectuée.</p>
                <button onClick={onBrowse} className="mt-4 text-brand-600 font-bold underline">Commander un plat</button>
            </div>
        ) : (
            <div className="space-y-4">
                {orders.map(order => {
                   const isCompleted = order.status === 'completed';
                   const isCancelled = order.status === 'cancelled';
                   return (
                    <div key={order.id} className="bg-white rounded-xl shadow-sm border border-gray-100 p-4">
                        <div className="flex justify-between items-start mb-2">
                            <div>
                                <h3 className="font-bold text-gray-800">{order.restaurant?.name || 'Restaurant inconnu'}</h3>
                                <p className="text-[10px] text-gray-400">{new Date(order.createdAt).toLocaleDateString('fr-FR', { day: 'numeric', month: 'short', hour: '2-digit', minute: '2-digit'})}</p>
                            </div>
                            <span className={`text-[10px] font-bold px-2 py-1 rounded-full uppercase tracking-wide ${getStatusColor(order.status)}`}>{getStatusLabel(order.status)}</span>
                        </div>
                        {!isCompleted && !isCancelled && (
                            <div className="mb-4 mt-2">
                                <div className="h-1.5 w-full bg-gray-100 rounded-full overflow-hidden">
                                    <div className="h-full bg-brand-500 transition-all duration-1000 ease-out" style={{ width: getProgressWidth(order.status) }}></div>
                                </div>
                                <div className="flex justify-between text-[10px] text-gray-400 mt-1 font-medium"><span>Reçu</span><span>Préparation</span><span>Livraison</span></div>
                            </div>
                        )}
                        <div className="space-y-1 mb-3 bg-gray-50 p-2 rounded-lg">
                            {order.items.map((item, idx) => (
                                <div key={idx} className="flex justify-between text-sm text-gray-700"><span>{item.quantity}x {item.name}</span><span className="font-medium">${(item.price * item.quantity).toFixed(2)}</span></div>
                            ))}
                        </div>
                        <div className="flex justify-between items-center pt-2 border-t border-gray-100"><span className="text-sm font-bold text-gray-500">Total</span><div className="flex items-center space-x-3"><span className="text-lg font-black text-brand-600">${order.totalAmount.toFixed(2)}</span></div></div>
                        {!isCompleted && !isCancelled && (
                            <div className="mt-3 grid grid-cols-2 gap-2">
                                <button onClick={() => window.open(`tel:${order.restaurant?.phone_number || '+243999999999'}`)} className="flex items-center justify-center py-2 bg-gray-100 text-gray-700 rounded-lg text-xs font-bold hover:bg-gray-200 transition-colors"><Phone size={14} className="mr-2" /> Appeler</button>
                                <button onClick={() => onChat(order)} className="flex items-center justify-center py-2 bg-brand-100 text-brand-700 rounded-lg text-xs font-bold hover:bg-brand-200 transition-colors"><MessageSquare size={14} className="mr-2" /> Message</button>
                            </div>
                        )}
                    </div>
                   );
                })}
            </div>
        )}
    </div>
  );
};

