          <div className="pt-4 border-t border-gray-100 flex justify-end">
            <button
              type="submit"
              disabled={isSavingSettings}
              className="bg-brand-600 text-white font-bold py-4 px-8 rounded-xl hover:bg-brand-700 shadow-lg transition-transform active:scale-95 flex items-center"
            >
              {isSavingSettings ? (
                <>
                  <div className="w-5 h-5 border-2 border-white border-t-transparent rounded-full animate-spin mr-2"></div>
                  Sauvegarde...
                </>
              ) : (
                <>
                  <Save className="mr-2" size={20} />
                  Enregistrer les modifications
                </>
              )}
            </button>
          </div>
        </form>
      </div>
    </div>
  );

  const renderOrders = () => (
    <div className="space-y-6 animate-in fade-in duration-500">
      <h2 className="text-2xl font-black text-gray-800">Commandes ({orders.length})</h2>

      <div className="space-y-4">
        {orders.length === 0 ? (
           <div className="text-center py-10 bg-white rounded-2xl border border-gray-100">
              <ShoppingBag className="mx-auto h-12 w-12 text-gray-300 mb-3" />
              <p className="text-gray-500 font-medium">Aucune commande pour le moment.</p>
           </div>
        ) : (
          orders.map(order => (
            <div key={order.id} className="bg-white p-6 rounded-2xl shadow-sm border border-gray-100">
               <div className="flex flex-col md:flex-row justify-between md:items-start mb-4">
                  <div>
                      <div className="flex items-center space-x-2">
                        <h3 className="font-bold text-lg text-gray-900">Commande #{order.id.slice(0,6)}</h3>
                        {getStatusBadge(order.status)}
                      </div>
                      <p className="text-sm text-gray-500 mt-1 flex items-center">
                         <span className="font-bold mr-1">{order.customer?.full_name}</span> 
                         • {new Date(order.createdAt).toLocaleString()}
                      </p>
                      {order.customer?.phone_number && (
                          <div className="flex items-center text-xs text-brand-600 font-bold mt-1 cursor-pointer" onClick={() => window.open(`tel:${order.customer?.phone_number}`)}>
                              <Phone size={12} className="mr-1"/> {order.customer?.phone_number}
                          </div>
                      )}
                  </div>
                  <div className="mt-4 md:mt-0 text-right">
                      <p className="text-2xl font-black text-brand-600">${order.totalAmount.toFixed(2)}</p>
                      <p className="text-xs text-gray-400 font-bold uppercase">{order.items.length} articles</p>
                  </div>
               </div>

               <div className="bg-gray-50 rounded-xl p-4 mb-4 space-y-2">
                  {order.items.map((item, i) => (
                      <div key={i} className="flex justify-between items-center text-sm">
                          <div className="flex items-center">
                              <span className="font-bold bg-white border border-gray-200 w-6 h-6 flex items-center justify-center rounded-md mr-3 text-xs">
                                  {item.quantity}
                              </span>
                              <span className="text-gray-700">{item.name}</span>
                          </div>
                          <span className="font-bold text-gray-900">${(item.price * item.quantity).toFixed(2)}</span>
                      </div>
                  ))}
               </div>

               <div className="flex flex-wrap gap-2 justify-end pt-2 border-t border-gray-100">
                   <button 
                      onClick={() => setActiveChatOrder(order)}
                      className="px-4 py-2 bg-blue-50 text-blue-600 rounded-lg text-xs font-bold hover:bg-blue-100 flex items-center"
                   >
                       <MessageSquare size={14} className="mr-2"/> Message Client
                   </button>

                   {order.status === 'pending' && (
                       <>
                           <button onClick={() => updateOrderStatus(order.id, 'cancelled')} className="px-4 py-2 bg-red-50 text-red-600 rounded-lg text-xs font-bold hover:bg-red-100">Refuser</button>
                           <button onClick={() => updateOrderStatus(order.id, 'preparing')} className="px-4 py-2 bg-brand-600 text-white rounded-lg text-xs font-bold hover:bg-brand-700 shadow-md">Accepter & Cuisiner</button>
                       </>
                   )}
                   {order.status === 'preparing' && (
                       <button onClick={() => updateOrderStatus(order.id, 'ready')} className="px-4 py-2 bg-orange-500 text-white rounded-lg text-xs font-bold hover:bg-orange-600 shadow-md">Marquer Prêt</button>
                   )}
                   {order.status === 'ready' && (
                       <button onClick={() => updateOrderStatus(order.id, 'delivering')} className="px-4 py-2 bg-blue-500 text-white rounded-lg text-xs font-bold hover:bg-blue-600 shadow-md">En Livraison</button>
                   )}
                   {order.status === 'delivering' && (
                       <button onClick={() => updateOrderStatus(order.id, 'completed')} className="px-4 py-2 bg-green-500 text-white rounded-lg text-xs font-bold hover:bg-green-600 shadow-md">Terminer (Livré)</button>
                   )}
               </div>
            </div>
          ))
        )}
      </div>
    </div>
  );

  const renderMarketing = () => (
    <div className="space-y-6 animate-in fade-in duration-500">
        <div className="flex justify-between items-center">
            <h2 className="text-2xl font-black text-gray-800">Marketing & Stories</h2>
            <button 
                onClick={() => setIsAddingPromo(!isAddingPromo)}
                className="flex items-center bg-brand-600 text-white px-4 py-2 rounded-xl font-bold hover:bg-brand-700 transition-colors shadow-lg"
            >
                <Plus size={18} className="mr-2" /> Nouvelle Story
            </button>
        </div>

        {isAddingPromo && (
            <form onSubmit={addPromotion} className="bg-gradient-to-br from-purple-50 to-pink-50 p-6 rounded-2xl border border-purple-100 shadow-sm animate-slide-in-down">
                <h4 className="font-bold text-purple-900 mb-4 flex items-center"><Megaphone size={18} className="mr-2"/> Créer une promotion</h4>

                <div className="space-y-4">
                    <div>
                        <label className="block text-xs font-bold text-gray-500 mb-1">Type de média</label>
                        <div className="flex space-x-4">
                            <label className={`flex items-center space-x-2 cursor-pointer p-3 rounded-xl border ${newPromoType === 'image' ? 'bg-white border-purple-500 text-purple-700' : 'bg-transparent border-transparent'}`}>
                                <input type="radio" name="type" className="hidden" checked={newPromoType === 'image'} onChange={() => setNewPromoType('image')} />
                                <ImageIcon size={20} />
                                <span className="font-bold text-sm">Image</span>
                            </label>
                            <label className={`flex items-center space-x-2 cursor-pointer p-3 rounded-xl border ${newPromoType === 'video' ? 'bg-white border-purple-500 text-purple-700' : 'bg-transparent border-transparent'}`}>
                                <input type="radio" name="type" className="hidden" checked={newPromoType === 'video'} onChange={() => setNewPromoType('video')} />
                                <Video size={20} />
                                <span className="font-bold text-sm">Vidéo (MP4)</span>
                            </label>
                        </div>
                    </div>

                    <div>
                        <label className="block text-xs font-bold text-gray-500 mb-1">URL du média (Image ou Vidéo)</label>
                        <input 
                            type="url" 
                            required 
                            className="w-full p-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-purple-500 outline-none"
                            placeholder="https://..."
                            value={newPromoUrl}
                            onChange={e => setNewPromoUrl(e.target.value)}
                        />
                        <p className="text-[10px] text-gray-400 mt-1">Utilisez une URL directe vers votre image ou vidéo.</p>
                    </div>

                    <div>
                        <label className="block text-xs font-bold text-gray-500 mb-1">Légende (Optionnel)</label>
                        <input 
                            type="text" 
                            className="w-full p-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-purple-500 outline-none"
                            placeholder="Ex: -50% aujourd'hui seulement !"
                            value={newPromoCaption}
                            onChange={e => setNewPromoCaption(e.target.value)}
                        />
                    </div>

                    <div className="flex justify-end pt-2">
                        <button 
                            type="submit"
                            disabled={loading}
                            className="bg-purple-600 text-white font-bold py-3 px-6 rounded-xl hover:bg-purple-700 shadow-lg flex items-center"
                        >
                            {loading ? 'Publication...' : 'Publier la Story'}
                        </button>
                    </div>
                </div>
            </form>
        )}

        <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
            {promotions.map(promo => (
                <div key={promo.id} className="group relative aspect-[9/16] rounded-2xl overflow-hidden shadow-md bg-black">
                    {promo.mediaType === 'video' ? (
                        <video src={promo.mediaUrl} className="w-full h-full object-cover opacity-80" muted />
                    ) : (
                        <img src={promo.mediaUrl} alt="Promo" className="w-full h-full object-cover opacity-80" />
                    )}

                    <div className="absolute inset-0 bg-gradient-to-t from-black/80 to-transparent flex flex-col justify-end p-4">
                        <p className="text-white font-bold text-sm line-clamp-2 mb-2">{promo.caption || 'Sans légende'}</p>
                        <p className="text-[10px] text-gray-300">{new Date(promo.createdAt).toLocaleDateString()}</p>
                    </div>

                    <button 
                        onClick={() => deletePromotion(promo.id)}
                        className="absolute top-2 right-2 p-2 bg-red-500/80 text-white rounded-full opacity-0 group-hover:opacity-100 transition-opacity hover:bg-red-600"
                    >
                        <Trash2 size={16} />
                    </button>

                    {promo.mediaType === 'video' && (
                        <div className="absolute top-2 left-2 p-1 bg-black/50 rounded text-white">
                            <PlayCircle size={16} />
                        </div>
                    )}
                </div>
            ))}
            {promotions.length === 0 && !isAddingPromo && (
                <div className="col-span-full text-center py-10 bg-white rounded-2xl border border-gray-100">
                    <Megaphone className="mx-auto h-12 w-12 text-gray-300 mb-3" />
                    <p className="text-gray-500">Aucune promotion active.</p>
                    <p className="text-xs text-gray-400">Ajoutez des stories pour attirer plus de clients !</p>
                </div>
            )}
        </div>
    </div>
  );

  return (
    <div className="min-h-screen bg-gray-50 flex">

      {activeChatOrder && (
          <ChatWindow 
            orderId={activeChatOrder.id}
            currentUser={{ id: user.id, role: 'business' }}
            otherUserName={activeChatOrder.customer?.full_name || 'Client'}
            otherUserPhone={activeChatOrder.customer?.phone_number || ''}
            onClose={() => setActiveChatOrder(null)}
          />
      )}

      <aside className="hidden md:flex w-64 flex-col bg-white border-r border-gray-200 h-screen sticky top-0">
          <div className="p-6 border-b border-gray-100">
              <h1 className="text-2xl font-black text-brand-600 tracking-tight">DashPro</h1>
              <p className="text-xs text-gray-500 mt-1">Espace Partenaire</p>
          </div>
          <nav className="flex-1 p-4 space-y-2">
              {renderSidebarItem('overview', <LayoutDashboard size={20}/>, 'Vue d\'ensemble')}
              {renderSidebarItem('orders', <ShoppingBag size={20}/>, 'Commandes')}
              {renderSidebarItem('menu', <Coffee size={20}/>, 'Menu & Carte')}
              {renderSidebarItem('marketing', <Megaphone size={20}/>, 'Marketing')}
              {renderSidebarItem('settings', <Settings size={20}/>, 'Paramètres')}
          </nav>
          <div className="p-4 border-t border-gray-100">
             <button onClick={onLogout} className="w-full flex items-center justify-center space-x-2 text-red-500 hover:bg-red-50 p-2 rounded-lg transition-colors font-medium text-sm">
                  <LogOut size={16} />
                  <span>Déconnexion</span>
              </button>
          </div>
      </aside>

      <div className="md:hidden fixed top-0 left-0 right-0 bg-white border-b border-gray-200 z-50 px-4 py-3 flex justify-between items-center">
          <h1 className="text-xl font-black text-brand-600">DashPro</h1>
          <button onClick={() => setIsSidebarOpen(!isSidebarOpen)} className="p-2 text-gray-600">
             {isSidebarOpen ? <X /> : <LayoutDashboard />}
          </button>
      </div>

      {isSidebarOpen && (
          <div className="md:hidden fixed inset-0 z-40 bg-gray-800/50 backdrop-blur-sm" onClick={() => setIsSidebarOpen(false)}>
              <div className="w-3/4 h-full bg-white p-4 space-y-2 pt-20" onClick={e => e.stopPropagation()}>
                  {renderSidebarItem('overview', <LayoutDashboard size={20}/>, 'Vue d\'ensemble')}
                  {renderSidebarItem('orders', <ShoppingBag size={20}/>, 'Commandes')}
                  {renderSidebarItem('menu', <Coffee size={20}/>, 'Menu & Carte')}
                  {renderSidebarItem('marketing', <Megaphone size={20}/>, 'Marketing')}
                  {renderSidebarItem('settings', <Settings size={20}/>, 'Paramètres')}
                  <button onClick={onLogout} className="w-full flex items-center space-x-3 px-4 py-3 text-red-500 mt-10">
                      <LogOut size={20}/> <span>Déconnexion</span>
                  </button>
              </div>
          </div>
      )}

      <main className="flex-1 p-6 md:p-10 pt-20 md:pt-10 overflow-y-auto">
          {activeView === 'overview' && renderOverview()}
          {activeView === 'orders' && renderOrders()}
          {activeView === 'menu' && renderMenu()}
          {activeView === 'marketing' && renderMarketing()}
          {activeView === 'settings' && renderSettings()}
      </main>

    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { supabase } from '../lib/supabase';
import { Restaurant, MenuItem, User, Order, OrderStatus, Promotion } from '../types';
import { 
  Plus, Trash2, Power, LogOut, Coffee, DollarSign, Clock, Truck, 
  Receipt, CheckCircle, ChefHat, Bike, LayoutDashboard, Settings, 
  TrendingUp, Users, ShoppingBag, X, Save, Image as ImageIcon, MapPin,
  MessageSquare, Phone, Megaphone, Video, PlayCircle, Upload, AlertCircle
} from 'lucide-react';
import { ChatWindow } from '../components/ChatWindow';

interface Props {
  user: User;
  restaurant: Restaurant;
  onUpdateRestaurant: (updated: Restaurant) => void;
  onLogout: () => void;
}

type DashboardView = 'overview' | 'orders' | 'menu' | 'settings' | 'marketing';

export const BusinessDashboard: React.FC<Props> = ({ user, restaurant, onUpdateRestaurant, onLogout }) => {
  const [activeView, setActiveView] = useState<DashboardView>('overview');
  const [orders, setOrders] = useState<Order[]>([]);
  const [isSidebarOpen, setIsSidebarOpen] = useState(false); // For mobile

  // Menu Management State
  const [isAddingItem, setIsAddingItem] = useState(false);
  const [loading, setLoading] = useState(false);
  const [updatingTimes, setUpdatingTimes] = useState(false);

  // Marketing State
  const [promotions, setPromotions] = useState<Promotion[]>([]);
  const [newPromoUrl, setNewPromoUrl] = useState('');
  const [newPromoType, setNewPromoType] = useState<'image' | 'video'>('image');
  const [newPromoCaption, setNewPromoCaption] = useState('');
  const [isAddingPromo, setIsAddingPromo] = useState(false);

  // Settings State
  const [settingsForm, setSettingsForm] = useState({
      name: restaurant.name,
      description: restaurant.description,
      coverImage: restaurant.coverImage,
      city: restaurant.city,
      phoneNumber: restaurant.phoneNumber || ''
  });
  const [isSavingSettings, setIsSavingSettings] = useState(false);
  const [coverImageFile, setCoverImageFile] = useState<File | null>(null);

  // Time editing state
  const [prepTime, setPrepTime] = useState(restaurant.preparationTime.toString());
  const [deliveryTime, setDeliveryTime] = useState(restaurant.estimatedDeliveryTime.toString());

  // New Item State
  const [newItemName, setNewItemName] = useState('');
  const [newItemDesc, setNewItemDesc] = useState('');
  const [newItemPrice, setNewItemPrice] = useState('');
  const [newItemCategory, setNewItemCategory] = useState<MenuItem['category']>('plat');
  const [newItemImageFile, setNewItemImageFile] = useState<File | null>(null);

  // Chat State
  const [activeChatOrder, setActiveChatOrder] = useState<Order | null>(null);

  // Load orders and promotions
  useEffect(() => {
    fetchRestaurantOrders();
    fetchPromotions();
    const interval = setInterval(fetchRestaurantOrders, 30000); // Auto-refresh every 30s
    return () => clearInterval(interval);
  }, []);

  // Sync settings form if restaurant prop changes
  useEffect(() => {
      setSettingsForm({
          name: restaurant.name,
          description: restaurant.description,
          coverImage: restaurant.coverImage,
          city: restaurant.city,
          phoneNumber: restaurant.phoneNumber || ''
      });
  }, [restaurant]);

  // UPLOAD HELPER FUNCTION
  const uploadImage = async (file: File, bucket: string = 'images'): Promise<string | null> => {
      try {
          const fileExt = file.name.split('.').pop();
          const fileName = `${Math.random().toString(36).substring(2, 15)}_${Date.now()}.${fileExt}`;
          const filePath = `${fileName}`;

          const { error: uploadError } = await supabase.storage.from(bucket).upload(filePath, file);

          if (uploadError) {
              console.error("Upload error:", uploadError);
              alert("Erreur upload image (Vérifiez que le bucket 'images' existe dans Supabase)");
              return null;
          }

          const { data } = supabase.storage.from(bucket).getPublicUrl(filePath);
          return data.publicUrl;
      } catch (error) {
          console.error("Upload exception:", error);
          return null;
      }
  };

  const fetchPromotions = async () => {
    try {
      const { data, error } = await supabase
        .from('promotions')
        .select('*')
        .eq('restaurant_id', restaurant.id)
        .order('created_at', { ascending: false });

      if (data) {
        setPromotions(data.map((p: any) => ({
          id: p.id,
          restaurantId: p.restaurant_id,
          mediaUrl: p.media_url,
          mediaType: p.media_type,
          caption: p.caption,
          createdAt: p.created_at
        })));
      }
    } catch (err) {
      console.warn("Promotions fetch error (likely 403 in demo)", err);
    }
  };

  const fetchRestaurantOrders = async () => {
    try {
        const { data, error } = await supabase
            .from('orders')
            .select(`*, profiles:user_id(full_name, id, phone_number)`) // Retrieve phone_number from profile
            .eq('restaurant_id', restaurant.id)
            .order('created_at', { ascending: false });

        if (error) {
             // Fallback for demo mode
             console.warn("Fetch orders failed, using local/demo mode if needed");
             const localOrders = localStorage.getItem('dashmeals_mock_orders');
             if (localOrders) {
                const parsed = JSON.parse(localOrders).filter((o:any) => o.restaurantId === restaurant.id);
                setOrders(parsed);
             }
             return;
        }

        if (data) {
            setOrders(data.map((o: any) => ({
                id: o.id,
                userId: o.user_id,
                restaurantId: o.restaurant_id,
                status: o.status,
                totalAmount: o.total_amount,
                items: o.items,
                createdAt: o.created_at,
                customer: { 
                    full_name: o.profiles?.full_name || 'Client Inconnu',
                    phone_number: o.profiles?.phone_number || ''
                }
            })));
        }
    } catch (err) {
        console.error("Error fetching restaurant orders:", err);
    }
  };

  const updateOrderStatus = async (orderId: string, newStatus: OrderStatus) => {
    try {
        const { error } = await supabase
            .from('orders')
            .update({ status: newStatus })
            .eq('id', orderId);

        if (error) {
            const updatedOrders = orders.map(o => o.id === orderId ? { ...o, status: newStatus } : o);
            setOrders(updatedOrders);
            const allMockOrders = JSON.parse(localStorage.getItem('dashmeals_mock_orders') || '[]');
            const newAllMock = allMockOrders.map((o:any) => o.id === orderId ? { ...o, status: newStatus } : o);
            localStorage.setItem('dashmeals_mock_orders', JSON.stringify(newAllMock));
        } else {
            setOrders(prev => prev.map(o => o.id === orderId ? { ...o, status: newStatus } : o));
        }
    } catch (err) {
        console.error("Error updating status:", err);
    }
  };

  const addPromotion = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);

    const payload = {
      restaurant_id: restaurant.id,
      media_url: newPromoUrl,
      media_type: newPromoType,
      caption: newPromoCaption
    };

    try {
      const { data, error } = await supabase.from('promotions').insert(payload).select().single();
      if (error) throw error;

      if (data) {
        const newPromo: Promotion = {
          id: data.id,
          restaurantId: restaurant.id,
          mediaUrl: data.media_url,
          mediaType: data.media_type,
          caption: data.caption,
          createdAt: data.created_at
        };
        setPromotions([newPromo, ...promotions]);
        setNewPromoUrl('');
        setNewPromoCaption('');
        setIsAddingPromo(false);
      }
    } catch (err) {
      console.error("Error adding promo:", err);
      // Demo logic
      const mockPromo: Promotion = {
        id: Date.now().toString(),
        restaurantId: restaurant.id,
        mediaUrl: newPromoUrl,
        mediaType: newPromoType,
        caption: newPromoCaption,
        createdAt: new Date().toISOString()
      };
      setPromotions([mockPromo, ...promotions]);
      setNewPromoUrl('');
      setNewPromoCaption('');
      setIsAddingPromo(false);
    } finally {
      setLoading(false);
    }
  };

  const deletePromotion = async (id: string) => {
    if (!confirm("Supprimer cette publicité ?")) return;
    try {
      await supabase.from('promotions').delete().eq('id', id);
      setPromotions(promotions.filter(p => p.id !== id));
    } catch (err) {
      setPromotions(promotions.filter(p => p.id !== id));
    }
  };

  const updateTimes = async () => {
    setUpdatingTimes(true);
    try {
      const newPrep = parseInt(prepTime) || 0;
      const newDeliv = parseInt(deliveryTime) || 0;

      const { error } = await supabase
        .from('restaurants')
        .update({ preparation_time: newPrep, estimated_delivery_time: newDeliv })
        .eq('id', restaurant.id);
      if (error) throw error;

      onUpdateRestaurant({ ...restaurant, preparationTime: newPrep, estimatedDeliveryTime: newDeliv });
      alert("Temps mis à jour !");
    } catch (err) {
        onUpdateRestaurant({ ...restaurant, preparationTime: parseInt(prepTime), estimatedDeliveryTime: parseInt(deliveryTime) });
    } finally { setUpdatingTimes(false); }
  };

  const toggleOpen = async () => {
    try {
      const newState = !restaurant.isOpen;
      const { error } = await supabase.from('restaurants').update({ is_open: newState }).eq('id', restaurant.id);
      if (error) throw error;
      onUpdateRestaurant({ ...restaurant, isOpen: newState });
    } catch (err) {
        onUpdateRestaurant({ ...restaurant, isOpen: !restaurant.isOpen });
    }
  };

  const saveSettings = async (e: React.FormEvent) => {
      e.preventDefault();
      setIsSavingSettings(true);

      let imageUrl = settingsForm.coverImage;

      if (coverImageFile) {
          const uploadedUrl = await uploadImage(coverImageFile);
          if (uploadedUrl) {
              imageUrl = uploadedUrl;
          }
      }

      const updatePayload = {
          name: settingsForm.name,
          description: settingsForm.description,
          cover_image: imageUrl, // Mapping explicite vers la colonne snake_case
          city: settingsForm.city,
          phone_number: settingsForm.phoneNumber // Mapping explicite vers la colonne snake_case
      };

      try {
          const { error } = await supabase.from('restaurants')
            .update(updatePayload)
            .eq('id', restaurant.id);

          if(error) {
              console.error("Supabase Error:", error);
              throw error;
          }

          // Mise à jour de l'état local immédiatement pour reflet UI
          onUpdateRestaurant({ 
              ...restaurant, 
              name: settingsForm.name,
              description: settingsForm.description,
              city: settingsForm.city,
              phoneNumber: settingsForm.phoneNumber,
              coverImage: imageUrl 
          });

          setCoverImageFile(null);
          alert("✅ Paramètres enregistrés avec succès !");
      } catch (err: any) {
          console.error("Error Saving Settings:", err);
          alert(`Erreur de sauvegarde: ${err.message || 'Problème de connexion'}`);
          // On tente quand même de mettre à jour localement si c'est le mode démo/offline
          onUpdateRestaurant({ 
              ...restaurant, 
              name: settingsForm.name,
              description: settingsForm.description,
