    e.preventDefault();
    setLoading(true);

    let urlToUse = newPromoUrl;

    if (promoFile) {
        const uploaded = await uploadImage(promoFile);
        if (uploaded) {
            urlToUse = uploaded;
        } else {
            setLoading(false);
            return;
        }
    }

    if (!urlToUse) {
        alert("Veuillez fournir une URL ou un fichier.");
        setLoading(false);
        return;
    }

    const payload = {
      restaurant_id: restaurant.id,
      media_url: urlToUse,
      media_type: newPromoType,
      caption: newPromoCaption
    };

    try {
      const { data, error } = await supabase.from('promotions').insert(payload).select().single();
      if (error) throw error;

      if (data) {
        const newPromo: Promotion = {
          id: data.id,
          restaurantId: restaurant.id,
          mediaUrl: data.media_url,
          mediaType: data.media_type,
          caption: data.caption,
          createdAt: data.created_at
        };
        setPromotions([newPromo, ...promotions]);
        setNewPromoUrl('');
        setNewPromoCaption('');
        setPromoFile(null);
        setIsAddingPromo(false);
      }
    } catch (err) {
      console.error("Error adding promo:", err);
      // Demo logic
      const mockPromo: Promotion = {
        id: Date.now().toString(),
        restaurantId: restaurant.id,
        mediaUrl: urlToUse,
        mediaType: newPromoType,
        caption: newPromoCaption,
        createdAt: new Date().toISOString()
      };
      setPromotions([mockPromo, ...promotions]);
      setNewPromoUrl('');
      setNewPromoCaption('');
      setPromoFile(null);
      setIsAddingPromo(false);
    } finally {
      setLoading(false);
    }
  };

