                            <label className={`flex items-center space-x-2 cursor-pointer p-3 rounded-xl border ${newPromoType === 'image' ? 'bg-white border-purple-500 text-purple-700' : 'bg-transparent border-transparent'}`}>
                                <input type="radio" name="type" className="hidden" checked={newPromoType === 'image'} onChange={() => { setNewPromoType('image'); setPromoFile(null); setNewPromoUrl(''); }} />
                                <ImageIcon size={20} />
                                <span className="font-bold text-sm">Image</span>
                            </label>
                            <label className={`flex items-center space-x-2 cursor-pointer p-3 rounded-xl border ${newPromoType === 'video' ? 'bg-white border-purple-500 text-purple-700' : 'bg-transparent border-transparent'}`}>
                                <input type="radio" name="type" className="hidden" checked={newPromoType === 'video'} onChange={() => { setNewPromoType('video'); setPromoFile(null); setNewPromoUrl(''); }} />
                                <Video size={20} />
                                <span className="font-bold text-sm">Vidéo (MP4)</span>
                            </label>
                        </div>
                    </div>

                    <div>
                        <label className="block text-xs font-bold text-gray-500 mb-1">Média (Fichier ou URL)</label>

                        <div className="mb-3">
                             <label className={`cursor-pointer bg-white border border-gray-300 hover:bg-gray-50 text-gray-700 px-4 py-4 rounded-xl font-bold flex flex-col items-center justify-center border-dashed border-2 ${promoFile ? 'border-purple-500 bg-purple-50' : ''}`}>
                                <Upload size={24} className={`mb-2 ${promoFile ? 'text-purple-600' : 'text-gray-400'}`}/>
                                <span className="text-sm">{promoFile ? promoFile.name : (newPromoType === 'video' ? 'Cliquez pour téléverser une vidéo' : 'Cliquez pour téléverser une image')}</span>
                                <input 
                                    type="file" 
                                    accept={newPromoType === 'video' ? "video/*" : "image/*"} 
                                    className="hidden" 
                                    onChange={(e) => {
                                        const file = e.target.files?.[0];
                                        if (file) {
                                            setPromoFile(file);
                                            setNewPromoUrl(''); // Clear URL if file selected
                                        }
                                    }} 
                                />
                            </label>
                        </div>

                        <div className="relative flex py-2 items-center">
                            <div className="flex-grow border-t border-gray-300"></div>
                            <span className="flex-shrink-0 mx-4 text-gray-400 text-xs font-bold">OU UTILISER UN LIEN</span>
                            <div className="flex-grow border-t border-gray-300"></div>
                        </div>

                        <input 
                            type="url" 
                            className={`w-full p-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-purple-500 outline-none ${promoFile ? 'bg-gray-100 text-gray-400' : 'bg-white'}`}
                            placeholder={newPromoType === 'video' ? "https://... (Lien vidéo MP4)" : "https://... (Lien image)"}
                            value={newPromoUrl}
                            onChange={e => {
                                setNewPromoUrl(e.target.value);
                                if (e.target.value) setPromoFile(null); // Clear file if URL typed
                            }}
                            disabled={!!promoFile}
                        />
                    </div>

                    <div>
                        <label className="block text-xs font-bold text-gray-500 mb-1">Légende (Optionnel)</label>
                        <input 
                            type="text" 
                            className="w-full p-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-purple-500 outline-none"
                            placeholder="Ex: -50% aujourd'hui seulement !"
                            value={newPromoCaption}
                            onChange={e => setNewPromoCaption(e.target.value)}
                        />
                    </div>

                    <div className="flex justify-end pt-2">
                        <button 
                            type="submit"
                            disabled={loading}
                            className="bg-purple-600 text-white font-bold py-3 px-6 rounded-xl hover:bg-purple-700 shadow-lg flex items-center"
                        >
                            {loading ? 'Publication...' : 'Publier la Story'}
                        </button>
                    </div>
                </div>
            </form>
        )}

        <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
            {promotions.map(promo => (
                <div key={promo.id} className="group relative aspect-[9/16] rounded-2xl overflow-hidden shadow-md bg-black">
                    {promo.mediaType === 'video' ? (
                        <video src={promo.mediaUrl} className="w-full h-full object-cover opacity-80" muted />
                    ) : (
                        <img src={promo.mediaUrl} alt="Promo" className="w-full h-full object-cover opacity-80" />
                    )}

                    <div className="absolute inset-0 bg-gradient-to-t from-black/80 to-transparent flex flex-col justify-end p-4">
                        <p className="text-white font-bold text-sm line-clamp-2 mb-2">{promo.caption || 'Sans légende'}</p>
                        <p className="text-[10px] text-gray-300">{new Date(promo.createdAt).toLocaleDateString()}</p>
                    </div>

                    <button 
                        onClick={() => deletePromotion(promo.id)}
                        className="absolute top-2 right-2 p-2 bg-red-500/80 text-white rounded-full opacity-0 group-hover:opacity-100 transition-opacity hover:bg-red-600"
                    >
                        <Trash2 size={16} />
                    </button>

                    {promo.mediaType === 'video' && (
                        <div className="absolute top-2 left-2 p-1 bg-black/50 rounded text-white">
                            <PlayCircle size={16} />
                        </div>
                    )}
                </div>
            ))}
            {promotions.length === 0 && !isAddingPromo && (
                <div className="col-span-full text-center py-10 bg-white rounded-2xl border border-gray-100">
                    <Megaphone className="mx-auto h-12 w-12 text-gray-300 mb-3" />
                    <p className="text-gray-500">Aucune promotion active.</p>
                    <p className="text-xs text-gray-400">Ajoutez des stories pour attirer plus de clients !</p>
                </div>
            )}
        </div>
    </div>
  );

  return (
    <div className="min-h-screen bg-gray-50 flex">

      {activeChatOrder && (
          <ChatWindow 
            orderId={activeChatOrder.id}
            currentUser={{ id: user.id, role: 'business' }}
            otherUserName={activeChatOrder.customer?.full_name || 'Client'}
            otherUserPhone={activeChatOrder.customer?.phone_number || ''}
            onClose={() => setActiveChatOrder(null)}
          />
      )}

      <aside className="hidden md:flex w-64 flex-col bg-white border-r border-gray-200 h-screen sticky top-0">
          <div className="p-6 border-b border-gray-100">
              <h1 className="text-2xl font-black text-brand-600 tracking-tight">DashPro</h1>
              <p className="text-xs text-gray-500 mt-1">Espace Partenaire</p>
          </div>
          <nav className="flex-1 p-4 space-y-2">
              {renderSidebarItem('overview', <LayoutDashboard size={20}/>, 'Vue d\'ensemble')}
              {renderSidebarItem('orders', <ShoppingBag size={20}/>, 'Commandes')}
              {renderSidebarItem('menu', <Coffee size={20}/>, 'Menu & Carte')}
              {renderSidebarItem('marketing', <Megaphone size={20}/>, 'Marketing')}
              {renderSidebarItem('settings', <Settings size={20}/>, 'Paramètres')}
          </nav>
          <div className="p-4 border-t border-gray-100">
             <button onClick={onLogout} className="w-full flex items-center justify-center space-x-2 text-red-500 hover:bg-red-50 p-2 rounded-lg transition-colors font-medium text-sm">
                  <LogOut size={16} />
                  <span>Déconnexion</span>
              </button>
          </div>
      </aside>

      <div className="md:hidden fixed top-0 left-0 right-0 bg-white border-b border-gray-200 z-50 px-4 py-3 flex justify-between items-center">
          <h1 className="text-xl font-black text-brand-600">DashPro</h1>
          <button onClick={() => setIsSidebarOpen(!isSidebarOpen)} className="p-2 text-gray-600">
             {isSidebarOpen ? <X /> : <LayoutDashboard />}
          </button>
      </div>

      {isSidebarOpen && (
          <div className="md:hidden fixed inset-0 z-40 bg-gray-800/50 backdrop-blur-sm" onClick={() => setIsSidebarOpen(false)}>
              <div className="w-3/4 h-full bg-white p-4 space-y-2 pt-20" onClick={e => e.stopPropagation()}>
                  {renderSidebarItem('overview', <LayoutDashboard size={20}/>, 'Vue d\'ensemble')}
                  {renderSidebarItem('orders', <ShoppingBag size={20}/>, 'Commandes')}
                  {renderSidebarItem('menu', <Coffee size={20}/>, 'Menu & Carte')}
                  {renderSidebarItem('marketing', <Megaphone size={20}/>, 'Marketing')}
                  {renderSidebarItem('settings', <Settings size={20}/>, 'Paramètres')}
                  <button onClick={onLogout} className="w-full flex items-center space-x-3 px-4 py-3 text-red-500 mt-10">
                      <LogOut size={20}/> <span>Déconnexion</span>
                  </button>
              </div>
          </div>
      )}

      <main className="flex-1 p-6 md:p-10 pt-20 md:pt-10 overflow-y-auto">
          {activeView === 'overview' && renderOverview()}
          {activeView === 'orders' && renderOrders()}
          {activeView === 'menu' && renderMenu()}
          {activeView === 'marketing' && renderMarketing()}
          {activeView === 'settings' && renderSettings()}
      </main>

    </div>
  );
};

import React, { useState, useEffect, useMemo } from 'react';
import { MapPin, ShoppingBag, List, Map, Zap, ArrowLeft, Plus, Bike, Footprints, LogOut, Navigation, Search, X, Receipt, Phone, Info } from 'lucide-react';
import { supabase } from '../lib/supabase';
import { KINSHASA_CENTER_LAT, KINSHASA_CENTER_LNG, CITIES_RDC } from '../constants';
import { Restaurant, UserState, ViewMode, MenuItem, CartItem, User, Order, Promotion } from '../types';
import { calculateTime, getDistanceFromLatLonInKm, formatDistance, formatTime } from '../utils/geo';
import { RestaurantCard } from '../components/RestaurantCard';
import { MapView } from '../components/MapView';
import { CartDrawer } from '../components/CartDrawer';
import { ChatWindow } from '../components/ChatWindow';
import { StoryViewer } from '../components/StoryViewer';
import { OrdersView } from '../components/OrdersView';

// Speed constants
const SPEED_WALKING = 5;
const SPEED_MOTO = 30;

interface Props {
  user: User;
  allRestaurants: Restaurant[];
  onLogout: () => void;
}

export const CustomerView: React.FC<Props> = ({ user, allRestaurants, onLogout }) => {
  // State
  const [userState, setUserState] = useState<UserState>({
    location: null,
    locationError: null,
    loadingLocation: true,
  });

  const [restaurants, setRestaurants] = useState<Restaurant[]>([]);
  const [promotionsMap, setPromotionsMap] = useState<Record<string, Promotion[]>>({});

  const [viewMode, setViewMode] = useState<ViewMode>('list');
  const [selectedRestaurant, setSelectedRestaurant] = useState<Restaurant | null>(null);
  const [cart, setCart] = useState<CartItem[]>([]);
  const [isCartOpen, setIsCartOpen] = useState(false);
  const [urgentMode, setUrgentMode] = useState(false);
  const [searchQuery, setSearchQuery] = useState('');
  const [showSuccess, setShowSuccess] = useState(false);
  const [selectedCity, setSelectedCity] = useState<string>(user.city || 'Kinshasa');

  // Order States
  const [orders, setOrders] = useState<Order[]>([]);
  const [isCheckingOut, setIsCheckingOut] = useState(false);

  // Chat State
  const [activeChatOrder, setActiveChatOrder] = useState<Order | null>(null);

  // Story State
  const [activeStoryRestaurant, setActiveStoryRestaurant] = useState<Restaurant | null>(null);

  // Initial Geolocation
  useEffect(() => {
    if (!navigator.geolocation) {
      setUserState({
        location: null,
        locationError: "La géolocalisation n'est pas supportée par votre navigateur",
        loadingLocation: false
      });
      return;
    }

    navigator.geolocation.getCurrentPosition(
      (position) => {
        setUserState({
          location: {
            latitude: position.coords.latitude,
            longitude: position.coords.longitude,
          },
          locationError: null,
          loadingLocation: false
        });
      },
      (error) => {
        console.warn("Geo error:", error);
        setUserState({
            location: {
                latitude: KINSHASA_CENTER_LAT,
                longitude: KINSHASA_CENTER_LNG
            },
            locationError: "Position introuvable. Utilisation de la position par défaut (Kinshasa).",
            loadingLocation: false
        });
      },
      { enableHighAccuracy: true, timeout: 5000, maximumAge: 0 }
    );
  }, []);

  // Update Restaurants when location or database changes
  useEffect(() => {
    if (userState.location) {
      const updatedRestaurants = allRestaurants.map(r => {
        const dist = getDistanceFromLatLonInKm(
          userState.location!.latitude,
          userState.location!.longitude,
          r.latitude,
          r.longitude
        );
        return {
          ...r,
          distance: dist,
          timeWalking: calculateTime(dist, SPEED_WALKING),
          timeMoto: calculateTime(dist, SPEED_MOTO),
        };
      }).sort((a, b) => (a.distance || 0) - (b.distance || 0));

      setRestaurants(updatedRestaurants);
      // Fetch promotions after restaurants are ready
      fetchPromotions(updatedRestaurants);
    } else {
      setRestaurants(allRestaurants);
      fetchPromotions(allRestaurants);
    }
  }, [userState.location, allRestaurants]);

  const fetchPromotions = async (restos: Restaurant[]) => {
      // In a real app, join query is better, but here we simulate or fetch separately
      const { data } = await supabase.from('promotions').select('*').order('created_at', { ascending: false });
      if (data) {
          const mapping: Record<string, Promotion[]> = {};
          data.forEach((p: any) => {
              if (!mapping[p.restaurant_id]) mapping[p.restaurant_id] = [];
              mapping[p.restaurant_id].push({
                  id: p.id,
                  restaurantId: p.restaurant_id,
                  mediaUrl: p.media_url,
                  mediaType: p.media_type,
                  caption: p.caption,
                  createdAt: p.created_at
              });
          });
          setPromotionsMap(mapping);
      }
  };

  // Load Orders when entering 'orders' view
  useEffect(() => {
    if (viewMode === 'orders') {
        fetchOrders();
    }
  }, [viewMode]);

  const fetchOrders = async () => {
    try {
        const { data, error } = await supabase
            .from('orders')
            .select(`*, restaurant:restaurants(name, phone_number)`)
            .eq('user_id', user.id)
            .order('created_at', { ascending: false });

        if (error) {
             const localOrders = localStorage.getItem('dashmeals_mock_orders');
             if (localOrders) setOrders(JSON.parse(localOrders));
             return;
        }

        if (data) {
            setOrders(data.map((o: any) => ({
                id: o.id,
                userId: o.user_id,
                restaurantId: o.restaurant_id,
                status: o.status,
                totalAmount: o.total_amount,
                items: o.items,
                createdAt: o.created_at,
                restaurant: {
                    name: o.restaurant?.name || 'Inconnu',
                    phone_number: o.restaurant?.phone_number
                }
            })));
        }
    } catch (err) {
        console.error("Error fetching orders:", err);
    }
  };

  // Filter Logic (City + Urgent + Search)
  const filteredRestaurants = useMemo(() => {
    let list = restaurants;
    if (selectedCity && selectedCity !== 'Toutes') list = list.filter(r => r.city === selectedCity);
    if (urgentMode) list = list.filter(r => r.isOpen && r.preparationTime <= 20);
    if (searchQuery) {
        const query = searchQuery.toLowerCase();
        list = list.filter(r => 
          r.name.toLowerCase().includes(query) || 
          r.description.toLowerCase().includes(query)
        );
    }
    return list;
  }, [restaurants, urgentMode, selectedCity, searchQuery]);

  // Cart Logic
  const addToCart = (item: MenuItem, restaurant: Restaurant) => {
    if (cart.length > 0 && cart[0].restaurantId !== restaurant.id) {
        if(!window.confirm("Vous ne pouvez commander que dans un restaurant à la fois. Vider le panier actuel ?")) return;
        setCart([]);
    }
    setCart(prev => {
        const existing = prev.find(i => i.id === item.id);
        if (existing) return prev.map(i => i.id === item.id ? { ...i, quantity: i.quantity + 1 } : i);
        return [...prev, { ...item, quantity: 1, restaurantId: restaurant.id, restaurantName: restaurant.name }];
    });
  };

  const removeFromCart = (itemId: string) => {
    setCart(prev => {
        const index = prev.findIndex(i => i.id === itemId);
        if (index > -1) {
            const newArr = [...prev];
            newArr.splice(index, 1);
            return newArr;
        }
        return prev;
    });
  };

  const cartTotal = cart.reduce((sum, item) => sum + (item.price * item.quantity), 0);

  const handleCheckout = async () => {
    if (cart.length === 0) return;
    setIsCheckingOut(true);

    try {
        const { data, error } = await supabase.from('orders').insert({
            user_id: user.id,
            restaurant_id: cart[0].restaurantId,
            status: 'pending',
            total_amount: cartTotal,
            items: cart // Supabase will stringify this automatically for jsonb
        }).select().single();

        if (error) {
            console.error("Erreur commande:", error);
            throw new Error("Impossible d'envoyer la commande. Vérifiez votre connexion.");
        }

        // Success Path
        setIsCartOpen(false);
        setShowSuccess(true);
        setCart([]);

        // Optimistic UI update not needed here as we refetch orders in viewMode change
        setTimeout(() => {
             setShowSuccess(false);
             setViewMode('orders');
             fetchOrders(); // Refresh list from DB
        }, 2000);

    } catch (err: any) {
        alert(err.message || "Erreur inconnue lors de la commande.");
    } finally {
        setIsCheckingOut(false);
    }
  };

  // Views
  if (userState.loadingLocation) {
    return (
      <div className="min-h-screen flex flex-col items-center justify-center bg-brand-50">
        <div className="w-16 h-16 border-4 border-brand-500 border-t-transparent rounded-full animate-spin"></div>
        <p className="mt-4 text-brand-800 font-medium">Localisation en cours...</p>
      </div>
    );
  }

  // Get list of restaurants that have promotions
  const restaurantsWithStories = restaurants.filter(r => promotionsMap[r.id] && promotionsMap[r.id].length > 0);

  return (
    <div className="min-h-screen pb-20 max-w-md mx-auto bg-gray-50 shadow-2xl overflow-hidden relative">

      {/* STORY VIEWER OVERLAY */}
      {activeStoryRestaurant && promotionsMap[activeStoryRestaurant.id] && (
          <StoryViewer 
            restaurant={activeStoryRestaurant}
            promotions={promotionsMap[activeStoryRestaurant.id]}
            onClose={() => setActiveStoryRestaurant(null)}
            onVisitRestaurant={() => {
                setActiveStoryRestaurant(null);
                setSelectedRestaurant(activeStoryRestaurant);
                setViewMode('restaurant_detail');
            }}
          />
      )}

      {/* CHAT OVERLAY */}
      {activeChatOrder && (
          <ChatWindow 
            orderId={activeChatOrder.id}
            currentUser={{ id: user.id, role: 'client' }}
            otherUserName={activeChatOrder.restaurant?.name || 'Restaurant'}
            otherUserPhone={activeChatOrder.restaurant?.phone_number || '+243999999999'}
            onClose={() => setActiveChatOrder(null)}
          />
      )}

      {/* SUCCESS OVERLAY */}
      {showSuccess && (
        <div className="absolute inset-0 z-[60] bg-brand-500 flex flex-col items-center justify-center text-white p-6 text-center animate-fade-in">
           <div className="w-20 h-20 bg-white rounded-full flex items-center justify-center mb-6 shadow-xl">
              <ShoppingBag className="text-brand-500" size={40} />
           </div>
           <h2 className="text-3xl font-bold mb-2">Commande Reçue !</h2>
           <p className="text-brand-100">Votre repas est en préparation.</p>
           <div className="mt-8 bg-white/20 p-4 rounded-xl backdrop-blur-sm">
             <p className="font-mono text-sm">Vous pouvez suivre le statut dans "Commandes"</p>
           </div>
        </div>
      )}

      {/* HEADER */}
      <header className="bg-white sticky top-0 z-30 px-4 py-3 shadow-sm border-b border-gray-100">
        <div className="flex justify-between items-center mb-2">
            <div className="flex items-center">
                <h1 className="text-xl font-black text-brand-600 tracking-tight mr-2">DashMeals</h1>
                <span className="text-xs bg-brand-100 text-brand-800 px-2 py-0.5 rounded-full font-bold">Client</span>
            </div>
          <div className="flex items-center space-x-2">
            <button onClick={() => setIsCartOpen(true)} className="relative p-2 bg-gray-100 rounded-full hover:bg-gray-200 transition-colors">
                <ShoppingBag size={20} className="text-gray-700" />
                {cart.length > 0 && <span className="absolute top-0 right-0 bg-red-500 text-white text-[10px] font-bold h-4 w-4 flex items-center justify-center rounded-full border-2 border-white">{cart.length}</span>}
            </button>
            <button onClick={onLogout} className="p-2 text-gray-400 hover:text-red-500">
                <LogOut size={20} />
            </button>
          </div>
        </div>

        {(viewMode === 'list' || viewMode === 'map') && (
            <div className="flex items-center space-x-2">
                <div className="flex-1 flex items-center text-sm text-gray-500 bg-gray-50 p-2 rounded-lg truncate">
                <MapPin size={14} className="mr-1.5 text-brand-500 flex-shrink-0" />
                <span className="truncate">{userState.locationError ? "Mode Démo" : "Ma Position"}</span>
                </div>
                <select className="bg-brand-50 text-brand-700 text-xs font-bold py-2 pl-2 pr-6 rounded-lg border border-brand-200 outline-none appearance-none" value={selectedCity} onChange={(e) => setSelectedCity(e.target.value)}>
                <option value="Toutes">Toutes les villes</option>
                {CITIES_RDC.map(city => <option key={city} value={city}>{city}</option>)}
                </select>
            </div>
        )}
      </header>

      {/* MAIN CONTENT AREA */}
      <main className="p-4 pt-2">

        {viewMode === 'list' || viewMode === 'map' ? (
            <>
                {/* SEARCH BAR - Moved to Top */}
                <div className="mb-4 relative z-20">
                    <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 text-gray-400" size={18} />
                    <input 
                        type="text"
                        placeholder="Rechercher un restaurant par nom..."
                        className="w-full pl-10 pr-10 py-3 rounded-xl border border-gray-200 focus:ring-2 focus:ring-brand-500 outline-none text-sm bg-white shadow-sm transition-shadow focus:shadow-md"
                        value={searchQuery}
                        onChange={(e) => setSearchQuery(e.target.value)}
                    />
                    {searchQuery && (
                      <button 
                        onClick={() => setSearchQuery('')} 
                        className="absolute right-3 top-1/2 transform -translate-y-1/2 text-gray-400 hover:text-gray-600 p-1"
                      >
                        <X size={16} />
                      </button>
                    )}
                </div>

                {/* STORIES BAR (Professional Look) - Hidden during search */}
                {!searchQuery && restaurantsWithStories.length > 0 && (
                    <div className="mb-6 -mx-4 px-4 overflow-x-auto no-scrollbar">
                        <div className="flex space-x-4">
                            {restaurantsWithStories.map(r => (
                                <button 
                                    key={r.id} 
                                    onClick={() => setActiveStoryRestaurant(r)}
                                    className="flex flex-col items-center space-y-1 min-w-[64px]"
                                >
                                    <div className="w-16 h-16 rounded-full p-[2px] bg-gradient-to-tr from-brand-500 to-yellow-500">
                                        <div className="w-full h-full rounded-full border-2 border-white overflow-hidden">
                                            <img src={r.coverImage} className="w-full h-full object-cover" alt={r.name} />
                                        </div>
                                    </div>
                                    <span className="text-[10px] font-medium text-gray-600 truncate w-full text-center">{r.name}</span>
                                </button>
                            ))}
                        </div>
                    </div>
                )}

                {/* FILTERS */}
                <div className="flex space-x-3 mb-6 overflow-x-auto no-scrollbar pb-1">
                    <button 
                        onClick={() => setUrgentMode(!urgentMode)}
                        className={`flex items-center px-4 py-2 rounded-full font-bold text-sm shadow-sm transition-all border whitespace-nowrap ${urgentMode ? 'bg-red-500 text-white border-red-500 animate-pulse-fast' : 'bg-white text-gray-700 border-gray-200'}`}
                    >
                        <Zap size={16} className={`mr-1 ${urgentMode ? 'fill-white' : 'fill-none'}`} />
                        Urgent - J'ai faim !
                    </button>
