  );
};

import React, { useEffect, useRef, useState } from 'react';
import { Restaurant, Location } from '../types';
import { Navigation, MapPin, Bike, Footprints, Info } from 'lucide-react';
import { formatTime } from '../utils/geo';

interface Props {
  restaurants: Restaurant[];
  userLocation: Location | null;
  onSelect: (r: Restaurant) => void;
}

declare global {
  interface Window {
    google: any;
    googleMapsLoaded: boolean;
  }
}

export const MapView: React.FC<Props> = ({ restaurants, userLocation, onSelect }) => {
  const mapRef = useRef<HTMLDivElement>(null);
  const [map, setMap] = useState<any>(null);
  const [markers, setMarkers] = useState<any[]>([]);
  const [userMarker, setUserMarker] = useState<any>(null);
  const [error, setError] = useState<string | null>(null);

  // Initialisation de la carte
  useEffect(() => {
    const initMap = () => {
      if (!window.google || !mapRef.current) {
         // Si l'API n'est pas encore chargée, on attend un peu ou on signale une erreur si la clé manque
         if(!window.google) {
             setError("Clé API Google Maps manquante ou invalide. Vérifiez index.html.");
         }
         return;
      }

      setError(null);

      const defaultCenter = userLocation 
        ? { lat: userLocation.latitude, lng: userLocation.longitude }
        : { lat: -4.301, lng: 15.301 }; // Kinshasa Center

      const mapInstance = new window.google.maps.Map(mapRef.current, {
        center: defaultCenter,
        zoom: 14,
        disableDefaultUI: true, // App-like feel
        zoomControl: true,
        styles: [
            {
                "featureType": "poi",
                "elementType": "labels.icon",
                "stylers": [{ "visibility": "off" }]
            }
        ]
      });

      setMap(mapInstance);
    };

    if (window.google && window.google.maps) {
      initMap();
    } else {
      window.addEventListener('google-maps-loaded', initMap);
      // Timeout fallback check
      setTimeout(() => {
          if (!window.google) setError("Impossible de charger Google Maps. Vérifiez votre connexion ou la clé API.");
      }, 3000);
    }

    return () => {
      window.removeEventListener('google-maps-loaded', initMap);
    };
  }, []);

  // Mise à jour de la position utilisateur (Point Bleu)
  useEffect(() => {
    if (!map || !window.google) return;

    if (userMarker) userMarker.setMap(null);

    if (userLocation) {
        // Création d'un marqueur style "GPS dot"
        const newUserMarker = new window.google.maps.Marker({
            position: { lat: userLocation.latitude, lng: userLocation.longitude },
            map: map,
            icon: {
                path: window.google.maps.SymbolPath.CIRCLE,
                scale: 8,
                fillColor: "#3B82F6",
                fillOpacity: 1,
                strokeColor: "white",
                strokeWeight: 2,
            },
            title: "Vous êtes ici",
            zIndex: 999
        });

        // Cercle de précision (optionnel, simple cercle bleu transparent)
        new window.google.maps.Circle({
            strokeColor: "#3B82F6",
            strokeOpacity: 0.3,
            strokeWeight: 1,
            fillColor: "#3B82F6",
            fillOpacity: 0.1,
            map: map,
            center: { lat: userLocation.latitude, lng: userLocation.longitude },
            radius: 300 // 300 mètres
        });

        setUserMarker(newUserMarker);
        map.panTo({ lat: userLocation.latitude, lng: userLocation.longitude });
    }
  }, [map, userLocation]);

  // Mise à jour des marqueurs restaurants
  useEffect(() => {
    if (!map || !window.google) return;

    // Nettoyer les anciens marqueurs
    markers.forEach(m => m.setMap(null));
    const newMarkers: any[] = [];

    restaurants.forEach(resto => {
        // Création d'une icône personnalisée (SVG pin)
        const pinColor = resto.isOpen ? "#f97316" : "#9ca3af"; // Orange (Brand) ou Gris
        const pinSvg = {
            path: "M12 2C8.13 2 5 5.13 5 9c0 5.25 7 13 7 13s7-7.75 7-13c0-3.87-3.13-7-7-7zm0 9.5c-1.38 0-2.5-1.12-2.5-2.5s1.12-2.5 2.5-2.5 2.5 1.12 2.5 2.5-1.12 2.5-2.5 2.5z",
            fillColor: pinColor,
            fillOpacity: 1,
            strokeWeight: 1,
            strokeColor: "#FFFFFF",
            scale: 1.5,
            anchor: new window.google.maps.Point(12, 22),
        };

        const marker = new window.google.maps.Marker({
            position: { lat: resto.latitude, lng: resto.longitude },
            map: map,
            icon: pinSvg,
            title: resto.name,
            animation: window.google.maps.Animation.DROP
        });

        // InfoWindow pour afficher les détails au clic sur le marqueur
        const contentString = `
            <div style="padding: 4px; max-width: 200px;">
                <h3 style="margin: 0; font-weight: bold; color: #1f2937; font-size: 14px;">${resto.name}</h3>
                <p style="margin: 4px 0; color: #6b7280; font-size: 11px;">${resto.isOpen ? '<span style="color:green">Ouvert</span>' : '<span style="color:red">Fermé</span>'} • ${resto.rating} ★</p>
                <div style="display: flex; gap: 8px; font-size: 10px; margin-top: 4px; color: #4b5563;">
                    ${resto.timeMoto ? `<span>🏍️ ${formatTime(resto.timeMoto)}</span>` : ''}
                    ${resto.timeWalking ? `<span>👣 ${formatTime(resto.timeWalking)}</span>` : ''}
                </div>
            </div>
        `;

        const infoWindow = new window.google.maps.InfoWindow({
            content: contentString,
        });

        marker.addListener("click", () => {
            infoWindow.open({
                anchor: marker,
                map,
                shouldFocus: false,
            });
            // Sélectionner le restaurant dans l'app React
            onSelect(resto);
        });

        newMarkers.push(marker);
    });

    setMarkers(newMarkers);

  }, [map, restaurants]);

  return (
    <div className="relative w-full h-[calc(100vh-180px)] rounded-xl overflow-hidden border border-gray-300 bg-gray-200">

      {/* Container de la carte */}
      <div ref={mapRef} className="w-full h-full" />

      {/* Message d'erreur si pas de clé API */}
      {error && (
        <div className="absolute inset-0 flex items-center justify-center bg-gray-100 p-6 text-center z-50">
           <div>
               <Info size={48} className="mx-auto text-red-500 mb-2"/>
               <h3 className="font-bold text-gray-800">Configuration Requise</h3>
               <p className="text-sm text-gray-600 mt-2">{error}</p>
               <p className="text-xs text-gray-500 mt-4 bg-white p-2 rounded border">
                   Ajoutez votre clé dans <code>index.html</code>
               </p>
           </div>
        </div>
      )}

      {/* Bouton de recentrage */}
      <button 
        onClick={() => {
            if (map && userLocation) {
                map.panTo({ lat: userLocation.latitude, lng: userLocation.longitude });
                map.setZoom(15);
            }
        }}
        className="absolute bottom-6 right-4 bg-white p-3 rounded-full shadow-lg text-brand-600 hover:bg-brand-50 transition-colors z-10"
      >
        <Navigation size={20} className={userLocation ? "fill-current" : ""} />
      </button>

      {/* Légende rapide */}
      <div className="absolute top-4 left-4 bg-white/90 backdrop-blur-md px-3 py-2 rounded-lg shadow-md z-10 text-xs">
          <div className="flex items-center space-x-2 mb-1">
              <span className="w-3 h-3 rounded-full bg-blue-500 border border-white"></span>
              <span className="text-gray-700 font-bold">Moi</span>
          </div>
          <div className="flex items-center space-x-2">
              <span className="w-3 h-3 rounded-full bg-brand-500 border border-white"></span>
              <span className="text-gray-700 font-bold">Restaurant</span>
          </div>
      </div>
    </div>
  );
};

import React, { useEffect, useState } from 'react';
import { MapContainer, TileLayer, Marker, Popup, useMap } from 'react-leaflet';
import L from 'leaflet';
import { Restaurant, Location } from '../types';
import { Navigation, Info, Bike, Footprints } from 'lucide-react';
import { formatTime } from '../utils/geo';

// On fixe les icônes par défaut de Leaflet qui buggent souvent avec les imports ESM/Webpack
// Nous utiliserons plutôt des L.divIcon personnalisés pour un look moderne

interface Props {
  restaurants: Restaurant[];
  userLocation: Location | null;
  onSelect: (r: Restaurant) => void;
}

// Composant utilitaire pour recentrer la carte
const RecenterMap = ({ center }: { center: Location }) => {
  const map = useMap();
  useEffect(() => {
    map.flyTo([center.latitude, center.longitude], 15, {
        animate: true,
        duration: 1.5
    });
  }, [center, map]);
  return null;
};

export const MapView: React.FC<Props> = ({ restaurants, userLocation, onSelect }) => {
  const [mapCenter, setMapCenter] = useState<Location>({ latitude: -4.301, longitude: 15.301 }); // Kinshasa par défaut

  useEffect(() => {
    if (userLocation) {
      setMapCenter(userLocation);
    }
  }, [userLocation]);

  // Icône Utilisateur (Point bleu pulsant)
  const userIcon = L.divIcon({
    className: 'custom-user-icon',
    html: `
      <div class="relative flex items-center justify-center w-6 h-6">
        <span class="animate-ping absolute inline-flex h-full w-full rounded-full bg-blue-400 opacity-75"></span>
        <span class="relative inline-flex rounded-full h-4 w-4 bg-blue-600 border-2 border-white shadow-lg"></span>
      </div>
    `,
    iconSize: [24, 24],
    iconAnchor: [12, 12]
  });

  // Icône Restaurant (Pin Orange SVG)
  const createRestoIcon = (isOpen: boolean) => L.divIcon({
    className: 'custom-resto-icon',
    html: `
      <div class="relative w-8 h-8 flex flex-col items-center justify-center transition-transform hover:scale-110">
        <svg viewBox="0 0 24 24" fill="${isOpen ? '#ea580c' : '#9ca3af'}" stroke="white" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" class="w-8 h-8 drop-shadow-md">
          <path d="M21 10c0 7-9 13-9 13s-9-6-9-13a9 9 0 0 1 18 0z"></path>
          <circle cx="12" cy="10" r="3" fill="white"></circle>
        </svg>
      </div>
    `,
    iconSize: [32, 32],
    iconAnchor: [16, 32], // La pointe du pin est en bas au centre
    popupAnchor: [0, -32]
  });

  return (
    <div className="relative w-full h-[calc(100vh-180px)] rounded-xl overflow-hidden border border-gray-300 bg-gray-100 z-0">

      <MapContainer 
        center={[mapCenter.latitude, mapCenter.longitude]} 
        zoom={14} 
        scrollWheelZoom={true} 
        style={{ height: '100%', width: '100%' }}
        zoomControl={false} // On cache le zoom par défaut pour un look plus "App"
      >
        <TileLayer
          attribution='&copy; <a href="https://www.openstreetmap.org/copyright">OSM</a>'
          url="https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png"
        />

        {/* Composant pour gérer le recentrage programmatique */}
        <RecenterMap center={mapCenter} />

        {/* Marqueur Utilisateur */}
        {userLocation && (
          <Marker position={[userLocation.latitude, userLocation.longitude]} icon={userIcon}>
             <Popup closeButton={false} offset={[0, -10]}>
                <span className="font-bold text-blue-600">Vous êtes ici</span>
             </Popup>
          </Marker>
        )}

        {/* Marqueurs Restaurants */}
        {restaurants.map((resto) => (
          <Marker 
            key={resto.id} 
            position={[resto.latitude, resto.longitude]} 
            icon={createRestoIcon(resto.isOpen)}
            eventHandlers={{
                click: () => onSelect(resto), // Sélectionne le resto au clic sur le pin
            }}
          >
            <Popup className="rounded-xl overflow-hidden p-0 shadow-lg">
              <div 
                className="w-48 cursor-pointer"
                onClick={() => onSelect(resto)}
              >
                 <div className="relative h-24 bg-gray-200">
                    <img src={resto.coverImage} className="w-full h-full object-cover rounded-t-lg" alt={resto.name} />
                    <span className={`absolute top-2 right-2 text-[10px] font-bold px-2 py-0.5 rounded-full text-white ${resto.isOpen ? 'bg-green-500' : 'bg-red-500'}`}>
