          </div>
      </div>

    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { supabase } from '../lib/supabase';
import { User, UserRole, BusinessType } from '../types';
import { CITIES_RDC } from '../constants';
import { User as UserIcon, Store, AlertCircle, MapPin, Mail, Phone } from 'lucide-react';

interface Props {
  onLogin: (user: User, businessData?: any) => void;
}

export const AuthScreen: React.FC<Props> = ({ onLogin }) => {
  const [isLogin, setIsLogin] = useState(true);
  const [role, setRole] = useState<UserRole>('client');
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  // Form States
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [name, setName] = useState('');
  const [phone, setPhone] = useState('');
  const [city, setCity] = useState('Kinshasa');
  const [availableCities, setAvailableCities] = useState<string[]>(CITIES_RDC);

  // Business Specific States
  const [businessType, setBusinessType] = useState<BusinessType>('restaurant');
  const [businessName, setBusinessName] = useState('');

  // Fetch cities from DB on mount
  useEffect(() => {
    const fetchCities = async () => {
      try {
        const { data, error } = await supabase
          .from('cities')
          .select('name')
          .eq('is_active', true)
          .order('name');

        if (!error && data && data.length > 0) {
          setAvailableCities(data.map(c => c.name));
        }
      } catch (err) {
        console.warn("Could not fetch cities from DB, using defaults");
      }
    };
    fetchCities();
  }, []);

  const handleOAuthLogin = async (provider: 'google' | 'facebook') => {
    setLoading(true);
    setError(null);
    try {
      localStorage.setItem('dashmeals_pending_auth', JSON.stringify({ 
          role, 
          city,
      }));

      const { error } = await supabase.auth.signInWithOAuth({
        provider: provider,
        options: {
          redirectTo: window.location.origin,
          queryParams: {
            access_type: 'offline',
            prompt: 'consent',
          }
        }
      });
      if (error) throw error;
    } catch (err: any) {
      console.error("OAuth Error:", err);
      setError(err.message || "Erreur de connexion sociale");
      setLoading(false);
    }
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (loading) return;

    setLoading(true);
    setError(null);

    try {
      if (isLogin) {
        // LOGIN
        const { error } = await supabase.auth.signInWithPassword({
          email,
          password,
        });
        if (error) throw error;
      } else {
        // SIGN UP
        // 1. Create Auth User
        const { data: authData, error: authError } = await supabase.auth.signUp({
          email,
          password,
          options: {
            data: { full_name: name, role: role, city: city }, // Metadata fallback
          }
        });

        if (authError) throw authError;

        if (authData.user) {
          // 2. Create Profile in DB with phone number explicitely
          // We wait for this to finish to ensure consistency
          const { error: profileError } = await supabase.from('profiles').insert({
            id: authData.user.id,
            role: role,
            full_name: name,
            city: city,
            phone_number: phone
          });

          if (profileError) {
             console.error("Erreur création profil:", profileError);
             // On ne bloque pas tout si le profil échoue (peut-être déjà créé par trigger), 
             // mais on loggue l'erreur.
             if (!profileError.message.includes('duplicate key')) {
                 throw new Error("Erreur lors de la création du profil utilisateur.");
             }
          }

          // 3. If Business, Create Restaurant
          if (role === 'business') {
            const { error: restoError } = await supabase.from('restaurants').insert({
              owner_id: authData.user.id,
              name: businessName,
              type: businessType,
              city: city, 
              latitude: -4.301 + (Math.random() - 0.5) * 0.02, 
              longitude: 15.301 + (Math.random() - 0.5) * 0.02,
              description: `Bienvenue chez ${businessName}`,
              cover_image: `https://picsum.photos/800/600?random=${Date.now()}`,
              preparation_time: 30,
              estimated_delivery_time: 30,
              phone_number: phone // Set restaurant phone number to owner's phone initially
            });
            if (restoError) {
                console.warn("Restaurant creation warning:", restoError);
            }
          }

          // Si inscription réussie mais pas de session auto (ex: email confirm), on prévient
          if (!authData.session) {
              setError("Compte créé ! Veuillez vérifier vos emails pour confirmer votre adresse avant de vous connecter.");
              setIsLogin(true);
              setLoading(false);
              return;
          }
        }
      }
    } catch (err: any) {
      console.error("Auth Error:", err);
      let message = err.message || "Une erreur est survenue";
      const lowerMsg = message.toLowerCase();

      // MAPPING DES ERREURS SUPABASE
      if (lowerMsg.includes("rate limit") || lowerMsg.includes("too many requests")) {
        message = "Trop de tentatives de connexion. Pour votre sécurité, veuillez patienter quelques minutes avant de réessayer.";
      } else if (lowerMsg.includes("invalid login credentials")) {
        message = "Email ou mot de passe incorrect. Vérifiez vos identifiants.";
      } else if (lowerMsg.includes("email not confirmed")) {
        message = "Votre adresse email n'a pas encore été confirmée. Veuillez vérifier votre boîte de réception (et vos spams).";
      } else if (lowerMsg.includes("user already registered") || lowerMsg.includes("already exists")) {
        message = "Cette adresse email est déjà associée à un compte. Essayez de vous connecter.";
      } else if (lowerMsg.includes("password should be at least")) {
        message = "Le mot de passe est trop court. Il doit contenir au moins 6 caractères.";
      } else if (lowerMsg.includes("fetch failed") || lowerMsg.includes("network request failed")) {
        message = "Problème de connexion internet. Vérifiez votre réseau.";
      }

      setError(message);
      setLoading(false);
    }
  };

  return (
    <div className="min-h-screen bg-brand-50 flex flex-col items-center justify-center p-4">
      <div className="bg-white w-full max-w-md rounded-2xl shadow-xl overflow-hidden">

        {/* Header */}
        <div className="bg-brand-600 p-6 text-center">
          <h1 className="text-3xl font-black text-white tracking-tight">DashMeals<span className="text-brand-200 text-xs font-normal ml-1">RDC</span></h1>
          <p className="text-brand-100 mt-2">La plateforme gourmande de Kinshasa</p>
        </div>

        {/* Tabs */}
        <div className="flex border-b">
          <button 
            type="button"
            onClick={() => setRole('client')}
            className={`flex-1 py-4 text-sm font-bold flex items-center justify-center ${role === 'client' ? 'text-brand-600 border-b-2 border-brand-600 bg-brand-50' : 'text-gray-500'}`}
          >
            <UserIcon size={18} className="mr-2" />
            Client
          </button>
          <button 
            type="button"
            onClick={() => setRole('business')}
            className={`flex-1 py-4 text-sm font-bold flex items-center justify-center ${role === 'business' ? 'text-brand-600 border-b-2 border-brand-600 bg-brand-50' : 'text-gray-500'}`}
          >
            <Store size={18} className="mr-2" />
            Entreprise
          </button>
        </div>

        <div className="p-6 pb-2">
            <h2 className="text-xl font-bold text-gray-800 text-center mb-6">
                {isLogin ? 'Connexion' : 'Créer un compte'} {role === 'business' ? 'Partenaire' : ''}
            </h2>

            {/* Social Login Buttons */}
            <div className="grid grid-cols-2 gap-3 mb-6">
                <button 
                    type="button"
                    onClick={() => handleOAuthLogin('google')}
                    className="flex items-center justify-center py-2.5 px-4 border border-gray-300 rounded-lg hover:bg-gray-50 transition-colors bg-white text-gray-700 font-bold text-sm"
                >
                    Google
                </button>
                <button 
                    type="button"
                    onClick={() => handleOAuthLogin('facebook')}
                    className="flex items-center justify-center py-2.5 px-4 border border-gray-300 rounded-lg hover:bg-[#1877F2] hover:text-white hover:border-[#1877F2] transition-colors bg-white text-gray-700 font-bold text-sm"
                >
                    Facebook
                </button>
            </div>

            <div className="relative flex items-center justify-center mb-6">
                <hr className="w-full border-gray-300" />
                <span className="absolute bg-white px-3 text-xs text-gray-500 font-medium">OU AVEC EMAIL</span>
            </div>
        </div>

        {/* Form */}
        <form onSubmit={handleSubmit} className="px-6 pb-6 space-y-4">

          {error && (
            <div className="bg-red-50 border border-red-100 text-red-600 p-4 rounded-xl text-sm animate-pulse flex items-start shadow-sm">
                 <AlertCircle size={18} className="mr-2 flex-shrink-0 mt-0.5" />
                 <span className="font-medium leading-tight">{error}</span>
            </div>
          )}

          {!isLogin && (
            <div>
              <label className="block text-xs font-bold text-gray-600 mb-1">Votre Nom complet</label>
              <input 
                type="text" 
                required 
                className="w-full p-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-brand-500 outline-none"
                placeholder="Ex: Jean K."
                value={name}
                onChange={(e) => setName(e.target.value)}
              />
            </div>
          )}

           {/* Phone Number Field */}
           {!isLogin && (
            <div>
              <label className="block text-xs font-bold text-gray-600 mb-1">Numéro de téléphone</label>
              <div className="relative">
                <Phone size={16} className="absolute left-3 top-1/2 transform -translate-y-1/2 text-gray-400" />
                <input 
                    type="tel" 
                    required 
                    className="w-full p-3 pl-10 border border-gray-300 rounded-lg focus:ring-2 focus:ring-brand-500 outline-none"
                    placeholder="Ex: 0812345678"
                    value={phone}
                    onChange={(e) => setPhone(e.target.value)}
                />
              </div>
            </div>
          )}

          {/* City Selection for both Roles during Signup */}
          {!isLogin && (
             <div>
                <label className="block text-xs font-bold text-gray-600 mb-1 flex items-center">
                  <MapPin size={12} className="mr-1"/> 
                  {role === 'business' ? 'Ville du commerce' : 'Votre Ville'}
                </label>
                <select 
                  className="w-full p-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-brand-500 outline-none bg-white text-gray-900"
                  value={city}
                  onChange={(e) => setCity(e.target.value)}
                >
                  {availableCities.map(c => (
                    <option key={c} value={c} className="text-gray-900">{c}</option>
                  ))}
                </select>
             </div>
          )}

          {/* Business Specific Fields during Signup */}
          {!isLogin && role === 'business' && (
            <div className="bg-gray-50 p-4 rounded-lg border border-gray-200 space-y-3">
              <h3 className="text-sm font-bold text-gray-700 flex items-center"><Store size={14} className="mr-2"/> Infos Établissement</h3>
              <div>
                <label className="block text-xs font-bold text-gray-500 mb-1">Nom du commerce</label>
                <input 
                  type="text" 
                  required 
                  className="w-full p-2 border border-gray-300 rounded focus:ring-1 focus:ring-brand-500 outline-none"
                  placeholder="Ex: Chez Ntemba"
                  value={businessName}
                  onChange={(e) => setBusinessName(e.target.value)}
                />
              </div>
              <div>
                <label className="block text-xs font-bold text-gray-500 mb-1">Type</label>
                <select 
                  className="w-full p-2 border border-gray-300 rounded bg-white text-gray-900"
                  value={businessType}
                  onChange={(e) => setBusinessType(e.target.value as BusinessType)}
                >
                  <option value="restaurant" className="text-gray-900">Restaurant</option>
                  <option value="bar" className="text-gray-900">Bar / Lounge</option>
                  <option value="terrasse" className="text-gray-900">Terrasse</option>
                  <option value="snack" className="text-gray-900">Snack / Fast-food</option>
                </select>
              </div>
            </div>
          )}

          <div>
            <label className="block text-xs font-bold text-gray-600 mb-1">Email</label>
            <input 
              type="email" 
              required 
              className="w-full p-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-brand-500 outline-none"
              placeholder="Ex: nom@mail.com"
              value={email}
              onChange={(e) => setEmail(e.target.value)}
            />
          </div>

          <div>
            <label className="block text-xs font-bold text-gray-600 mb-1">Mot de passe</label>
            <input 
              type="password" 
              required 
              className="w-full p-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-brand-500 outline-none"
              placeholder="••••••••"
              value={password}
              onChange={(e) => setPassword(e.target.value)}
            />
          </div>

          <button 
            type="submit"
            disabled={loading}
            className={`w-full bg-brand-600 hover:bg-brand-700 text-white font-bold py-3 rounded-xl shadow-lg transition-transform active:scale-95 mt-4 flex justify-center items-center ${loading ? 'opacity-70 cursor-not-allowed' : ''}`}
          >
            {loading ? <div className="w-5 h-5 border-2 border-white border-t-transparent rounded-full animate-spin"></div> : (isLogin ? 'Se connecter' : "S'inscrire")}
          </button>
        </form>

        <div className="bg-gray-50 p-4 text-center border-t">
          <button 
            type="button"
            onClick={() => {
                setIsLogin(!isLogin);
                setError(null);
            }}
            className="text-sm text-brand-600 font-bold hover:underline"
          >
            {isLogin ? "Pas de compte ? S'inscrire" : "Déjà inscrit ? Se connecter"}
          </button>
        </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect, useMemo } from 'react';
import { MapPin, ShoppingBag, List, Map, Zap, ArrowLeft, Plus, Bike, Footprints, LogOut, Navigation, Search, X, Receipt, Phone, Info, Image as ImageIcon, PlayCircle } from 'lucide-react';
import { supabase } from '../lib/supabase';
import { KINSHASA_CENTER_LAT, KINSHASA_CENTER_LNG, CITIES_RDC } from '../constants';
import { Restaurant, UserState, ViewMode, MenuItem, CartItem, User, Order, Promotion } from '../types';
import { calculateTime, getDistanceFromLatLonInKm, formatDistance, formatTime } from '../utils/geo';
import { RestaurantCard } from '../components/RestaurantCard';
import { MapView } from '../components/MapView';
import { CartDrawer } from '../components/CartDrawer';
import { ChatWindow } from '../components/ChatWindow';
import { StoryViewer } from '../components/StoryViewer';
import { OrdersView } from '../components/OrdersView';

// Speed constants
const SPEED_WALKING = 5;
const SPEED_MOTO = 30;

interface Props {
  user: User;
  allRestaurants: Restaurant[];
  onLogout: () => void;
}

export const CustomerView: React.FC<Props> = ({ user, allRestaurants, onLogout }) => {
  // State
  const [userState, setUserState] = useState<UserState>({
    location: null,
    locationError: null,
    loadingLocation: true,
  });

  const [restaurants, setRestaurants] = useState<Restaurant[]>([]);
  const [promotionsMap, setPromotionsMap] = useState<Record<string, Promotion[]>>({});

  const [viewMode, setViewMode] = useState<ViewMode>('list');
  const [selectedRestaurant, setSelectedRestaurant] = useState<Restaurant | null>(null);
  const [cart, setCart] = useState<CartItem[]>([]);
  const [isCartOpen, setIsCartOpen] = useState(false);
  const [urgentMode, setUrgentMode] = useState(false);
  const [searchQuery, setSearchQuery] = useState('');
  const [showSuccess, setShowSuccess] = useState(false);
  const [selectedCity, setSelectedCity] = useState<string>(user.city || 'Kinshasa');

  // Order States
  const [orders, setOrders] = useState<Order[]>([]);
  const [isCheckingOut, setIsCheckingOut] = useState(false);

  // Chat State
  const [activeChatOrder, setActiveChatOrder] = useState<Order | null>(null);

  // Story State
  const [activeStoryRestaurant, setActiveStoryRestaurant] = useState<Restaurant | null>(null);
  const [storyStartIndex, setStoryStartIndex] = useState(0);

  // Initial Geolocation
  useEffect(() => {
    if (!navigator.geolocation) {
      setUserState({
        location: null,
        locationError: "La géolocalisation n'est pas supportée par votre navigateur",
        loadingLocation: false
      });
      return;
    }

    navigator.geolocation.getCurrentPosition(
      (position) => {
        setUserState({
          location: {
            latitude: position.coords.latitude,
            longitude: position.coords.longitude,
          },
          locationError: null,
          loadingLocation: false
        });
      },
      (error) => {
        console.warn("Geo error:", error);
        setUserState({
            location: {
                latitude: KINSHASA_CENTER_LAT,
                longitude: KINSHASA_CENTER_LNG
            },
            locationError: "Position introuvable. Utilisation de la position par défaut (Kinshasa).",
            loadingLocation: false
        });
      },
      { enableHighAccuracy: true, timeout: 5000, maximumAge: 0 }
    );
  }, []);

  // Update Restaurants when location or database changes
  useEffect(() => {
    if (userState.location) {
      const updatedRestaurants = allRestaurants.map(r => {
        const dist = getDistanceFromLatLonInKm(
          userState.location!.latitude,
          userState.location!.longitude,
          r.latitude,
          r.longitude
        );
        return {
          ...r,
          distance: dist,
          timeWalking: calculateTime(dist, SPEED_WALKING),
          timeMoto: calculateTime(dist, SPEED_MOTO),
        };
      }).sort((a, b) => (a.distance || 0) - (b.distance || 0));

      setRestaurants(updatedRestaurants);
      // Fetch promotions after restaurants are ready
      fetchPromotions(updatedRestaurants);
    } else {
      setRestaurants(allRestaurants);
      fetchPromotions(allRestaurants);
    }
  }, [userState.location, allRestaurants]);

  const fetchPromotions = async (restos: Restaurant[]) => {
      // In a real app, join query is better, but here we simulate or fetch separately
      const { data } = await supabase.from('promotions').select('*').order('created_at', { ascending: false });
      if (data) {
          const mapping: Record<string, Promotion[]> = {};
          data.forEach((p: any) => {
              if (!mapping[p.restaurant_id]) mapping[p.restaurant_id] = [];
              mapping[p.restaurant_id].push({
                  id: p.id,
                  restaurantId: p.restaurant_id,
                  mediaUrl: p.media_url,
                  mediaType: p.media_type,
                  caption: p.caption,
                  createdAt: p.created_at
              });
          });
          setPromotionsMap(mapping);
      }
  };

  // Load Orders when entering 'orders' view
  useEffect(() => {
    if (viewMode === 'orders') {
        fetchOrders();
    }
  }, [viewMode]);

  const fetchOrders = async () => {
    try {
        const { data, error } = await supabase
            .from('orders')
            .select(`*, restaurant:restaurants(name, phone_number)`)
            .eq('user_id', user.id)
            .order('created_at', { ascending: false });

        if (error) {
             const localOrders = localStorage.getItem('dashmeals_mock_orders');
             if (localOrders) setOrders(JSON.parse(localOrders));
             return;
        }

        if (data) {
            setOrders(data.map((o: any) => ({
                id: o.id,
                userId: o.user_id,
                restaurantId: o.restaurant_id,
                status: o.status,
                totalAmount: o.total_amount,
                items: o.items,
                createdAt: o.created_at,
                restaurant: {
                    name: o.restaurant?.name || 'Inconnu',
                    phone_number: o.restaurant?.phone_number
                }
            })));
        }
    } catch (err) {
        console.error("Error fetching orders:", err);
    }
  };

  // Filter Logic (City + Urgent + Search)
  const filteredRestaurants = useMemo(() => {
    let list = restaurants;
    if (selectedCity && selectedCity !== 'Toutes') list = list.filter(r => r.city === selectedCity);
    if (urgentMode) list = list.filter(r => r.isOpen && r.preparationTime <= 20);
    if (searchQuery) {
        const query = searchQuery.toLowerCase();
        list = list.filter(r => 
          r.name.toLowerCase().includes(query) || 
          r.description.toLowerCase().includes(query)
        );
    }
    return list;
  }, [restaurants, urgentMode, selectedCity, searchQuery]);

  // Cart Logic
  const addToCart = (item: MenuItem, restaurant: Restaurant) => {
    if (cart.length > 0 && cart[0].restaurantId !== restaurant.id) {
        if(!window.confirm("Vous ne pouvez commander que dans un restaurant à la fois. Vider le panier actuel ?")) return;
        setCart([]);
    }
    setCart(prev => {
        const existing = prev.find(i => i.id === item.id);
        if (existing) return prev.map(i => i.id === item.id ? { ...i, quantity: i.quantity + 1 } : i);
        return [...prev, { ...item, quantity: 1, restaurantId: restaurant.id, restaurantName: restaurant.name }];
    });
  };

  const removeFromCart = (itemId: string) => {
    setCart(prev => {
        const index = prev.findIndex(i => i.id === itemId);
        if (index > -1) {
            const newArr = [...prev];
            newArr.splice(index, 1);
            return newArr;
        }
        return prev;
    });
  };

  const cartTotal = cart.reduce((sum, item) => sum + (item.price * item.quantity), 0);

  const handleCheckout = async () => {
    if (cart.length === 0) return;
    setIsCheckingOut(true);

    try {
        const { data, error } = await supabase.from('orders').insert({
            user_id: user.id,
            restaurant_id: cart[0].restaurantId,
            status: 'pending',
            total_amount: cartTotal,
            items: cart // Supabase will stringify this automatically for jsonb
        }).select().single();

        if (error) {
            console.error("Erreur commande:", error);
            throw new Error("Impossible d'envoyer la commande. Vérifiez votre connexion.");
        }

        // Success Path
        setIsCartOpen(false);
        setShowSuccess(true);
        setCart([]);

        // Optimistic UI update not needed here as we refetch orders in viewMode change
        setTimeout(() => {
             setShowSuccess(false);
             setViewMode('orders');
             fetchOrders(); // Refresh list from DB
        }, 2000);

    } catch (err: any) {
        alert(err.message || "Erreur inconnue lors de la commande.");
    } finally {
        setIsCheckingOut(false);
    }
  };

  // Views
  if (userState.loadingLocation) {
    return (
      <div className="min-h-screen flex flex-col items-center justify-center bg-brand-50">
        <div className="w-16 h-16 border-4 border-brand-500 border-t-transparent rounded-full animate-spin"></div>
