                        <div className="grid grid-cols-3 gap-2">
                            {promotionsMap[selectedRestaurant.id].map((item, idx) => (
                                <button
                                    key={item.id}
                                    onClick={() => {
                                        setStoryStartIndex(idx);
                                        setActiveStoryRestaurant(selectedRestaurant);
