import React from 'react';
import { Receipt, ShoppingBag, Phone, MessageSquare, CheckCircle2, Circle, Bike, ChefHat, Clock } from 'lucide-react';
import { Order, OrderStatus } from '../types';

interface Props {
  orders: Order[];
  onChat: (order: Order) => void;
  onBrowse: () => void;
}

export const OrdersView: React.FC<Props> = ({ orders, onChat, onBrowse }) => {
  const getStatusColor = (status: string) => {
    switch (status) {
        case 'pending': return 'bg-gray-100 text-gray-700';
        case 'preparing': return 'bg-yellow-100 text-yellow-800';
        case 'ready': return 'bg-blue-100 text-blue-800';
        case 'delivering': return 'bg-orange-100 text-orange-800';
        case 'completed': return 'bg-green-100 text-green-800';
        case 'cancelled': return 'bg-red-100 text-red-800';
        default: return 'bg-gray-100';
    }
  };

  const getStatusLabel = (status: string) => {
    switch (status) {
        case 'pending': return 'En attente';
        case 'preparing': return 'En cuisine';
        case 'ready': return 'Prêt';
        case 'delivering': return 'En livraison';
        case 'completed': return 'Livré';
        case 'cancelled': return 'Annulé';
        default: return status;
    }
  };

  // Composant interne pour une étape de la timeline
  const TimelineStep = ({ 
      active, 
      completed, 
      icon: Icon, 
      title, 
      isLast = false 
  }: { active: boolean, completed: boolean, icon: any, title: string, isLast?: boolean }) => (
      <div className="flex relative pb-6">
          {!isLast && (
              <div className={`absolute left-3 top-6 bottom-0 w-0.5 ${completed ? 'bg-brand-500' : 'bg-gray-200'}`}></div>
          )}
          <div className={`relative z-10 w-6 h-6 rounded-full flex items-center justify-center border-2 mr-4 flex-shrink-0 ${
              active || completed 
              ? 'bg-brand-500 border-brand-500 text-white shadow-md shadow-brand-200' 
              : 'bg-white border-gray-300 text-gray-300'
          }`}>
              <Icon size={12} />
          </div>
          <div>
              <p className={`text-xs font-bold ${active || completed ? 'text-gray-900' : 'text-gray-400'}`}>{title}</p>
              {active && <p className="text-[10px] text-brand-600 font-medium animate-pulse">En cours...</p>}
          </div>
      </div>
  );

  return (
    <div className="animate-in slide-in-from-right duration-300 pb-20">
        <h2 className="text-xl font-black text-gray-800 mb-4 flex items-center">
            <Receipt className="mr-2 text-brand-600"/> Historique
        </h2>
        {orders.length === 0 ? (
            <div className="text-center text-gray-400 py-10">
                <ShoppingBag size={48} className="mx-auto mb-2 opacity-20"/>
                <p>Aucune commande effectuée.</p>
                <button onClick={onBrowse} className="mt-4 text-brand-600 font-bold underline">Commander un plat</button>
            </div>
        ) : (
            <div className="space-y-6">
                {orders.map(order => {
                   const isCompleted = order.status === 'completed';
                   const isCancelled = order.status === 'cancelled';

                   // Déterminer l'état pour la timeline
                   const s = order.status;
                   const isPending = s === 'pending';
                   const isPrep = s === 'preparing';
                   const isReady = s === 'ready';
                   const isDelivering = s === 'delivering';

                   // Logique un peu verbeuse pour la démo, mais claire
                   const step1Complete = !isPending && !isCancelled;
                   const step2Complete = (isReady || isDelivering || isCompleted) && !isCancelled;
                   const step3Complete = (isDelivering || isCompleted) && !isCancelled;
                   const step4Complete = isCompleted && !isCancelled;

                   return (
                    <div key={order.id} className="bg-white rounded-xl shadow-sm border border-gray-100 overflow-hidden">
                        {/* Header de la carte */}
                        <div className="p-4 border-b border-gray-50 bg-gray-50/50">
                            <div className="flex justify-between items-start mb-1">
                                <div>
                                    <h3 className="font-bold text-gray-800 text-lg">{order.restaurant?.name || 'Restaurant inconnu'}</h3>
                                    <p className="text-xs text-gray-400">Commande #{order.id.slice(0,6)} • {new Date(order.createdAt).toLocaleDateString('fr-FR', { day: 'numeric', month: 'short', hour: '2-digit', minute: '2-digit'})}</p>
                                </div>
                                <span className={`text-[10px] font-bold px-2 py-1 rounded-full uppercase tracking-wide ${getStatusColor(order.status)}`}>{getStatusLabel(order.status)}</span>
                            </div>
                        </div>

                        {/* Contenu principal */}
                        <div className="p-4">
                            {/* TIMELINE DE SUIVI (Seulement si pas annulé) */}
                            {!isCancelled && !isCompleted && (
                                <div className="mb-6 pl-2 mt-2">
                                    <TimelineStep 
                                        active={isPending} 
                                        completed={step1Complete} 
                                        icon={Clock} 
                                        title="Commande reçue" 
                                    />
                                    <TimelineStep 
                                        active={isPrep} 
                                        completed={step2Complete} 
                                        icon={ChefHat} 
                                        title="Préparation en cuisine" 
                                    />
                                    <TimelineStep 
                                        active={isReady || isDelivering} 
                                        completed={step3Complete} 
                                        icon={Bike} 
                                        title="En route vers vous" 
                                    />
                                    <TimelineStep 
                                        active={false} 
                                        completed={step4Complete} 
                                        icon={CheckCircle2} 
                                        title="Livré et savouré" 
                                        isLast
                                    />
                                </div>
                            )}

                            {/* Liste des articles simplifiée */}
                            <div className="bg-gray-50 p-3 rounded-lg mb-4 text-sm">
                                {order.items.map((item, idx) => (
                                    <div key={idx} className="flex justify-between items-center mb-1 last:mb-0">
                                        <div className="flex items-center text-gray-600">
                                            <span className="font-bold mr-2 text-xs text-gray-400">x{item.quantity}</span>
                                            <span>{item.name}</span>
                                        </div>
                                        <span className="font-medium text-gray-800">${(item.price * item.quantity).toFixed(2)}</span>
                                    </div>
                                ))}
                                <div className="flex justify-between items-center pt-2 mt-2 border-t border-gray-200">
                                    <span className="font-bold text-gray-600">Total</span>
                                    <span className="font-black text-brand-600 text-lg">${order.totalAmount.toFixed(2)}</span>
                                </div>
                            </div>

                            {/* Actions */}
                            {!isCompleted && !isCancelled && (
                                <div className="grid grid-cols-2 gap-3">
                                    <button 
                                        onClick={() => window.open(`tel:${order.restaurant?.phone_number || '+243999999999'}`)} 
                                        className="flex items-center justify-center py-2.5 bg-white border border-gray-200 text-gray-700 rounded-xl text-xs font-bold hover:bg-gray-50 transition-colors"
                                    >
                                        <Phone size={14} className="mr-2" /> Appeler
                                    </button>
                                    <button 
                                        onClick={() => onChat(order)} 
                                        className="flex items-center justify-center py-2.5 bg-brand-600 text-white rounded-xl text-xs font-bold hover:bg-brand-700 shadow-md shadow-brand-100 transition-colors"
                                    >
                                        <MessageSquare size={14} className="mr-2" /> Message
                                    </button>
                                </div>
                            )}

                            {isCompleted && (
                                <div className="text-center bg-green-50 p-3 rounded-lg border border-green-100">
                                    <p className="text-green-800 font-bold text-sm flex items-center justify-center">
                                        <CheckCircle2 size={16} className="mr-2"/> Commande terminée
                                    </p>
                                    <button onClick={onBrowse} className="text-xs text-green-700 underline mt-1">Commander à nouveau</button>
                                </div>
                            )}
                        </div>
                    </div>
                   );
                })}
            </div>
        )}
    </div>
  );
};

import React, { useState, useEffect, useMemo } from 'react';
import { MapPin, ShoppingBag, List, Map, Zap, ArrowLeft, Plus, Bike, Footprints, LogOut, Navigation, Search, X, Receipt, Phone, Info, Image as ImageIcon, PlayCircle } from 'lucide-react';
import { supabase } from '../lib/supabase';
import { KINSHASA_CENTER_LAT, KINSHASA_CENTER_LNG, CITIES_RDC } from '../constants';
import { Restaurant, UserState, ViewMode, MenuItem, CartItem, User, Order, Promotion } from '../types';
import { calculateTime, getDistanceFromLatLonInKm, formatDistance, formatTime } from '../utils/geo';
import { RestaurantCard } from '../components/RestaurantCard';
import { MapView } from '../components/MapView';
import { CartDrawer } from '../components/CartDrawer';
import { ChatWindow } from '../components/ChatWindow';
import { StoryViewer } from '../components/StoryViewer';
import { OrdersView } from '../components/OrdersView';

// Speed constants
const SPEED_WALKING = 5;
const SPEED_MOTO = 30;

interface Props {
  user: User;
  allRestaurants: Restaurant[];
  onLogout: () => void;
}

export const CustomerView: React.FC<Props> = ({ user, allRestaurants, onLogout }) => {
  // State
  const [userState, setUserState] = useState<UserState>({
    location: null,
    locationError: null,
    loadingLocation: true,
  });

  const [restaurants, setRestaurants] = useState<Restaurant[]>([]);
  const [promotionsMap, setPromotionsMap] = useState<Record<string, Promotion[]>>({});

  const [viewMode, setViewMode] = useState<ViewMode>('list');
  const [selectedRestaurant, setSelectedRestaurant] = useState<Restaurant | null>(null);
  const [cart, setCart] = useState<CartItem[]>([]);
  const [isCartOpen, setIsCartOpen] = useState(false);
  const [urgentMode, setUrgentMode] = useState(false);
  const [searchQuery, setSearchQuery] = useState('');
  const [showSuccess, setShowSuccess] = useState(false);
  const [selectedCity, setSelectedCity] = useState<string>(user.city || 'Kinshasa');

  // Order States
  const [orders, setOrders] = useState<Order[]>([]);
  const [isCheckingOut, setIsCheckingOut] = useState(false);

  // Chat State
  const [activeChatOrder, setActiveChatOrder] = useState<Order | null>(null);

  // Story State
  const [activeStoryRestaurant, setActiveStoryRestaurant] = useState<Restaurant | null>(null);
  const [storyStartIndex, setStoryStartIndex] = useState(0);

  // Initial Geolocation
  useEffect(() => {
    if (!navigator.geolocation) {
      setUserState({
        location: null,
        locationError: "La géolocalisation n'est pas supportée par votre navigateur",
        loadingLocation: false
      });
      return;
    }

    navigator.geolocation.getCurrentPosition(
      (position) => {
        setUserState({
          location: {
            latitude: position.coords.latitude,
            longitude: position.coords.longitude,
          },
          locationError: null,
          loadingLocation: false
        });
      },
      (error) => {
        console.warn("Geo error:", error);
        setUserState({
            location: {
                latitude: KINSHASA_CENTER_LAT,
                longitude: KINSHASA_CENTER_LNG
            },
            locationError: "Position introuvable. Utilisation de la position par défaut (Kinshasa).",
            loadingLocation: false
        });
      },
      { enableHighAccuracy: true, timeout: 5000, maximumAge: 0 }
    );
  }, []);

  // Update Restaurants when location or database changes
  useEffect(() => {
    if (userState.location) {
      const updatedRestaurants = allRestaurants.map(r => {
        const dist = getDistanceFromLatLonInKm(
          userState.location!.latitude,
          userState.location!.longitude,
          r.latitude,
          r.longitude
        );
        return {
          ...r,
          distance: dist,
          timeWalking: calculateTime(dist, SPEED_WALKING),
          timeMoto: calculateTime(dist, SPEED_MOTO),
        };
      }).sort((a, b) => (a.distance || 0) - (b.distance || 0));

      setRestaurants(updatedRestaurants);
      // Fetch promotions after restaurants are ready
      fetchPromotions(updatedRestaurants);
    } else {
      setRestaurants(allRestaurants);
      fetchPromotions(allRestaurants);
    }
  }, [userState.location, allRestaurants]);

  // Realtime Orders Subscription for Customer
  useEffect(() => {
    const channel = supabase
        .channel('customer-orders')
        .on(
            'postgres_changes',
            {
                event: 'UPDATE', // On écoute quand le restaurant change le statut
                schema: 'public',
                table: 'orders',
                filter: `user_id=eq.${user.id}`
            },
            (payload) => {
                console.log("Mise à jour commande client:", payload);
                // On met à jour l'état local pour voir le changement instantanément
                setOrders(prev => prev.map(o => 
                    o.id === payload.new.id ? { ...o, status: payload.new.status } : o
                ));
            }
        )
        .subscribe();

    return () => {
        supabase.removeChannel(channel);
    };
  }, [user.id]);

  const fetchPromotions = async (restos: Restaurant[]) => {
      // In a real app, join query is better, but here we simulate or fetch separately
      const { data } = await supabase.from('promotions').select('*').order('created_at', { ascending: false });
      if (data) {
          const mapping: Record<string, Promotion[]> = {};
          data.forEach((p: any) => {
              if (!mapping[p.restaurant_id]) mapping[p.restaurant_id] = [];
              mapping[p.restaurant_id].push({
                  id: p.id,
                  restaurantId: p.restaurant_id,
                  mediaUrl: p.media_url,
                  mediaType: p.media_type,
                  caption: p.caption,
                  createdAt: p.created_at
              });
          });
          setPromotionsMap(mapping);
      }
  };

  // Load Orders when entering 'orders' view
  useEffect(() => {
    if (viewMode === 'orders') {
        fetchOrders();
    }
  }, [viewMode]);

  const fetchOrders = async () => {
    try {
        const { data, error } = await supabase
            .from('orders')
            .select(`*, restaurant:restaurants(name, phone_number)`)
            .eq('user_id', user.id)
            .order('created_at', { ascending: false });

        if (error) {
             const localOrders = localStorage.getItem('dashmeals_mock_orders');
             if (localOrders) setOrders(JSON.parse(localOrders));
             return;
        }

        if (data) {
            setOrders(data.map((o: any) => ({
                id: o.id,
                userId: o.user_id,
                restaurantId: o.restaurant_id,
                status: o.status,
                totalAmount: o.total_amount,
                items: o.items,
                createdAt: o.created_at,
                restaurant: {
                    name: o.restaurant?.name || 'Inconnu',
                    phone_number: o.restaurant?.phone_number
                }
            })));
        }
    } catch (err) {
        console.error("Error fetching orders:", err);
    }
  };

  // Filter Logic (City + Urgent + Search)
  const filteredRestaurants = useMemo(() => {
    let list = restaurants;
    if (selectedCity && selectedCity !== 'Toutes') list = list.filter(r => r.city === selectedCity);
    if (urgentMode) list = list.filter(r => r.isOpen && r.preparationTime <= 20);
    if (searchQuery) {
        const query = searchQuery.toLowerCase();
        list = list.filter(r => 
          r.name.toLowerCase().includes(query) || 
          r.description.toLowerCase().includes(query)
        );
    }
    return list;
  }, [restaurants, urgentMode, selectedCity, searchQuery]);

  // Cart Logic
  const addToCart = (item: MenuItem, restaurant: Restaurant) => {
    if (cart.length > 0 && cart[0].restaurantId !== restaurant.id) {
        if(!window.confirm("Vous ne pouvez commander que dans un restaurant à la fois. Vider le panier actuel ?")) return;
        setCart([]);
    }
    setCart(prev => {
        const existing = prev.find(i => i.id === item.id);
        if (existing) return prev.map(i => i.id === item.id ? { ...i, quantity: i.quantity + 1 } : i);
        return [...prev, { ...item, quantity: 1, restaurantId: restaurant.id, restaurantName: restaurant.name }];
    });
  };

  const removeFromCart = (itemId: string) => {
    setCart(prev => {
        const index = prev.findIndex(i => i.id === itemId);
        if (index > -1) {
            const newArr = [...prev];
            newArr.splice(index, 1);
            return newArr;
        }
        return prev;
    });
  };

  const cartTotal = cart.reduce((sum, item) => sum + (item.price * item.quantity), 0);

  const handleCheckout = async () => {
    if (cart.length === 0) return;
    setIsCheckingOut(true);

    try {
        const { data, error } = await supabase.from('orders').insert({
            user_id: user.id,
            restaurant_id: cart[0].restaurantId,
            status: 'pending',
            total_amount: cartTotal,
            items: cart // Supabase will stringify this automatically for jsonb
        }).select().single();

        if (error) {
            console.error("Erreur commande:", error);
            throw new Error("Impossible d'envoyer la commande. Vérifiez votre connexion.");
        }

        // Success Path
        setIsCartOpen(false);
        setShowSuccess(true);
        setCart([]);

        // Redirection rapide vers l'historique pour voir le suivi
        setTimeout(() => {
             setShowSuccess(false);
             setViewMode('orders');
             // fetchOrders sera appelé par le useEffect du viewMode
        }, 2000);

    } catch (err: any) {
        alert(err.message || "Erreur inconnue lors de la commande.");
    } finally {
        setIsCheckingOut(false);
    }
  };

  // Views
  if (userState.loadingLocation) {
    return (
      <div className="min-h-screen flex flex-col items-center justify-center bg-brand-50">
        <div className="w-16 h-16 border-4 border-brand-500 border-t-transparent rounded-full animate-spin"></div>
        <p className="mt-4 text-brand-800 font-medium">Localisation en cours...</p>
      </div>
    );
  }

  // Get list of restaurants that have promotions
  const restaurantsWithStories = restaurants.filter(r => promotionsMap[r.id] && promotionsMap[r.id].length > 0);

  return (
    // AJOUT DE 'transform-gpu' POUR FORCER LE RENDU PIXEL-PERFECT ET ÉVITER LE FLOU SUR LES MARGES AUTO
    <div className="min-h-screen pb-20 max-w-md mx-auto bg-gray-50 shadow-2xl overflow-hidden relative transform-gpu">

      {/* STORY VIEWER OVERLAY */}
      {activeStoryRestaurant && promotionsMap[activeStoryRestaurant.id] && (
          <StoryViewer 
            restaurant={activeStoryRestaurant}
            promotions={promotionsMap[activeStoryRestaurant.id]}
            onClose={() => setActiveStoryRestaurant(null)}
            onVisitRestaurant={() => {
                setActiveStoryRestaurant(null);
                setSelectedRestaurant(activeStoryRestaurant);
                setViewMode('restaurant_detail');
            }}
            initialIndex={storyStartIndex}
          />
      )}

      {/* CHAT OVERLAY */}
      {activeChatOrder && (
          <ChatWindow 
            orderId={activeChatOrder.id}
            currentUser={{ id: user.id, role: 'client' }}
            otherUserName={activeChatOrder.restaurant?.name || 'Restaurant'}
            otherUserPhone={activeChatOrder.restaurant?.phone_number || '+243999999999'}
            onClose={() => setActiveChatOrder(null)}
          />
      )}

      {/* SUCCESS OVERLAY */}
      {showSuccess && (
        <div className="absolute inset-0 z-[60] bg-brand-500 flex flex-col items-center justify-center text-white p-6 text-center animate-fade-in">
           <div className="w-20 h-20 bg-white rounded-full flex items-center justify-center mb-6 shadow-xl">
              <ShoppingBag className="text-brand-500" size={40} />
           </div>
           <h2 className="text-3xl font-bold mb-2">Commande Reçue !</h2>
           <p className="text-brand-100">Votre repas est en préparation.</p>
           <div className="mt-8 bg-white/20 p-4 rounded-xl backdrop-blur-sm">
             <p className="font-mono text-sm">Redirection vers le suivi...</p>
           </div>
        </div>
      )}

      {/* HEADER */}
      <header className="bg-white sticky top-0 z-30 px-4 py-3 shadow-sm border-b border-gray-100">
        <div className="flex justify-between items-center mb-2">
            <div className="flex items-center">
                <h1 className="text-xl font-black text-brand-600 tracking-tight mr-2">DashMeals</h1>
                <span className="text-xs bg-brand-100 text-brand-800 px-2 py-0.5 rounded-full font-bold">Client</span>
            </div>
          <div className="flex items-center space-x-2">
            <button onClick={() => setIsCartOpen(true)} className="relative p-2 bg-gray-100 rounded-full hover:bg-gray-200 transition-colors">
                <ShoppingBag size={20} className="text-gray-700" />
                {cart.length > 0 && <span className="absolute top-0 right-0 bg-red-500 text-white text-[10px] font-bold h-4 w-4 flex items-center justify-center rounded-full border-2 border-white">{cart.length}</span>}
            </button>
            <button onClick={onLogout} className="p-2 text-gray-400 hover:text-red-500">
                <LogOut size={20} />
            </button>
          </div>
        </div>

        {(viewMode === 'list' || viewMode === 'map') && (
            <div className="flex items-center space-x-2">
                <div className="flex-1 flex items-center text-sm text-gray-500 bg-gray-50 p-2 rounded-lg truncate">
                <MapPin size={14} className="mr-1.5 text-brand-500 flex-shrink-0" />
                <span className="truncate">{userState.locationError ? "Mode Démo" : "Ma Position"}</span>
                </div>
                <select className="bg-brand-50 text-brand-700 text-xs font-bold py-2 pl-2 pr-6 rounded-lg border border-brand-200 outline-none appearance-none" value={selectedCity} onChange={(e) => setSelectedCity(e.target.value)}>
                <option value="Toutes">Toutes les villes</option>
                {CITIES_RDC.map(city => <option key={city} value={city}>{city}</option>)}
                </select>
            </div>
        )}
      </header>

      {/* MAIN CONTENT AREA */}
      <main className="p-4 pt-2">

        {viewMode === 'list' || viewMode === 'map' ? (
            <>
                {/* SEARCH BAR - Moved to Top */}
                <div className="mb-4 relative z-20">
                    <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 text-gray-400" size={18} />
                    <input 
                        type="text"
                        placeholder="Rechercher un restaurant par nom..."
                        className="w-full pl-10 pr-10 py-3 rounded-xl border border-gray-200 focus:ring-2 focus:ring-brand-500 outline-none text-sm bg-white shadow-sm transition-shadow focus:shadow-md"
                        value={searchQuery}
                        onChange={(e) => setSearchQuery(e.target.value)}
                    />
                    {searchQuery && (
                      <button 
                        onClick={() => setSearchQuery('')} 
                        className="absolute right-3 top-1/2 transform -translate-y-1/2 text-gray-400 hover:text-gray-600 p-1"
                      >
                        <X size={16} />
                      </button>
                    )}
                </div>

                {/* STORIES BAR (Professional Look) - Hidden during search */}
                {!searchQuery && restaurantsWithStories.length > 0 && (
                    <div className="mb-6 -mx-4 px-4 overflow-x-auto no-scrollbar">
                        <div className="flex space-x-4">
                            {restaurantsWithStories.map(r => (
                                <button 
                                    key={r.id} 
                                    onClick={() => {
                                        setStoryStartIndex(0);
                                        setActiveStoryRestaurant(r);
                                    }}
                                    className="flex flex-col items-center space-y-1 min-w-[64px]"
                                >
                                    <div className="w-16 h-16 rounded-full p-[2px] bg-gradient-to-tr from-brand-500 to-yellow-500">
                                        <div className="w-full h-full rounded-full border-2 border-white overflow-hidden">
                                            <img src={r.coverImage} className="w-full h-full object-cover" alt={r.name} />
                                        </div>
                                    </div>
                                    <span className="text-[10px] font-medium text-gray-600 truncate w-full text-center">{r.name}</span>
                                </button>
                            ))}
                        </div>
                    </div>
                )}

                {/* FILTERS */}
                <div className="flex space-x-3 mb-6 overflow-x-auto no-scrollbar pb-1">
                    <button 
                        onClick={() => setUrgentMode(!urgentMode)}
                        className={`flex items-center px-4 py-2 rounded-full font-bold text-sm shadow-sm transition-all border whitespace-nowrap ${urgentMode ? 'bg-red-500 text-white border-red-500 animate-pulse-fast' : 'bg-white text-gray-700 border-gray-200'}`}
                    >
                        <Zap size={16} className={`mr-1 ${urgentMode ? 'fill-white' : 'fill-none'}`} />
                        Urgent - J'ai faim !
                    </button>
                    <button className="px-4 py-2 rounded-full bg-white border border-gray-200 text-gray-600 font-medium text-sm whitespace-nowrap shadow-sm">🍖 Grillades</button>
                    <button className="px-4 py-2 rounded-full bg-white border border-gray-200 text-gray-600 font-medium text-sm whitespace-nowrap shadow-sm">🍗 Poulet</button>
                </div>

                {/* CONTENT */}
                {viewMode === 'list' ? (
                    <div className="space-y-4">
                        {filteredRestaurants.map(restaurant => (
                            <RestaurantCard 
                                key={restaurant.id} 
                                restaurant={restaurant} 
                                onClick={() => { setSelectedRestaurant(restaurant); setViewMode('restaurant_detail'); }} 
                            />
                        ))}
                        {filteredRestaurants.length === 0 && (
                            <div className="text-center py-10 text-gray-500">
                                <p>Aucun restaurant trouvé {selectedCity !== 'Toutes' ? `à ${selectedCity}` : ''} {searchQuery ? `pour "${searchQuery}"` : ''} :(</p>
                                {urgentMode && <button onClick={() => setUrgentMode(false)} className="text-brand-500 underline mt-2">Désactiver le mode urgent</button>}
                            </div>
                        )}
                    </div>
                ) : (
                    <MapView 
                        restaurants={filteredRestaurants} 
                        userLocation={userState.location} 
                        onSelect={(r) => { setSelectedRestaurant(r); setViewMode('restaurant_detail'); }}
                    />
                )}
            </>
        ) : viewMode === 'restaurant_detail' && selectedRestaurant ? (
            <div className="animate-in slide-in-from-right duration-300">
                <button onClick={() => setViewMode('list')} className="mb-4 flex items-center text-gray-600 font-medium hover:text-brand-600"><ArrowLeft size={18} className="mr-1" /> Retour</button>
                <div className="bg-white rounded-2xl shadow-sm border border-gray-100 overflow-hidden mb-6">
                    <img src={selectedRestaurant.coverImage} className="w-full h-48 object-cover" alt="Cover" />
                    <div className="p-4">
                        <div className="flex justify-between items-start">
                           <h1 className="text-2xl font-bold text-gray-900">{selectedRestaurant.name}</h1>
                           <span className="text-xs bg-gray-100 text-gray-600 px-2 py-1 rounded-lg">{selectedRestaurant.city}</span>
                        </div>
                        <p className="text-gray-500 mb-4 mt-2">{selectedRestaurant.description}</p>

                        {/* Info & Contact Section */}
                        <div className="bg-gray-50 p-4 rounded-xl mb-4 border border-gray-100">
                            <h3 className="text-sm font-bold text-gray-800 mb-3 flex items-center"><Info size={16} className="mr-2 text-brand-600"/> Informations & Contact</h3>
                            <div className="space-y-2">
                                <div className="flex items-center text-sm text-gray-600">
                                    <MapPin size={16} className="mr-2 text-gray-400"/>
                                    <span>{selectedRestaurant.city || 'Kinshasa'}</span>
                                </div>
                                <div className="flex items-center justify-between">
                                    <div className="flex items-center text-sm text-gray-600">
                                        <Phone size={16} className="mr-2 text-gray-400"/>
                                        <span>{selectedRestaurant.phoneNumber || 'Numéro non disponible'}</span>
                                    </div>
                                    {selectedRestaurant.phoneNumber && (
                                        <button 
                                            onClick={() => window.open(`tel:${selectedRestaurant.phoneNumber}`)}
                                            className="bg-green-500 hover:bg-green-600 text-white px-4 py-2 rounded-lg text-xs font-bold flex items-center shadow-md transition-transform active:scale-95"
                                        >
                                            <Phone size={14} className="mr-1"/> Appeler
                                        </button>
                                    )}
                                </div>
                            </div>
                        </div>

                        <div className="flex items-center space-x-4 text-sm text-gray-600 mb-4">
                            <span className="flex items-center bg-gray-100 px-2 py-1 rounded"><Navigation size={14} className="mr-1"/> {formatDistance(selectedRestaurant.distance || 0)}</span>
                            <span className="flex items-center bg-gray-100 px-2 py-1 rounded"><Zap size={14} className="mr-1 text-yellow-500"/> {selectedRestaurant.preparationTime} min</span>
                        </div>

                        <div className="grid grid-cols-2 gap-3 mb-2">
                             <div className="flex items-center p-3 bg-orange-50 rounded-lg text-orange-700 border border-orange-100">
                                <Bike size={20} className="mr-3" />
                                <div><p className="text-[10px] font-bold uppercase tracking-wider opacity-70">En Moto</p><p className="font-bold text-lg leading-none">{selectedRestaurant.timeMoto ? formatTime(selectedRestaurant.timeMoto) : '--'}</p></div>
                            </div>
                            <div className="flex items-center p-3 bg-blue-50 rounded-lg text-blue-700 border border-blue-100">
                                <Footprints size={20} className="mr-3" />
                                <div><p className="text-[10px] font-bold uppercase tracking-wider opacity-70">À pied</p><p className="font-bold text-lg leading-none">{selectedRestaurant.timeWalking ? formatTime(selectedRestaurant.timeWalking) : '--'}</p></div>
                            </div>
                        </div>
                    </div>
                </div>

                {/* GALLERY SECTION (NEW) */}
                {promotionsMap[selectedRestaurant.id] && promotionsMap[selectedRestaurant.id].length > 0 && (
                    <div className="mb-6">
                        <h3 className="text-lg font-bold mb-3 text-gray-800 flex items-center">
                            <ImageIcon className="mr-2 text-brand-600" size={18} />
                            Galerie ({promotionsMap[selectedRestaurant.id].length})
                        </h3>
                        <div className="grid grid-cols-3 gap-2">
                            {promotionsMap[selectedRestaurant.id].map((item, idx) => (
                                <button
                                    key={item.id}
                                    onClick={() => {
                                        setStoryStartIndex(idx);
                                        setActiveStoryRestaurant(selectedRestaurant);
                                    }}
                                    className="relative aspect-square rounded-xl overflow-hidden shadow-sm border border-gray-100 group"
                                >
                                    {item.mediaType === 'video' ? (
                                        <>
                                            <video src={item.mediaUrl} className="w-full h-full object-cover opacity-90" muted />
                                            <div className="absolute inset-0 flex items-center justify-center bg-black/20 group-hover:bg-black/40 transition-colors">
                                                <PlayCircle className="text-white opacity-90" size={24} />
                                            </div>
                                        </>
                                    ) : (
                                        <img src={item.mediaUrl} className="w-full h-full object-cover transition-transform duration-300 group-hover:scale-110" alt="Gallery" />
                                    )}
                                </button>
                            ))}
                        </div>
                    </div>
                )}

                <h3 className="text-lg font-bold mb-3">Menu</h3>
                <div className="space-y-3">
                    {selectedRestaurant.menu.map(item => (
                        <div key={item.id} className="bg-white p-3 rounded-xl border border-gray-100 shadow-sm flex space-x-3">
                            <img src={item.image} className="w-20 h-20 rounded-lg object-cover bg-gray-100" alt={item.name} />
                            <div className="flex-1 flex flex-col justify-between">
                                <div>
                                    <h4 className="font-bold text-gray-800">{item.name}</h4>
                                    <p className="text-xs text-gray-500 line-clamp-1">{item.description}</p>
                                </div>
                                <div className="flex justify-between items-end mt-2">
                                    <span className="font-bold text-brand-600">${item.price.toFixed(2)}</span>
                                    <button onClick={() => addToCart(item, selectedRestaurant)} className="bg-brand-50 text-brand-600 p-2 rounded-full hover:bg-brand-100 transition-colors"><Plus size={16} /></button>
                                </div>
                            </div>
                        </div>
                    ))}
                </div>
            </div>
        ) : viewMode === 'orders' ? (
            <OrdersView 
                orders={orders} 
                onChat={(order) => setActiveChatOrder(order)} 
                onBrowse={() => setViewMode('list')} 
            />
        ) : null}
      </main>

      <nav className="fixed bottom-0 left-0 right-0 bg-white border-t border-gray-200 px-6 py-3 flex justify-around items-center z-40 max-w-md mx-auto">
        <button onClick={() => setViewMode('list')} className={`flex flex-col items-center space-y-1 ${viewMode === 'list' || viewMode === 'restaurant_detail' ? 'text-brand-600' : 'text-gray-400'}`}><List size={22} /><span className="text-[10px] font-medium">Liste</span></button>
        <div className="relative -top-6"><button onClick={() => setUrgentMode(!urgentMode)} className={`w-14 h-14 rounded-full flex items-center justify-center shadow-lg border-4 border-gray-50 transition-all ${urgentMode ? 'bg-red-500 text-white scale-110' : 'bg-brand-500 text-white'}`}><Zap size={24} className={urgentMode ? 'animate-pulse' : ''} /></button></div>
        <button onClick={() => setViewMode('map')} className={`flex flex-col items-center space-y-1 ${viewMode === 'map' ? 'text-brand-600' : 'text-gray-400'}`}><Map size={22} /><span className="text-[10px] font-medium">Carte</span></button>
        <button onClick={() => setViewMode('orders')} className={`flex flex-col items-center space-y-1 ${viewMode === 'orders' ? 'text-brand-600' : 'text-gray-400'}`}><Receipt size={22} /><span className="text-[10px] font-medium">Commandes</span></button>
      </nav>

      <CartDrawer isOpen={isCartOpen} onClose={() => setIsCartOpen(false)} items={cart} onRemove={removeFromCart} onCheckout={handleCheckout} total={cartTotal} isLoading={isCheckingOut} />
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { supabase } from '../lib/supabase';
import { User, UserRole, BusinessType } from '../types';
import { CITIES_RDC } from '../constants';
import { User as UserIcon, Store, AlertCircle, MapPin, Mail, Phone } from 'lucide-react';

interface Props {
  onLogin: (user: User, businessData?: any) => void;
}

export const AuthScreen: React.FC<Props> = ({ onLogin }) => {
  const [isLogin, setIsLogin] = useState(true);
  const [role, setRole] = useState<UserRole>('client');
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  // Form States
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [name, setName] = useState('');
  const [phone, setPhone] = useState('');
  const [city, setCity] = useState('Kinshasa');
  const [availableCities, setAvailableCities] = useState<string[]>(CITIES_RDC);

  // Business Specific States
  const [businessType, setBusinessType] = useState<BusinessType>('restaurant');
  const [businessName, setBusinessName] = useState('');

  // Fetch cities from DB on mount
  useEffect(() => {
    const fetchCities = async () => {
      try {
        const { data, error } = await supabase
          .from('cities')
          .select('name')
          .eq('is_active', true)
          .order('name');

        if (!error && data && data.length > 0) {
          setAvailableCities(data.map(c => c.name));
        }
      } catch (err) {
        console.warn("Could not fetch cities from DB, using defaults");
      }
    };
    fetchCities();
  }, []);

  const handleOAuthLogin = async (provider: 'google' | 'facebook') => {
    setLoading(true);
    setError(null);
    try {
      localStorage.setItem('dashmeals_pending_auth', JSON.stringify({ 
          role, 
          city,
      }));

      const { error } = await supabase.auth.signInWithOAuth({
        provider: provider,
        options: {
          redirectTo: window.location.origin,
          queryParams: {
            access_type: 'offline',
            prompt: 'consent',
          }
        }
      });
      if (error) throw error;
    } catch (err: any) {
      console.error("OAuth Error:", err);
      setError(err.message || "Erreur de connexion sociale");
      setLoading(false);
    }
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (loading) return;

    setLoading(true);
    setError(null);

    try {
      if (isLogin) {
        // LOGIN
        const { error } = await supabase.auth.signInWithPassword({
          email,
          password,
        });
        if (error) throw error;
      } else {
        // SIGN UP
        // 1. Create Auth User
        const { data: authData, error: authError } = await supabase.auth.signUp({
          email,
          password,
          options: {
            // On sauvegarde aussi les infos dans les métadonnées comme backup
            data: { 
                full_name: name, 
                role: role, 
                city: city, 
                phone_number: phone 
            }, 
          }
        });

        if (authError) throw authError;

        if (authData.user) {
          // 2. Create Profile in DB using UPSERT to prevent conflicts
          const { error: profileError } = await supabase.from('profiles').upsert({
            id: authData.user.id,
            role: role,
            full_name: name,
            city: city,
            phone_number: phone
          });

          if (profileError) {
             console.warn("Avertissement création profil (Non bloquant):", profileError);
             // On ne throw PAS d'erreur ici car l'utilisateur est déjà créé dans Auth
             // et l'application peut fonctionner avec les métadonnées ou le mode offline
          }

          // 3. If Business, Create Restaurant
          if (role === 'business') {
            const { error: restoError } = await supabase.from('restaurants').insert({
              owner_id: authData.user.id,
              name: businessName,
              type: businessType,
              city: city, 
              latitude: -4.301 + (Math.random() - 0.5) * 0.02, 
              longitude: 15.301 + (Math.random() - 0.5) * 0.02,
              description: `Bienvenue chez ${businessName}`,
              cover_image: `https://picsum.photos/800/600?random=${Date.now()}`,
              preparation_time: 30,
              estimated_delivery_time: 30,
              phone_number: phone // Set restaurant phone number to owner's phone initially
            });
            if (restoError) {
                console.warn("Restaurant creation warning:", restoError);
            }
          }

          // Si inscription réussie mais pas de session auto (ex: email confirm), on prévient
          if (!authData.session) {
              setError("Compte créé ! Veuillez vérifier vos emails pour confirmer votre adresse avant de vous connecter.");
              setIsLogin(true);
              setLoading(false);
              return;
          }
        }
      }
    } catch (err: any) {
      console.error("Auth Error:", err);
      let message = err.message || "Une erreur est survenue";
      const lowerMsg = message.toLowerCase();

      // MAPPING DES ERREURS SUPABASE
      if (lowerMsg.includes("rate limit") || lowerMsg.includes("too many requests")) {
        message = "Trop de tentatives de connexion. Pour votre sécurité, veuillez patienter quelques minutes avant de réessayer.";
      } else if (lowerMsg.includes("invalid login credentials")) {
        message = "Email ou mot de passe incorrect. Vérifiez vos identifiants.";
      } else if (lowerMsg.includes("email not confirmed")) {
        message = "Votre adresse email n'a pas encore été confirmée. Veuillez vérifier votre boîte de réception (et vos spams).";
      } else if (lowerMsg.includes("user already registered") || lowerMsg.includes("already exists")) {
        message = "Cette adresse email est déjà associée à un compte. Essayez de vous connecter.";
      } else if (lowerMsg.includes("password should be at least")) {
        message = "Le mot de passe est trop court. Il doit contenir au moins 6 caractères.";
      } else if (lowerMsg.includes("fetch failed") || lowerMsg.includes("network request failed")) {
        message = "Problème de connexion internet. Vérifiez votre réseau.";
      }

      setError(message);
      setLoading(false);
    }
  };

  return (
    <div className="min-h-screen bg-brand-50 flex flex-col items-center justify-center p-4">
      <div className="bg-white w-full max-w-md rounded-2xl shadow-xl overflow-hidden">

        {/* Header */}
        <div className="bg-brand-600 p-6 text-center">
          <h1 className="text-3xl font-black text-white tracking-tight">DashMeals<span className="text-brand-200 text-xs font-normal ml-1">RDC</span></h1>
          <p className="text-brand-100 mt-2">La plateforme gourmande de Kinshasa</p>
        </div>

        {/* Tabs */}
        <div className="flex border-b">
          <button 
            type="button"
            onClick={() => setRole('client')}
            className={`flex-1 py-4 text-sm font-bold flex items-center justify-center ${role === 'client' ? 'text-brand-600 border-b-2 border-brand-600 bg-brand-50' : 'text-gray-500'}`}
          >
            <UserIcon size={18} className="mr-2" />
            Client
          </button>
          <button 
            type="button"
            onClick={() => setRole('business')}
            className={`flex-1 py-4 text-sm font-bold flex items-center justify-center ${role === 'business' ? 'text-brand-600 border-b-2 border-brand-600 bg-brand-50' : 'text-gray-500'}`}
          >
            <Store size={18} className="mr-2" />
            Entreprise
          </button>
        </div>

        <div className="p-6 pb-2">
            <h2 className="text-xl font-bold text-gray-800 text-center mb-6">
                {isLogin ? 'Connexion' : 'Créer un compte'} {role === 'business' ? 'Partenaire' : ''}
            </h2>

            {/* Social Login Buttons */}
            <div className="grid grid-cols-2 gap-3 mb-6">
                <button 
                    type="button"
                    onClick={() => handleOAuthLogin('google')}
                    className="flex items-center justify-center py-2.5 px-4 border border-gray-300 rounded-lg hover:bg-gray-50 transition-colors bg-white text-gray-700 font-bold text-sm"
                >
                    Google
                </button>
                <button 
                    type="button"
                    onClick={() => handleOAuthLogin('facebook')}
                    className="flex items-center justify-center py-2.5 px-4 border border-gray-300 rounded-lg hover:bg-[#1877F2] hover:text-white hover:border-[#1877F2] transition-colors bg-white text-gray-700 font-bold text-sm"
                >
                    Facebook
                </button>
            </div>

            <div className="relative flex items-center justify-center mb-6">
                <hr className="w-full border-gray-300" />
                <span className="absolute bg-white px-3 text-xs text-gray-500 font-medium">OU AVEC EMAIL</span>
            </div>
        </div>

        {/* Form */}
        <form onSubmit={handleSubmit} className="px-6 pb-6 space-y-4">

          {error && (
            <div className="bg-red-50 border border-red-100 text-red-600 p-4 rounded-xl text-sm animate-pulse flex items-start shadow-sm">
                 <AlertCircle size={18} className="mr-2 flex-shrink-0 mt-0.5" />
                 <span className="font-medium leading-tight">{error}</span>
            </div>
          )}

          {!isLogin && (
            <div>
              <label className="block text-xs font-bold text-gray-600 mb-1">Votre Nom complet</label>
              <input 
                type="text" 
                required 
                className="w-full p-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-brand-500 outline-none"
                placeholder="Ex: Jean K."
                value={name}
                onChange={(e) => setName(e.target.value)}
              />
            </div>
          )}

           {/* Phone Number Field */}
           {!isLogin && (
            <div>
              <label className="block text-xs font-bold text-gray-600 mb-1">Numéro de téléphone</label>
              <div className="relative">
                <Phone size={16} className="absolute left-3 top-1/2 transform -translate-y-1/2 text-gray-400" />
                <input 
                    type="tel" 
                    required 
                    className="w-full p-3 pl-10 border border-gray-300 rounded-lg focus:ring-2 focus:ring-brand-500 outline-none"
                    placeholder="Ex: 0812345678"
                    value={phone}
                    onChange={(e) => setPhone(e.target.value)}
                />
              </div>
            </div>
          )}

          {/* City Selection for both Roles during Signup */}
          {!isLogin && (
             <div>
                <label className="block text-xs font-bold text-gray-600 mb-1 flex items-center">
                  <MapPin size={12} className="mr-1"/> 
                  {role === 'business' ? 'Ville du commerce' : 'Votre Ville'}
                </label>
                <select 
                  className="w-full p-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-brand-500 outline-none bg-white text-gray-900"
                  value={city}
                  onChange={(e) => setCity(e.target.value)}
                >
                  {availableCities.map(c => (
                    <option key={c} value={c} className="text-gray-900">{c}</option>
                  ))}
                </select>
             </div>
          )}

          {/* Business Specific Fields during Signup */}
          {!isLogin && role === 'business' && (
            <div className="bg-gray-50 p-4 rounded-lg border border-gray-200 space-y-3">
              <h3 className="text-sm font-bold text-gray-700 flex items-center"><Store size={14} className="mr-2"/> Infos Établissement</h3>
              <div>
                <label className="block text-xs font-bold text-gray-500 mb-1">Nom du commerce</label>
                <input 
                  type="text" 
                  required 
                  className="w-full p-2 border border-gray-300 rounded focus:ring-1 focus:ring-brand-500 outline-none"
                  placeholder="Ex: Chez Ntemba"
                  value={businessName}
                  onChange={(e) => setBusinessName(e.target.value)}
                />
              </div>
              <div>
                <label className="block text-xs font-bold text-gray-500 mb-1">Type</label>
                <select 
                  className="w-full p-2 border border-gray-300 rounded bg-white text-gray-900"
                  value={businessType}
                  onChange={(e) => setBusinessType(e.target.value as BusinessType)}
                >
                  <option value="restaurant" className="text-gray-900">Restaurant</option>
                  <option value="bar" className="text-gray-900">Bar / Lounge</option>
                  <option value="terrasse" className="text-gray-900">Terrasse</option>
                  <option value="snack" className="text-gray-900">Snack / Fast-food</option>
                </select>
              </div>
            </div>
          )}

          <div>
            <label className="block text-xs font-bold text-gray-600 mb-1">Email</label>
            <input 
              type="email" 
              required 
              className="w-full p-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-brand-500 outline-none"
              placeholder="Ex: nom@mail.com"
              value={email}
              onChange={(e) => setEmail(e.target.value)}
            />
          </div>

          <div>
            <label className="block text-xs font-bold text-gray-600 mb-1">Mot de passe</label>
            <input 
              type="password" 
              required 
              className="w-full p-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-brand-500 outline-none"
              placeholder="••••••••"
              value={password}
              onChange={(e) => setPassword(e.target.value)}
            />
          </div>

          <button 
            type="submit"
            disabled={loading}
            className={`w-full bg-brand-600 hover:bg-brand-700 text-white font-bold py-3 rounded-xl shadow-lg transition-transform active:scale-95 mt-4 flex justify-center items-center ${loading ? 'opacity-70 cursor-not-allowed' : ''}`}
          >
            {loading ? <div className="w-5 h-5 border-2 border-white border-t-transparent rounded-full animate-spin"></div> : (isLogin ? 'Se connecter' : "S'inscrire")}
          </button>
        </form>

        <div className="bg-gray-50 p-4 text-center border-t">
          <button 
            type="button"
            onClick={() => {
                setIsLogin(!isLogin);
                setError(null);
            }}
            className="text-sm text-brand-600 font-bold hover:underline"
          >
            {isLogin ? "Pas de compte ? S'inscrire" : "Déjà inscrit ? Se connecter"}
          </button>
        </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { supabase } from './lib/supabase';
import { MOCK_RESTAURANTS } from './constants';
import { Restaurant, User, UserRole, MenuItem, BusinessType } from './types';
import { AuthScreen } from './components/AuthScreen';
import { CustomerView } from './components/CustomerView';
import { BusinessDashboard } from './components/BusinessDashboard';
import { AlertTriangle, Store, ArrowRight } from 'lucide-react';

function App() {
  const [restaurants, setRestaurants] = useState<Restaurant[]>([]);
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [loading, setLoading] = useState(true);
  const [isOfflineMode, setIsOfflineMode] = useState(false);

  // États pour la création manuelle de restaurant (Fallback)
  const [newRestoName, setNewRestoName] = useState('');
  const [newRestoType, setNewRestoType] = useState<BusinessType>('restaurant');
  const [creationLoading, setCreationLoading] = useState(false);

  // Initialisation et écoute de la session
  useEffect(() => {
    const initSession = async () => {
        try {
            const { data: { session }, error } = await supabase.auth.getSession();
            if (error) {
                console.warn("Erreur session:", error.message);
                setIsOfflineMode(true);
            }
            if (session?.user) {
                await fetchUserProfile(session.user.id, session.user.email!, session.user.user_metadata);
            }
        } catch (err) {
            console.error("Erreur init:", err);
            setIsOfflineMode(true);
        } finally {
            setLoading(false);
        }
    };

    initSession();

    const { data: { subscription } } = supabase.auth.onAuthStateChange((_event, session) => {
      if (session?.user) {
        fetchUserProfile(session.user.id, session.user.email!, session.user.user_metadata);
      } else {
        setCurrentUser(null);
        setLoading(false);
      }
    });

    fetchRestaurants();

    return () => subscription.unsubscribe();
  }, []);

  const fetchUserProfile = async (userId: string, email: string, metadata: any = {}) => {
    try {
      let { data: profile, error } = await supabase
        .from('profiles')
        .select('*')
        .eq('id', userId)
        .maybeSingle();

      if (error) {
          console.warn("Erreur lecture profil (403/Offline):", error.message);
          setIsOfflineMode(true);
      }

      // Si pas de profil ou erreur, création profil mémoire
      if (!profile) {
        console.log("Utilisation profil mémoire...");

        const pendingAuthDataStr = localStorage.getItem('dashmeals_pending_auth');
        const pendingAuthData = pendingAuthDataStr ? JSON.parse(pendingAuthDataStr) : null;
        if (pendingAuthData) localStorage.removeItem('dashmeals_pending_auth');

        const defaultProfile = {
            id: userId,
            full_name: metadata?.full_name || metadata?.name || email.split('@')[0],
            role: pendingAuthData?.role || metadata?.role || 'client', 
            city: pendingAuthData?.city || metadata?.city || 'Kinshasa',
            phone_number: metadata?.phone_number || '' // Récupération du téléphone depuis les métadonnées
        };

        // On tente l'insert DB mais on ne bloque pas si ça échoue (403)
        supabase.from('profiles').insert(defaultProfile).then(({ error }) => {
            if (error) {
                console.warn("Insert profil échoué, continué en mémoire");
                setIsOfflineMode(true);
            }
        });

        profile = defaultProfile;
      }

      if (profile) {
        let businessId = undefined;

        if (profile.role === 'business') {
          // Si business, on check si le resto existe
          // En mode offline/403, on ne trouvera rien, donc l'UI Business demandera de créer
          // C'est acceptable pour le mode dégradé
          const { data: resto } = await supabase
            .from('restaurants')
            .select('id')
            .eq('owner_id', userId)
            .maybeSingle();

          if (resto) businessId = resto.id;
        }

        setCurrentUser({
          id: userId,
          email: email,
          name: profile.full_name || 'Utilisateur',
          role: profile.role as UserRole,
          city: profile.city || 'Kinshasa',
          phoneNumber: profile.phone_number,
          businessId,
        });
      }
    } catch (error) {
      console.error("Erreur critique profil:", error);
    } finally {
      setLoading(false);
    }
  };

  const fetchRestaurants = async () => {
    try {
      const { data, error } = await supabase
        .from('restaurants')
        .select(`*, menu_items (*)`);

      if (error) throw error;

      if (data && data.length > 0) {
        const mappedRestaurants: Restaurant[] = data.map((r: any) => ({
          id: r.id,
          ownerId: r.owner_id,
          type: r.type,
          name: r.name,
          description: r.description,
          latitude: r.latitude,
          longitude: r.longitude,
          city: r.city || 'Kinshasa',
          isOpen: r.is_open,
          rating: r.rating,
          reviewCount: r.review_count,
          preparationTime: r.preparation_time,
          estimatedDeliveryTime: r.estimated_delivery_time || 20,
          deliveryAvailable: r.delivery_available,
          coverImage: r.cover_image || 'https://picsum.photos/800/600?grayscale',
          menu: (r.menu_items || []).map((m: any) => ({
            id: m.id,
            name: m.name,
            description: m.description,
            price: m.price,
            image: m.image,
            category: m.category,
            isAvailable: m.is_available
          }))
        }));
        setRestaurants(mappedRestaurants);
        setIsOfflineMode(false); // Si ça marche, on n'est pas hors ligne
      } else {
        // DB vide ou connectée mais pas de données
        // On pourrait laisser vide, mais pour la démo on remet les Mocks si vide
        if (data && data.length === 0) {
             console.log("DB vide, chargement Mocks...");
             setRestaurants(MOCK_RESTAURANTS);
        }
      }
    } catch (err) {
      console.warn("Erreur chargement restaurants (403 probable). Utilisation des données MOCK.");
      setRestaurants(MOCK_RESTAURANTS);
      setIsOfflineMode(true);
    }
  };

  const handleLogout = async () => {
    await supabase.auth.signOut();
    setCurrentUser(null);
  };

  const handleUpdateRestaurant = async (updatedResto: Restaurant) => {
    // Mise à jour de l'état local uniquement pour éviter les conflits et la latence
    setRestaurants(prev => prev.map(r => r.id === updatedResto.id ? updatedResto : r));
    // Nous ne rappelons PAS fetchRestaurants() ici pour laisser l'UI fluide
    // La prochaine visite ou refresh chargera les données DB.
  };

  // Fonction pour force la création du restaurant si l'automatisme a échoué
  const handleManualRestaurantCreation = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!currentUser) return;
    setCreationLoading(true);

    const newRestaurantPayload = {
        owner_id: currentUser.id,
        name: newRestoName || "Mon Restaurant",
        type: newRestoType,
        city: currentUser.city || 'Kinshasa',
        description: `Bienvenue chez ${newRestoName}`,
        latitude: -4.325 + (Math.random() * 0.01), // Random pos near center
        longitude: 15.322 + (Math.random() * 0.01),
        is_open: true,
        preparation_time: 30,
        estimated_delivery_time: 30,
        cover_image: 'https://picsum.photos/800/600?food'
    };

    try {
        // 1. Tenter l'insertion DB
        const { data, error } = await supabase
            .from('restaurants')
            .insert(newRestaurantPayload)
            .select()
            .single();

        if (error) throw error;

        // 2. Si succès, recharger
        await fetchRestaurants();
    } catch (err: any) {
        console.warn("Erreur création DB (Mode Offline activé):", err.message);

        // 3. Fallback Mode Offline / Démo
        const mockResto: Restaurant = {
            id: `temp-${Date.now()}`,
            ownerId: currentUser.id,
            name: newRestoName || "Mon Restaurant (Mode Démo)",
            type: newRestoType,
            city: currentUser.city || 'Kinshasa',
            description: "Restaurant créé en mode démonstration.",
            latitude: -4.325,
            longitude: 15.322,
            isOpen: true,
            rating: 5.0,
            reviewCount: 0,
            preparationTime: 30,
            estimatedDeliveryTime: 30,
            deliveryAvailable: true,
            coverImage: 'https://picsum.photos/800/600?food',
            menu: []
        };

        setRestaurants(prev => [...prev, mockResto]);
        setIsOfflineMode(true);
    } finally {
        setCreationLoading(false);
    }
  };

  if (loading) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-brand-50">
        <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-brand-600"></div>
      </div>
    );
  }

  // 1. Not Logged In -> Show Auth
  if (!currentUser) {
    return <AuthScreen onLogin={() => {}} />;
  }

  // Banner component
  const OfflineBanner = () => isOfflineMode ? (
    <div className="bg-yellow-500 text-white text-xs font-bold px-4 py-1 text-center flex justify-center items-center sticky top-0 z-50">
        <AlertTriangle size={14} className="mr-2" />
        Mode Démo (Connexion Base de Données instable ou Permissions 403)
    </div>
  ) : null;

  // 2. Logged in as Business
  if (currentUser.role === 'business') {
    const myRestaurant = restaurants.find(r => r.ownerId === currentUser.id);

    // CAS CRITIQUE : L'utilisateur est Business mais n'a pas de restaurant (Echec initialisation)
    // On affiche un formulaire de rattrapage au lieu du chargement infini
    if (!myRestaurant) {
         return (
             <div className="min-h-screen bg-gray-50 flex flex-col items-center justify-center p-4">
                 <OfflineBanner />

                 <div className="bg-white max-w-md w-full rounded-2xl shadow-xl p-8 text-center animate-in fade-in zoom-in duration-300">
                     <div className="w-16 h-16 bg-brand-100 text-brand-600 rounded-full flex items-center justify-center mx-auto mb-4">
                        <Store size={32} />
                     </div>

                     <h2 className="text-2xl font-black text-gray-800 mb-2">Finalisation</h2>
                     <p className="text-gray-500 mb-6">Nous devons configurer votre établissement pour continuer.</p>

                     <form onSubmit={handleManualRestaurantCreation} className="space-y-4 text-left">
                        <div>
                            <label className="block text-xs font-bold text-gray-600 mb-1">Nom du restaurant</label>
                            <input 
                                type="text"
                                required
                                className="w-full p-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-brand-500 outline-none"
                                placeholder="Ex: Chez Maman..."
                                value={newRestoName}
                                onChange={e => setNewRestoName(e.target.value)}
                            />
                        </div>

                        <div>
                            <label className="block text-xs font-bold text-gray-600 mb-1">Type d'établissement</label>
                            <select 
                                className="w-full p-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-brand-500 outline-none bg-white"
                                value={newRestoType}
                                onChange={e => setNewRestoType(e.target.value as BusinessType)}
                            >
                                <option value="restaurant">Restaurant</option>
                                <option value="snack">Snack / Fast Food</option>
                                <option value="bar">Bar / Lounge</option>
                                <option value="terrasse">Terrasse</option>
                            </select>
                        </div>

                        <button 
                            type="submit"
                            disabled={creationLoading}
                            className="w-full bg-brand-600 hover:bg-brand-700 text-white font-bold py-3 rounded-xl shadow-lg flex justify-center items-center mt-4"
                        >
                            {creationLoading ? (
                                <div className="w-5 h-5 border-2 border-white border-t-transparent rounded-full animate-spin"></div>
                            ) : (
                                <>Créer mon espace <ArrowRight size={18} className="ml-2"/></>
                            )}
                        </button>
                     </form>

                     <button onClick={handleLogout} className="mt-6 text-gray-400 text-sm hover:text-red-500 underline">
                         Annuler et se déconnecter
                     </button>
                 </div>
             </div>
         )
    }

    return (
      <>
        <OfflineBanner />
        <BusinessDashboard 
            user={currentUser} 
            restaurant={myRestaurant} 
            onUpdateRestaurant={handleUpdateRestaurant}
            onLogout={handleLogout}
        />
      </>
    );
  }

  // 3. Logged in as Client
  return (
    <>
      <OfflineBanner />
      <CustomerView 
        user={currentUser}
        allRestaurants={restaurants}
        onLogout={handleLogout}
      />
    </>
  );
}

